async function _obBootSequence() {
  const ov = document.createElement('div');
  ov.id = 'ob-boot-overlay';
  ov.innerHTML = `
    <div class="ob-brand-wrap">
      <div class="ob-brand-rings">
        <div class="ob-ring ob-ring-1"></div>
        <div class="ob-ring ob-ring-2"></div>
        <div class="ob-ring ob-ring-3"></div>
      </div>
      <div class="ob-brand-icon">⚛</div>
      <div class="ob-brand-logo">Quant<span>Entelloq</span></div>
      <div class="ob-brand-tag">Powered by Entelloq Networks</div>
    </div>
    <div class="ob-boot-sub" style="opacity:0;animation:obFadeUp 0.5s 0.85s ease-out forwards;margin-top:2px;margin-bottom:0;">AI-Native Financial Intelligence Platform</div>
    <div class="ob-boot-progress" style="opacity:0;animation:obFadeUp 0.4s 1.0s ease-out forwards;"><div class="ob-boot-bar" id="ob-boot-bar"></div></div>
    <div class="ob-boot-lines" id="ob-boot-lines"></div>
  `;
  document.body.appendChild(ov);

  const lines = [
    { text: '▸ Initializing Entelloq intelligence network…' },
    { text: '▸ Initializing multi-agent AI systems…' },
    { text: '▸ Loading 100,000,000+ securities universe…' },
    { text: '▸ Connecting Polygon.io data streams…' },
    { text: '▸ Calibrating risk & signal engines…' },
    { text: '✓ Quant Entelloq — All systems operational.', done: true },
  ];

  // Let the rebrand animation play through before rolling the boot log
  await new Promise(r => setTimeout(r, 1100));

  const linesEl = document.getElementById('ob-boot-lines');
  const barEl   = document.getElementById('ob-boot-bar');

  for (let i = 0; i < lines.length; i++) {
    const ln = lines[i];
    await new Promise(r => setTimeout(r, i === 0 ? 0 : 270));
    const div = document.createElement('div');
    div.className = 'ob-boot-line' + (ln.done ? ' done' : ' active');
    div.textContent = ln.text;
    if (linesEl) linesEl.appendChild(div);
    if (barEl) barEl.style.width = Math.round((i + 1) / lines.length * 100) + '%';
  }

  await new Promise(r => setTimeout(r, 650));
  ov.style.transition = 'opacity 500ms ease';
  ov.style.opacity = '0';
  await new Promise(r => setTimeout(r, 520));
  ov.remove();
}

function _obStartNeuralCanvas() {
  const canvas = document.getElementById('ob-canvas');
  if (!canvas) return;
  canvas.style.cssText = 'position:fixed;inset:0;z-index:1498;pointer-events:none;opacity:0.25;';
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  const ctx = canvas.getContext('2d');
  const nodes = Array.from({length:60}, () => ({
    x: Math.random() * canvas.width, y: Math.random() * canvas.height,
    vx: (Math.random()-0.5)*0.5, vy: (Math.random()-0.5)*0.5,
    r: Math.random()*3+1
  }));
  function frame() {
    ctx.clearRect(0,0,canvas.width,canvas.height);
    nodes.forEach(n => {
      n.x += n.vx; n.y += n.vy;
      if(n.x<0||n.x>canvas.width) n.vx*=-1;
      if(n.y<0||n.y>canvas.height) n.vy*=-1;
    });
    nodes.forEach((a,i) => {
      nodes.slice(i+1).forEach(b => {
        const d = Math.hypot(a.x-b.x,a.y-b.y);
        if(d<120) {
          ctx.beginPath(); ctx.moveTo(a.x,a.y); ctx.lineTo(b.x,b.y);
          ctx.strokeStyle=`rgba(167,139,250,${0.18*(1-d/120)})`;
          ctx.lineWidth=0.6; ctx.stroke();
        }
      });
      ctx.beginPath(); ctx.arc(a.x,a.y,a.r,0,Math.PI*2);
      ctx.fillStyle='rgba(167,139,250,0.5)'; ctx.fill();
    });
    if(document.getElementById('onboarding')&&!document.getElementById('onboarding').classList.contains('hidden'))
      requestAnimationFrame(frame);
  }
  frame();
}
function updateOnboardingProgress() {
  const pct = (state.onboardingStep / state.totalSteps) * 100;
  document.getElementById('ob-progress').style.width = pct + '%';
  document.getElementById('ob-step-label').textContent = `${state.onboardingStep} / ${state.totalSteps}`;
}
function nextStep() {
  // === Compulsory questionnaire — block advance until current step is answered ===
  const stepRequirements = {
    1: () => state.profile.useCase,         // What brings you here?
    2: () => state.profile.experience,      // Experience level
    3: () => state.profile.risk != null,    // Risk tolerance slider
    4: () => Array.isArray(state.assets) && state.assets.length > 0, // Asset selection (or fallback OK)
    5: () => true,  // Style — optional
    6: () => true,  // Alerts — optional
  };
  const cur = state.onboardingStep;
  const check = stepRequirements[cur];
  if (typeof check === 'function' && !check()) {
    // Visual nudge: shake the step container
    const stepEl = document.getElementById(`ob-${cur}`);
    if (stepEl) {
      stepEl.style.animation = 'none';
      void stepEl.offsetWidth;
      stepEl.style.animation = 'qeShake 0.5s cubic-bezier(0.36,0.07,0.19,0.97)';
    }
    // Inline error
    let err = document.getElementById(`ob-err-${cur}`);
    if (!err) {
      err = document.createElement('div');
      err.id = `ob-err-${cur}`;
      err.style.cssText = 'color:var(--red);font-size:13px;margin-top:10px;padding:10px 14px;background:rgba(255,71,87,0.08);border-left:3px solid var(--red);border-radius:6px;';
      const nav = stepEl?.querySelector('.onboarding-nav');
      if (nav) nav.parentNode.insertBefore(err, nav);
    }
    err.textContent = 'Please make a selection to continue. Every answer personalizes your Quant Entelloq experience.';
    return;
  }
  // Clear any prior error
  const prevErr = document.getElementById(`ob-err-${cur}`);
  if (prevErr) prevErr.remove();
  if (cur < state.totalSteps) {
    document.getElementById(`ob-${cur}`).classList.remove('active');
    state.onboardingStep++;
    document.getElementById(`ob-${state.onboardingStep}`).classList.add('active');
    updateOnboardingProgress();
  }
}
function prevStep() {
  if(state.onboardingStep > 1) {
    document.getElementById(`ob-${state.onboardingStep}`).classList.remove('active');
    state.onboardingStep--;
    document.getElementById(`ob-${state.onboardingStep}`).classList.add('active');
    updateOnboardingProgress();
  }
}
function selectOption(el, key, val) {
  el.closest('.option-grid').querySelectorAll('.option-item').forEach(i => i.classList.remove('selected'));
  el.classList.add('selected');
  state.profile[key] = val;
  // Map specific keys onto state.profile.useCase / experience for the validator
  if (key === 'useCase' || key === 'goal' || key === 'purpose') state.profile.useCase = val;
  if (key === 'experience' || key === 'level') state.profile.experience = val;
  // Clear any pending validation error on this step
  const err = document.getElementById(`ob-err-${state.onboardingStep}`);
  if (err) err.remove();
}
function toggleAsset(el, val) {
  el.classList.toggle('selected');
  state.assets = state.assets || [];
  if (el.classList.contains('selected')) {
    if (!state.assets.includes(val)) state.assets.push(val);
  } else {
    state.assets = state.assets.filter(a => a !== val);
  }
  // Clear validator error
  const err = document.getElementById(`ob-err-${state.onboardingStep}`);
  if (err && state.assets.length > 0) err.remove();
}
function updateRisk(val) {
  const labels = ['', 'Very Conservative', 'Conservative', 'Moderate', 'Aggressive', 'Very Aggressive'];
  document.getElementById('risk-label').textContent = labels[val];
  state.profile.risk = val;
}
function finishOnboarding() {
  document.getElementById('onboarding').classList.add('hidden');
  localStorage.setItem('qz_onboarded', '1');
  initApp();
  // Agent system will use the user's set level when they navigate there
}

// ==================== APP INIT ====================
function initApp() {
  try { state.portfolio = [...(typeof PORTFOLIO_DATA !== 'undefined' ? PORTFOLIO_DATA : [])]; } catch(_) { state.portfolio = []; }
  try { state.ledger    = [...(typeof LEDGER_DATA    !== 'undefined' ? LEDGER_DATA    : [])]; } catch(_) { state.ledger    = []; }
  const appEl = document.getElementById('app');
  if (appEl) appEl.style.display = 'flex';

  // Set user info — null-guard every getElementById
  const name = state.user?.name || 'User';
  const _avEl  = document.getElementById('user-avatar-sidebar');
  const _nmEl  = document.getElementById('user-name-sidebar');
  const _stNm  = document.getElementById('settings-name');
  const _stEm  = document.getElementById('settings-email');
  if (_avEl) _avEl.textContent = name.charAt(0).toUpperCase();
  if (_nmEl) _nmEl.textContent = name;
  if (_stNm) _stNm.textContent = name;
  if (_stEm) _stEm.textContent = state.user?.email || '';

  try { renderDashboard(); } catch(e){ console.warn('[initApp] renderDashboard', e); }
  // Each renderer is guarded — a single failing one can't crash the whole app
  try { renderSignals(); }   catch(e){ console.warn('[initApp] renderSignals', e); }
  try { renderNews(); }      catch(e){ console.warn('[initApp] renderNews', e); }
  try { renderPortfolio(); } catch(e){ console.warn('[initApp] renderPortfolio', e); }
  try { renderLedger(); }    catch(e){ console.warn('[initApp] renderLedger', e); }
  try { renderScanner(); }   catch(e){ console.warn('[initApp] renderScanner', e); }
  try { renderAlerts(); }    catch(e){ console.warn('[initApp] renderAlerts', e); }
  try { renderReports(); }   catch(e){ console.warn('[initApp] renderReports', e); }
  try { calcScenario(); }    catch(e){ console.warn('[initApp] calcScenario', e); }
  // calcBusiness() was removed — its parent page is gone. Reference left for grep-ability.
  // Initialize regional data
  try { applyRegionToApp(regionState.selectedCountry); } catch(e){ console.warn('[initApp] applyRegion', e); }

  // Trial timer (24 hours → for demo, use 24 mins or skip)
  // For real: check after 24h. We'll give full access for demo.
  state.subscribed = true;

  // Show one-time rebrand notification for returning users
  setTimeout(_showRebrandToast, 1200);
}

// ── One-time rebrand announcement for returning users ──────────────────────
function _showRebrandToast() {
  try { if (localStorage.getItem('qz_rebrand_entelloq_v1')) return; } catch(_) {}
  try { localStorage.setItem('qz_rebrand_entelloq_v1', '1'); } catch(_) {}
  const toast = document.createElement('div');
  toast.id = 'qz-rebrand-toast';
  toast.style.cssText = [
    'position:fixed;bottom:96px;left:50%;transform:translateX(-50%);z-index:99990',
    'background:rgba(10,12,22,0.97);border:1px solid rgba(167,139,250,0.28)',
    'border-radius:18px;padding:18px 22px 18px 18px;max-width:430px;width:calc(100% - 48px)',
    'backdrop-filter:blur(24px);-webkit-backdrop-filter:blur(24px)',
    'box-shadow:0 20px 60px rgba(0,0,0,0.55),0 0 0 1px rgba(167,139,250,0.08) inset',
    'animation:obFadeUp 0.55s cubic-bezier(0.34,1.56,0.64,1)'
  ].join(';');
  toast.innerHTML = `
    <div style="display:flex;align-items:flex-start;gap:14px;">
      <div style="flex:0 0 auto;width:40px;height:40px;border-radius:12px;
        background:linear-gradient(135deg,#7C3AED,#A78BFA);
        display:flex;align-items:center;justify-content:center;font-size:18px;
        box-shadow:0 4px 16px rgba(124,58,237,0.35);">⚡</div>
      <div style="flex:1;min-width:0;">
        <div style="font-weight:700;font-size:13.5px;color:#fff;margin-bottom:5px;font-family:var(--font-display);letter-spacing:-0.01em;">We've rebranded</div>
        <div style="font-size:12px;color:rgba(255,255,255,0.5);line-height:1.6;">
          Welcome to <strong style="color:#C4B5FD;">Quant Entelloq</strong> — your AI-native financial intelligence platform, powered by Entelloq Networks.
        </div>
        <div style="font-size:11px;color:rgba(167,139,250,0.45);margin-top:3px;font-family:var(--font-mono);letter-spacing:0.05em;">Powered by Entelloq Networks</div>
      </div>
      <button onclick="document.getElementById('qz-rebrand-toast').remove()"
        style="flex:0 0 auto;background:none;border:none;color:rgba(255,255,255,0.25);
        font-size:20px;cursor:pointer;padding:0 2px;line-height:1;
        transition:color 150ms;" onmouseover="this.style.color='rgba(255,255,255,0.6)'"
        onmouseout="this.style.color='rgba(255,255,255,0.25)'">×</button>
    </div>
  `;
  document.body.appendChild(toast);
  // Auto-dismiss after 7s
  setTimeout(() => {
    const t = document.getElementById('qz-rebrand-toast');
    if (!t) return;
    t.style.transition = 'opacity 0.45s ease, transform 0.45s ease';
    t.style.opacity = '0';
    t.style.transform = 'translateX(-50%) translateY(12px)';
    setTimeout(() => t && t.remove(), 460);
  }, 7000);
}

// ==================== PAGE NAVIGATION ====================
// Pages whose JS engines were removed are rebuilt inline below.
const _qzComingSoon = {};

function showPage(page, navEl) {
  // Unified Intelligence Terminal — replaces both 'intel' and 'news' with
  // the new ecosystem (NewsJudge + Intelligence + Opportunities merged).
  if (page === 'intel' || page === 'news') {
    document.querySelectorAll('[id^="page-"]').forEach(p => p.classList.add('hidden'));
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    if (navEl) navEl.classList.add('active');
    _qzRenderUnifiedIntel();
    var _intelTitle = document.getElementById('page-title');
    if (_intelTitle) _intelTitle.innerHTML = 'Intelligence Terminal<small>AI-powered news + signals + opportunities</small>';
    _qzSyncSectionChrome('intel');
    return;
  }
  // Quant Lab — inline-rebuilt premium quant terminal
  if (page === 'quantlab') {
    document.querySelectorAll('[id^="page-"]').forEach(p => p.classList.add('hidden'));
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    if (navEl) navEl.classList.add('active');
    if (typeof _qzRenderQuantLab === 'function') _qzRenderQuantLab();
    var _qlTitle = document.getElementById('page-title');
    if (_qlTitle) _qlTitle.innerHTML = 'Quant Lab<small>Risk · Greeks · Monte Carlo · Backtests · Strategy builder</small>';
    state.currentPage = 'quantlab';
    _qzSyncSectionChrome('quantlab');
    try { window.scrollTo({ top: 0, left: 0, behavior: 'instant' }); } catch (_) { window.scrollTo(0,0); }
    return;
  }
  // Coming-soon intercept (currently empty allowlist)
  if (_qzComingSoon[page]) {
    _qzShowComingSoon(page);
    return;
  }
  document.querySelectorAll('[id^="page-"]').forEach(p => p.classList.add('hidden'));
  const _pageEl = document.getElementById(`page-${page}`);
  if (!_pageEl) return;
  _pageEl.classList.remove('hidden');
  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  if(navEl) navEl.classList.add('active');
  const titles = {
    dashboard:  { main:'Dashboard',        sub:'Intelligence Overview' },
    signals:    { main:'AI Signals',       sub:'High-conviction opportunities' },
    news:       { main:'NewsJudge',        sub:'AI-scored market news' },
    macro:      { main:'Macro',            sub:'Global economic overview' },
    portfolio:  { main:'Portfolio',        sub:'Holdings & performance' },
    ledger:     { main:'Ledger',           sub:'Transaction history' },
    ai:         { main:'AI Studio',        sub:'10 specialist agents' },
    scanner:    { main:'Scanner',          sub:'Real-time market scan' },
    scenario:   { main:'Simulations',      sub:'Stress-test any scenario' },
    backtest:   { main:'Backtest',         sub:'Strategy performance analysis' },
    reports:    { main:'Reports',          sub:'Weekly intelligence reports' },
    alerts:     { main:'Alerts',           sub:'Price & signal notifications' },
    settings:   { main:'Settings',         sub:'Account & preferences' },
    universe:   { main:'Watchlists',       sub:'100M+ securities across global markets' },
    paper:      { main:'Paper Trading',    sub:'Risk-free strategy testing' },
    quantlab:   { main:'Quant Lab',        sub:'AI-powered quantitative analysis' },
    command:    { main:'AI Studio',        sub:'Multi-agent orchestration' },
    intel:      { main:'Intelligence Terminal', sub:'Live market intelligence & macro data' },
    research:   { main:'Research Lab',     sub:'Hypothesis → Backtest → Out-of-sample validation' },
  };
  const t = titles[page] || { main: page, sub: 'Quant Intelligence Platform' };
  const titleEl = document.getElementById('page-title');
  if (titleEl) titleEl.innerHTML = t.main + '<small>' + t.sub + '</small>';
  state.currentPage = page;

  // Hard-anchor every page to top — fixes "content pushed up" on Market Hours / AI System
  try {
    window.scrollTo({ top: 0, left: 0, behavior: 'instant' });
    document.documentElement.scrollTop = 0;
    document.body.scrollTop = 0;
    const mc = document.querySelector('.main-content');
    if (mc) mc.scrollTop = 0;
    const pc = document.querySelector('.page-content');
    if (pc) pc.scrollTop = 0;
  } catch (_) { window.scrollTo(0, 0); }

  if(page === 'dashboard') setTimeout(renderHome, 20);
  if(page === 'reports')   setTimeout(renderReports, 50);
  if(page === 'scenario')  setTimeout(renderScenarioChart, 350);
  if(page === 'backtest')  document.getElementById('bt-results').classList.add('hidden');
  if(page === 'settings') { const lvlSel = document.getElementById('ai-level-setting'); if(lvlSel && window.state && state.profile && state.profile.level) lvlSel.value = state.profile.level; }
  if(page === 'agents')    setTimeout(renderAgentSystem, 50);
  if(page === 'markets')   setTimeout(renderMarketHours, 50);
  if(page === 'command')   setTimeout(renderCommandCenter, 60);
  if(page === 'ai')         setTimeout(renderCommandCenter, 80);
  if(page === 'ai') setTimeout(() => {
    const banner = document.getElementById('ai-key-banner');
    if (banner) banner.style.display = qzGetProvider().provider ? 'none' : '';
  }, 50);
  // ── Lazy render pages that use canvases — avoids blackout when first navigated to ──
  if(page === 'signals') setTimeout(() => { _sparkIdCounter = 0; renderSignals(); }, 60);
  if(page === 'news')    setTimeout(renderNews, 60);
  if(page === 'universe') setTimeout(() => { if (typeof uvFilter === 'function') uvFilter(); }, 80);
  if(page === 'intel' && !IntelEngine._init) { IntelEngine._init = true; setTimeout(() => IntelEngine.boot(), 120); }
  if(page === 'learn-explore')  setTimeout(renderLearnExplore, 20);
  if(page === 'learn-continue') setTimeout(renderLearnContinue, 20);
  _qzSyncSectionChrome(page);
}

// ==================== V2 SECTION NAV + SUBTABS ====================
// Six-section information architecture. Existing page-* containers are reused as
// subtab panels; nothing is deleted. showPage() stays the low-level panel switch;
// _qzSyncSectionChrome() keeps the sidebar + subtab bar in sync for every entry point.
var QZ_SECTIONS = {
  home:      { label:'Home',      subtabs:null, page:'dashboard' },
  markets:   { label:'Markets',   subtabs:[
                 { key:'explore',   label:'Explore',   page:'universe' },
                 { key:'screeners', label:'Screeners', page:'scanner'  },
                 { key:'heatmap',   label:'Heatmap',   page:'macro'    },
               ], more:[
                 { label:'Signals', page:'signals' },
                 { label:'News',    page:'intel'   },
               ] },
  learn:     { label:'Learn',     subtabs:[
                 { key:'explore',  label:'Explore',  page:'learn-explore'  },
                 { key:'continue', label:'Continue', page:'learn-continue' },
               ] },
  portfolio: { label:'Portfolio', subtabs:[
                 { key:'overview', label:'Overview', page:'portfolio' },
                 { key:'activity', label:'Activity', page:'ledger'    },
               ], more:[
                 { label:'Paper Trading', page:'paper'   },
                 { label:'Alerts',        page:'alerts'  },
                 { label:'Reports',       page:'reports' },
               ] },
  ai:        { label:'AI',        subtabs:null, page:'ai' },
  profile:   { label:'Profile',   subtabs:null, page:'settings' },
};
// Reverse map: every page → owning section (incl. advanced tools, so nav always highlights).
var _QZ_PAGE_SECTION = {
  dashboard:'home',
  universe:'markets', scanner:'markets', macro:'markets', signals:'markets', news:'markets', intel:'markets', markets:'markets', quantlab:'markets', research:'markets',
  'learn-explore':'learn', 'learn-continue':'learn',
  portfolio:'portfolio', ledger:'portfolio', paper:'portfolio', alerts:'portfolio', reports:'portfolio', scenario:'portfolio', backtest:'portfolio',
  ai:'ai', command:'ai', agents:'ai',
  settings:'profile'
};

function showSection(key, navEl) {
  var cfg = QZ_SECTIONS[key];
  if (!cfg) return;
  var page = cfg.subtabs ? cfg.subtabs[0].page : cfg.page;
  showPage(page);
}

function _qzSyncSectionChrome(page) {
  var section = _QZ_PAGE_SECTION[page] || 'home';
  var navs = document.querySelectorAll('.sidebar-nav .nav-item');
  navs.forEach(function(n){ n.classList.toggle('active', n.getAttribute('data-section') === section); });
  _qzRenderSubtabs(section, page);
}

function _qzRenderSubtabs(section, activePage) {
  var host = document.getElementById('section-subtabs');
  if (!host) return;
  var cfg = QZ_SECTIONS[section];
  if (!cfg || !cfg.subtabs) { host.innerHTML = ''; host.style.display = 'none'; return; }
  host.style.display = '';
  var html = cfg.subtabs.map(function(t){
    return '<button class="qz-subtab' + (t.page === activePage ? ' active' : '') +
           '" onclick="showPage(\'' + t.page + '\')">' + t.label + '</button>';
  }).join('');
  if (cfg.more && cfg.more.length) {
    html += '<span class="qz-subtab-sep"></span>' + cfg.more.map(function(m){
      return '<button class="qz-subtab qz-subtab-more' + (m.page === activePage ? ' active' : '') +
             '" onclick="showPage(\'' + m.page + '\')">' + m.label + '</button>';
    }).join('');
  }
  host.innerHTML = html;
}

// ── Progressive-disclosure primitive: qzDisclosure(summary, detailHTML, {open,icon}) → HTML ──
function qzDisclosure(summary, detailHTML, opts) {
  opts = opts || {};
  var open = opts.open ? ' qz-open' : '';
  return '<div class="qz-disclosure' + open + '">' +
           '<button type="button" class="qz-disc-head" onclick="qzToggleDisclosure(this)">' +
             (opts.icon ? '<span>' + opts.icon + '</span>' : '') +
             '<span>' + summary + '</span>' +
             '<span class="qz-disc-chevron">▾</span>' +
           '</button>' +
           '<div class="qz-disc-body">' + detailHTML + '</div>' +
         '</div>';
}
function qzToggleDisclosure(el) {
  var d = el.closest ? el.closest('.qz-disclosure') : el.parentNode;
  if (d) d.classList.toggle('qz-open');
}

// ── Experience-level reader (beginner-first default for UI density) ──
function qzLevel() {
  try { return (window.state && state.profile && state.profile.level) || 'beginner'; }
  catch (e) { return 'beginner'; }
}

// ── ✨ Explain → routes to the one AI assistant, pre-seeded in plain English ──
function qzExplain(term, context) {
  try {
    showPage('ai');
    setTimeout(function(){
      var inp = document.getElementById('chat-input');
      if (!inp) return;
      inp.value = 'Explain "' + term + '" in simple, beginner-friendly terms' +
                  (context ? ' (context: ' + context + ')' : '') + '.';
      inp.focus();
      if (typeof sendChat === 'function') sendChat();
    }, 140);
  } catch (e) {}
}
function qzExplainChip(term, context) {
  var t = (term || '').replace(/"/g, '&quot;');
  var c = (context || '').replace(/"/g, '&quot;');
  return '<span class="qz-explain" onclick="qzExplain(&quot;' + t + '&quot;,&quot;' + c + '&quot;)">✨ Explain</span>';
}

