function newsItemHTML(n) {
  const sentCls = n.impact === 'positive' ? 'pos' : n.impact === 'negative' ? 'neg' : 'neu';
  const sentLabel = n.impact === 'positive' ? '📈 Bullish' : n.impact === 'negative' ? '📉 Bearish' : '⚖ Neutral';
  const sentScore = n.impact === 'positive' ? (74 + Math.floor((n.id||1)*7)%22) : n.impact === 'negative' ? (52 + Math.floor((n.id||1)*5)%24) : (38 + Math.floor((n.id||1)*3)%22);
  const src = n.source || 'Reuters';
  const timeStr = n.time || n.pubDate || '2h ago';
  return `<div class="ent-news-card ${sentCls}" id="news-${n.id}" onclick="toggleEntNewsAnalysis(${n.id})">
    <div class="ent-news-accent"></div>
    <div class="ent-news-head">
      <div class="ent-news-meta">
        <span class="ent-news-source">${src}</span>
        <span class="ent-news-dot">·</span>
        <span class="ent-news-time">${timeStr}</span>
      </div>
      <div class="ent-news-sent ${sentCls}">${sentLabel}</div>
    </div>
    <div class="ent-news-title">${n.title}</div>
    <div class="ent-news-excerpt">${n.excerpt||''}</div>
    <div class="ent-news-footer">
      <div class="ent-news-score-wrap">
        <span class="ent-news-score-label">AI Score</span>
        <div class="ent-news-score-track"><div class="ent-news-score-fill ${sentCls}" style="width:${sentScore}%"></div></div>
        <span class="ent-news-score-val">${sentScore}</span>
      </div>
      <span class="ent-news-expand">⚡ Analysis ↓</span>
    </div>
    <div class="ent-news-analysis hidden" id="ent-analysis-${n.id}">
      <div class="ent-news-analysis-grid">
        <div><div class="ent-news-analysis-label">MARKET IMPACT</div><div class="ent-news-analysis-val">${n.analysis ? n.analysis.impact : 'Loading…'}</div></div>
        <div><div class="ent-news-analysis-label">AFFECTED ASSETS</div><div class="ent-news-analysis-val">${n.analysis ? n.analysis.assets : '—'}</div></div>
        <div><div class="ent-news-analysis-label">KEY RISKS</div><div class="ent-news-analysis-val">${n.analysis ? n.analysis.risks : '—'}</div></div>
        <div><div class="ent-news-analysis-label">OPPORTUNITIES</div><div class="ent-news-analysis-val">${n.analysis ? n.analysis.opportunities : '—'}</div></div>
      </div>
    </div>
  </div>`;
}
function toggleEntNewsAnalysis(id) {
  const el = document.getElementById('ent-analysis-' + id);
  if (el) el.classList.toggle('hidden');
}
function analyzeNews(id) {
  toggleEntNewsAnalysis(id);
}
function filterNews(type, btn) {
  document.querySelectorAll('#page-news .ent-tab').forEach(t => t.classList.remove('active'));
  btn.classList.add('active');
  const filtered = type === 'all' ? NEWS : NEWS.filter(n => n.impact === type);
  document.getElementById('news-feed').innerHTML = filtered.map(n => newsItemHTML(n)).join('');
}

// ==================== PORTFOLIO ====================
function renderPortfolio() {
  const tbody = document.getElementById('portfolio-tbody');
  tbody.innerHTML = state.portfolio.map(p => {
    const val = p.qty * p.current;
    const pnl = (p.current - p.cost) * p.qty;
    const pnlPct = ((p.current - p.cost) / p.cost * 100).toFixed(1);
    const cls = pnl >= 0 ? 'pnl-positive' : 'pnl-negative';
    const sigCls = p.signal === 'BUY' ? 'badge-green' : p.signal === 'SELL' ? 'badge-red' : 'badge-yellow';
    const pnlCls = pnl >= 0 ? 'ent-pf-pnl-pos' : 'ent-pf-pnl-neg';
    return `<tr>
      <td><span class="ent-pf-ticker-chip">${p.ticker}</span></td>
      <td style="color:var(--text-secondary);font-size:12.5px;">${p.name}</td>
      <td class="ent-ldg-num">${p.qty}</td>
      <td class="ent-ldg-num">${p.cost.toFixed(2)}</td>
      <td class="ent-ldg-num">${p.current.toFixed(2)}</td>
      <td style="font-family:var(--font-mono);font-weight:600;">${val.toLocaleString('en-US',{maximumFractionDigits:0})}</td>
      <td class="${pnlCls}">${pnl>=0?'+':''}${pnl.toLocaleString('en-US',{maximumFractionDigits:0})} (${pnl>=0?'+':''}${pnlPct}%)</td>
      <td><span class="badge ${sigCls}">${p.signal}</span></td>
    </tr>`;
  }).join('');
}
function showAddPosition() {
  document.getElementById('add-position-modal').classList.remove('hidden');
}
function addPosition() {
  const ticker = document.getElementById('pos-ticker').value.toUpperCase();
  const qty = parseFloat(document.getElementById('pos-qty').value);
  const cost = parseFloat(document.getElementById('pos-cost').value);
  if(!ticker || !qty || !cost) return;
  const stock = STOCKS.find(s => s.ticker === ticker);
  state.portfolio.push({ ticker, name: stock?.name || ticker, qty, cost, current: stock?.price || cost, signal: stock?.signal || 'HOLD' });
  document.getElementById('add-position-modal').classList.add('hidden');
  document.getElementById('pos-ticker').value = '';
  document.getElementById('pos-qty').value = '';
  document.getElementById('pos-cost').value = '';
  renderPortfolio();
  updatePortfolioMetrics();
}

// ==================== LEDGER ====================
function renderLedger() {
  const tbody = document.getElementById('ledger-tbody');
  tbody.innerHTML = state.ledger.map(l => {
    const total = l.qty * l.price;
    const pnlCls = l.pnl.startsWith('+') ? 'ent-ldg-pnl-pos' : l.pnl.startsWith('-') ? 'ent-ldg-pnl-neg' : 'ent-ldg-pnl-neu';
    const typEl = l.type === 'BUY' ? '<span class="ent-ldg-type-buy">BUY</span>' : '<span class="ent-ldg-type-sell">SELL</span>';
    return `<tr>
      <td><span class="ent-ldg-date">${l.date}</span></td>
      <td><span class="ent-ldg-ticker">${l.ticker}</span></td>
      <td>${typEl}</td>
      <td class="ent-ldg-num">${l.qty}</td>
      <td class="ent-ldg-num">$${l.price.toFixed(2)}</td>
      <td class="ent-ldg-num">$${total.toLocaleString()}</td>
      <td class="${pnlCls}">${l.pnl}</td>
    </tr>`;
  }).join('');
  // Update summary stats
  const buys = state.ledger.filter(l => l.type === 'BUY').length;
  const sells = state.ledger.filter(l => l.type === 'SELL').length;
  let netPnl = 0;
  state.ledger.forEach(l => {
    const v = parseFloat(l.pnl.replace(/[^0-9.-]/g,''));
    if (!isNaN(v)) netPnl += l.pnl.startsWith('-') ? -Math.abs(v) : Math.abs(v);
  });
  const fmt = (id, val) => { const el = document.getElementById(id); if(el) el.textContent = val; };
  fmt('ldg-stat-total', state.ledger.length);
  fmt('ldg-stat-buys', buys);
  fmt('ldg-stat-sells', sells);
  const pnlEl = document.getElementById('ldg-stat-pnl');
  const pnlStat = pnlEl && pnlEl.closest('.ent-ldg-stat');
  if (pnlEl) { pnlEl.textContent = (netPnl >= 0 ? '+' : '') + String.fromCharCode(36) + Math.abs(netPnl).toLocaleString('en-US',{maximumFractionDigits:0}); }
  if (pnlStat) { pnlStat.classList.toggle('pnl-pos', netPnl >= 0); pnlStat.classList.toggle('pnl-neg', netPnl < 0); }
}
function addLedgerEntry() {
  // Remove any existing modal first
  const existing = document.getElementById('ledger-modal');
  if (existing) { existing.remove(); return; }

  const today = new Date().toISOString().split('T')[0];
  const modal = document.createElement('div');
  modal.id = 'ledger-modal';
  modal.style.cssText = 'position:fixed;inset:0;z-index:900;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,0.65);backdrop-filter:blur(6px);';
  modal.innerHTML = `
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:28px;width:440px;max-width:94vw;box-shadow:0 32px 64px -16px rgba(0,0,0,0.6);">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:22px;">
        <div style="font-family:var(--font-display);font-size:15px;font-weight:700;">Record Transaction</div>
        <button onclick="document.getElementById('ledger-modal').remove()" style="background:none;border:none;cursor:pointer;color:var(--text-muted);font-size:18px;line-height:1;padding:0;">✕</button>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px;">
        <div class="form-group" style="margin:0;">
          <label class="input-label">Date</label>
          <input class="input" id="led-date" type="date" value="${today}">
        </div>
        <div class="form-group" style="margin:0;">
          <label class="input-label">Type</label>
          <select class="input" id="led-type"><option value="BUY">BUY</option><option value="SELL">SELL</option></select>
        </div>
        <div class="form-group" style="margin:0;">
          <label class="input-label">Ticker</label>
          <input class="input" id="led-ticker" placeholder="AAPL" style="text-transform:uppercase;" oninput="this.value=this.value.toUpperCase()">
        </div>
        <div class="form-group" style="margin:0;">
          <label class="input-label">Quantity</label>
          <input class="input" id="led-qty" type="number" min="0.001" step="any" placeholder="10">
        </div>
        <div class="form-group" style="margin:0;">
          <label class="input-label">Price per share ($)</label>
          <input class="input" id="led-price" type="number" min="0.01" step="any" placeholder="189.40">
        </div>
        <div class="form-group" style="margin:0;">
          <label class="input-label">P&L ($) <span style="font-size:10px;color:var(--text-muted);">optional</span></label>
          <input class="input" id="led-pnl" placeholder="+$0">
        </div>
      </div>
      <div id="led-error" style="font-size:12px;color:var(--red);margin-bottom:10px;display:none;"></div>
      <div style="display:flex;gap:10px;justify-content:flex-end;">
        <button class="btn btn-ghost btn-sm" onclick="document.getElementById('ledger-modal').remove()">Cancel</button>
        <button class="btn btn-primary btn-sm" onclick="submitLedgerEntry()">Record →</button>
      </div>
    </div>
  `;
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
  document.body.appendChild(modal);
  setTimeout(() => document.getElementById('led-ticker')?.focus(), 50);
}

function submitLedgerEntry() {
  const date   = document.getElementById('led-date')?.value?.trim();
  const ticker = document.getElementById('led-ticker')?.value?.trim().toUpperCase();
  const type   = document.getElementById('led-type')?.value || 'BUY';
  const qty    = parseFloat(document.getElementById('led-qty')?.value);
  const price  = parseFloat(document.getElementById('led-price')?.value);
  const pnlRaw = document.getElementById('led-pnl')?.value?.trim();
  const errEl  = document.getElementById('led-error');

  if (!ticker || ticker.length < 1) { errEl.textContent = 'Ticker is required.'; errEl.style.display=''; return; }
  if (!qty || qty <= 0)             { errEl.textContent = 'Quantity must be a positive number.'; errEl.style.display=''; return; }
  if (!price || price <= 0)         { errEl.textContent = 'Price must be a positive number.'; errEl.style.display=''; return; }
  errEl.style.display = 'none';

  const pnl = pnlRaw || '$0';
  state.ledger.unshift({ date: date || new Date().toISOString().split('T')[0], ticker, type, qty, price, pnl });
  document.getElementById('ledger-modal')?.remove();
  renderLedger();
}

