const AI_RESPONSES = {
  default: (q) => `Based on current market conditions and available data, here's my analysis of "${q}":\n\n📊 **Market Context**: Markets are showing bullish momentum with the S&P 500 up 1.2% today. Risk appetite is elevated.\n\n🧠 **AI Assessment**: ${q.toLowerCase().includes('buy') || q.toLowerCase().includes('invest') ? 'Given current signals and sentiment data, the risk/reward profile looks favorable for selective accumulation. Focus on quality names with strong fundamentals.' : 'The data suggests monitoring this situation closely. Key factors to watch include Fed policy, earnings revisions, and sector rotation signals.'}\n\n⚠️ **Key Risks**: Interest rate sensitivity, geopolitical uncertainty, and earnings season volatility.\n\n💡 **Recommendation**: Maintain diversified exposure and set appropriate position sizing based on your risk profile.`,
  nvda: `**NVIDIA (NVDA) Analysis** 🎯\n\nCurrent Price: $878.30 | Signal: BUY | Confidence: 91%\n\n📈 **Bull Case**: Dominant position in AI training chips with 80%+ market share. Blackwell GPU demand far exceeding supply. Data center revenue growing 200%+ YoY. Forward P/E justified by hyper-growth trajectory.\n\n⚠️ **Bear Case**: Valuation elevated at 40× forward earnings. Export restrictions to China risk. Competition from AMD and custom silicon (Google TPUs, AWS Trainium).\n\n🎯 **AI Verdict**: Fundamentals remain exceptional. Near-term entry with 5–7% position sizing and stop loss at $820 is our recommended approach for moderate risk profiles.`,
  aapl: `**Apple (AAPL) Analysis** 🍎\n\nCurrent Price: $189.40 | Signal: BUY | Confidence: 94%\n\n📈 **Bull Case**: Services revenue hit new record at $25B/quarter. iPhone 16 AI features driving strongest upgrade cycle in years. $110B buyback program provides price floor. Dividend growth consistent.\n\n⚠️ **Bear Case**: China regulatory risk. App Store antitrust pressure. Slower growth vs. pure-play AI names.\n\n🎯 **AI Verdict**: Best-in-class quality at reasonable valuation. Core holding for conservative to moderate portfolios. Accumulate on any dips below $180.`,
  tsla: `**Tesla (TSLA) Analysis** ⚡\n\nCurrent Price: $244.80 | Signal: HOLD | Confidence: 72%\n\n📈 **Bull Case**: FSD technology maturing. Robotaxi potential is transformational. Energy storage business accelerating. Cost structure improving.\n\n⚠️ **Bear Case**: Q1 delivery miss of 8%. Margin compression from price wars. Competition intensifying from BYD globally. Execution risk on Cybertruck.\n\n🎯 **AI Verdict**: Volatile name in transitional phase. Hold existing positions, avoid new entries until delivery growth resumes. Watch Robotaxi announcement as potential catalyst.`,
};
function getAIResponse(msg) {
  const m = msg.toLowerCase();
  if(m.includes('nvda') || m.includes('nvidia')) return AI_RESPONSES.nvda;
  if(m.includes('aapl') || m.includes('apple')) return AI_RESPONSES.aapl;
  if(m.includes('tsla') || m.includes('tesla')) return AI_RESPONSES.tsla;
  return AI_RESPONSES.default(msg);
}

async function sendChat() {
  const input = document.getElementById('chat-input');
  const msg = input.value.trim();
  if(!msg) return;
  input.value = '';
  const container = document.getElementById('chat-messages');
  container.innerHTML += `<div class="chat-msg user"><div class="chat-msg-label">YOU</div><div class="chat-bubble">${_escapeHtml(msg)}</div></div>`;
  // Typing indicator
  const typId = 'typing-' + Date.now();
  container.innerHTML += `<div class="chat-msg ai" id="${typId}"><div class="chat-msg-label">QUANT ENTELLOQ AI</div><div class="chat-bubble"><div class="typing-indicator"><div class="typing-dot"></div><div class="typing-dot"></div><div class="typing-dot"></div></div></div></div>`;
  container.scrollTop = container.scrollHeight;

  // Call Anthropic API
  try {
    const userLevel = (state.profile && state.profile.level) || 'intermediate';
    const levelPrompts = {
      beginner: 'You are QUANT ENTELLOQ AI. Explain financial concepts in simple, plain English. Avoid jargon. Use analogies when helpful. Keep responses concise and actionable. The user is new to investing.',
      intermediate: 'You are QUANT ENTELLOQ AI, a financial intelligence assistant. Provide data-driven analysis with standard financial terminology. Reference key metrics like P/E, RSI, sentiment scores. Be clear and actionable.',
      advanced: 'You are QUANT ENTELLOQ AI. Provide sophisticated analysis using technical indicators, factor models, and quantitative reasoning. Reference statistical concepts freely. The user has deep market knowledge.',
      professional: 'You are QUANT ENTELLOQ AI. Provide institutional-grade analysis: factor attribution, risk-adjusted returns, VaR implications, alpha generation. Use precise financial nomenclature. The user is a finance professional.'
    };
    const sysPrompt = (levelPrompts[userLevel] || levelPrompts.intermediate) + ' Format responses clearly. Reference real market concepts and current trends in 2025. Keep responses under 280 words unless detailed analysis is explicitly requested.';

    const reply = await qzAICall(sysPrompt, msg, 1000);
    document.getElementById(typId).remove();
    const safereply = _escapeHtml(reply);
    const formatted = safereply.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>').replace(/\n/g,'<br>');
    container.innerHTML += `<div class="chat-msg ai"><div class="chat-msg-label">QUANT ENTELLOQ AI</div><div class="chat-bubble">${formatted}</div></div>`;
  } catch(e) {
    document.getElementById(typId).remove();
    // getAIResponse returns trusted internal HTML — do not double-escape
    const reply = getAIResponse(msg);
    const formatted = reply.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>').replace(/\n/g,'<br>');
    container.innerHTML += `<div class="chat-msg ai"><div class="chat-msg-label">QUANT ENTELLOQ AI</div><div class="chat-bubble">${formatted}</div></div>`;
  }
  container.scrollTop = container.scrollHeight;
}

// ==================== SCANNER ====================
function renderScanner() {
  const grid = document.getElementById('scanner-grid');
  if (!grid) return;
  const filter  = document.getElementById('scanner-filter')?.value  || 'all';
  const riskFil = document.getElementById('scanner-risk')?.value    || 'all';
  let stocks = STOCKS;
  if (filter !== 'all') {
    if (filter === 'momentum')       stocks = stocks.filter(s => s.momentum >= 70);
    else if (filter === 'sentiment') stocks = stocks.filter(s => s.sentiment >= 70);
    else if (filter === 'breakout')  stocks = stocks.filter(s => s.signal === 'BUY' && s.conf >= 80);
  }
  if (riskFil !== 'all') stocks = stocks.filter(s => s.risk === riskFil);
  grid.innerHTML = stocks.map(s => {
    const cls = s.signal === 'BUY' ? 'badge-green' : s.signal === 'SELL' ? 'badge-red' : 'badge-yellow';
    const momColor = s.momentum>70?'var(--green)':s.momentum>45?'var(--yellow)':'var(--red)';
    const senColor = s.sentiment>70?'var(--green)':s.sentiment>45?'var(--yellow)':'var(--red)';
    const sparkId = 'scan-spark-' + s.ticker;
    const isUp = s.change > 0;
    const seed = s.ticker.split('').reduce((a,c)=>a+c.charCodeAt(0),0);
    const sparkData = Array.from({length:12},(_,i)=>{
      const t=(i+1)/12;
      const noise=Math.sin(seed*i*0.9)*0.02+(Math.random()-0.5)*0.01;
      return s.price*(1-(1-t)*(isUp?0.05:-0.05)+noise);
    });
    setTimeout(()=>drawInlineSparkline(sparkId, sparkData, isUp), 40);
    return `<div class="scanner-item">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px;">
        <div><div class="scanner-ticker">${s.ticker}</div><div class="scanner-name">${s.name}</div></div>
        <span class="badge ${cls}">${s.signal}</span>
      </div>
      <canvas id="${sparkId}" style="width:100%;height:34px;display:block;margin-bottom:8px;"></canvas>
      <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:10px;">
        <span style="font-family:var(--font-display);font-weight:700;">$${s.price.toLocaleString()}</span>
        <span style="color:${isUp?'var(--green)':'var(--red)'};">${isUp?'▲':'▼'} ${Math.abs(s.change)}%</span>
      </div>
      <div style="margin-bottom:6px;">
        <div style="display:flex;justify-content:space-between;font-size:10px;color:var(--text-muted);font-family:var(--font-mono);margin-bottom:3px;"><span>MOMENTUM</span><span style="color:${momColor};">${s.momentum}/100</span></div>
        <div style="height:4px;background:var(--surface3);border-radius:2px;overflow:hidden;"><div style="height:100%;width:${s.momentum}%;background:${momColor};border-radius:2px;transition:width 0.6s ease;"></div></div>
      </div>
      <div>
        <div style="display:flex;justify-content:space-between;font-size:10px;color:var(--text-muted);font-family:var(--font-mono);margin-bottom:3px;"><span>SENTIMENT</span><span style="color:${senColor};">${s.sentiment}/100</span></div>
        <div style="height:4px;background:var(--surface3);border-radius:2px;overflow:hidden;"><div style="height:100%;width:${s.sentiment}%;background:${senColor};border-radius:2px;transition:width 0.6s ease;"></div></div>
      </div>
    </div>`;
  }).join('');
}

// ==================== SCENARIO ====================
// ========== BLOOMBERG SCENARIO ENGINE ==========
function _qzscSetMode(mode, btn) {
  document.querySelectorAll('.qzsc-tab').forEach(b => b.classList.remove('active'));
  document.querySelectorAll('.qzsc-panel').forEach(p => p.classList.add('hidden'));
  if (btn) btn.classList.add('active');
  const panel = document.getElementById('qzsc-panel-' + mode);
  if (panel) panel.classList.remove('hidden');
  if (mode === 'growth') calcScenario();
}
function _qzscPickCrisis(id, el) {
  document.querySelectorAll('.qzsc-crisis-card').forEach(c => c.classList.remove('active'));
  if (el) el.classList.add('active');
}

function calcScenario() {
  const invest   = parseFloat(document.getElementById('sc-invest')?.value) || 10000;
  const monthly  = parseFloat(document.getElementById('sc-monthly')?.value) || 0;
  const retPct   = parseFloat(document.getElementById('sc-return')?.value) || 12;
  const years    = parseFloat(document.getElementById('sc-years')?.value)  || 10;
  const fee      = parseFloat(document.getElementById('sc-fee')?.value)    || 0.5;
  const inflation= parseFloat(document.getElementById('sc-inflation')?.value) || 3;
  const tax      = parseFloat(document.getElementById('sc-tax')?.value)    || 20;
  const benchPct = parseFloat(document.getElementById('sc-benchmark')?.value) || 10;
  const netAnnual = (retPct - fee) / 100;
  const monthlyRate = netAnnual / 12;
  const benchMonthlyRate = benchPct / 100 / 12;
  const months = Math.round(years * 12);
  let portfolio = invest, benchmark = invest, gross = invest;
  let totalContrib = invest;
  const portfolioData = [], benchData = [];
  const startYear = 2026 - years;
  for (let m = 0; m <= months; m++) {
    const yr = startYear + m / 12;
    if (m % 12 === 0 || m === months) {
      const yrStr = Math.floor(yr) + '-01-01';
      portfolioData.push({ time: yrStr, value: +portfolio.toFixed(0) });
      benchData.push({ time: yrStr, value: +benchmark.toFixed(0) });
    }
    if (m < months) {
      portfolio  = portfolio  * (1 + monthlyRate)      + monthly;
      benchmark  = benchmark  * (1 + benchMonthlyRate) + monthly;
      gross      = gross      * (1 + retPct/100/12)    + monthly;
      totalContrib += monthly;
    }
  }
  const final      = portfolio;
  const profit     = final - totalContrib;
  const totalRet   = (final / invest - 1) * 100;
  const cagr       = (Math.pow(final / invest, 1/years) - 1) * 100;
  const inflFactor = Math.pow(1 + inflation/100, years);
  const realValue  = final / inflFactor;
  const taxableGain= Math.max(0, final - totalContrib);
  const afterTax   = final - taxableGain * (tax/100);
  const feesPaid   = Math.max(0, gross - final);
  const benchFinal = benchmark;
  const vsBench    = totalRet - (benchFinal/invest - 1)*100;
  const rule72     = netAnnual > 0 ? (72 / (netAnnual*100)).toFixed(1) : '∞';
  const simpleGain = totalContrib * (retPct/100) * years;
  const compound   = Math.max(0, profit - simpleGain);
  const fmt  = v => '$' + Math.abs(v).toLocaleString('en-US',{maximumFractionDigits:0});
  const fmtp = v => (v>=0?'+':'-') + fmt(v);
  const fmtpct = v => (v>=0?'+':'') + v.toFixed(1) + '%';
  const $ = id => document.getElementById(id);
  if ($('sc-final'))       { $('sc-final').textContent = fmt(final); $('sc-final-sub').textContent = `From ${fmt(totalContrib)} contributed`; }
  if ($('sc-profit'))      { $('sc-profit').textContent = fmtp(profit); $('sc-profit').style.color = profit>=0?'#34D399':'#F87171'; $('sc-profit-sub').textContent = profit>=0?'Net gain':'Net loss'; }
  if ($('sc-totalret'))    { $('sc-totalret').textContent = fmtpct(totalRet); $('sc-totalret').style.color = totalRet>=0?'#34D399':'#F87171'; $('sc-ret-sub').textContent = `Over ${years} years`; }
  if ($('sc-cagr'))        $('sc-cagr').textContent = cagr.toFixed(2)+'%';
  if ($('sc-real'))        $('sc-real').textContent = fmt(realValue);
  if ($('sc-aftertax'))    $('sc-aftertax').textContent = fmt(afterTax);
  if ($('sc-contrib'))     $('sc-contrib').textContent = fmt(totalContrib);
  if ($('sc-compound'))    $('sc-compound').textContent = fmt(compound);
  if ($('sc-vsbench'))     { $('sc-vsbench').textContent = fmtpct(vsBench); $('sc-vsbench').style.color = vsBench>=0?'#34D399':'#F87171'; $('sc-vsbench-sub').textContent = `vs ${benchPct}% benchmark`; }
  if ($('sc-feespaid'))    $('sc-feespaid').textContent = fmt(feesPaid);
  if ($('sc-rule72'))      $('sc-rule72').textContent = rule72 + ' yrs';
  renderScenarioChart(portfolioData, benchData);
}

let _tvScChart = null;
function renderScenarioChart(portfolioData, benchData, containerId, height) {
  const container = document.getElementById(containerId || 'scenario-chart');
  if (!container || container.offsetWidth === 0) return;
  if (_tvScChart) { try { _tvScChart.remove(); } catch(_) {} _tvScChart = null; }
  container.innerHTML = '';
  if (!portfolioData || !portfolioData.length) return;
  if (typeof LightweightCharts === 'undefined') return;
  _tvScChart = LightweightCharts.createChart(container, {
    width: container.offsetWidth || 600, height: height || 200,
    layout: { background:{color:'transparent'}, textColor:'#94A3B8', fontFamily:"'DM Mono',monospace", fontSize:10 },
    grid: { vertLines:{color:'rgba(255,255,255,0.02)'}, horzLines:{color:'rgba(255,255,255,0.03)'} },
    timeScale: { borderColor:'rgba(255,255,255,0.06)', fixLeftEdge:true, fixRightEdge:true },
    rightPriceScale: { borderColor:'rgba(255,255,255,0.06)', scaleMargins:{top:0.08,bottom:0.06} },
    crosshair:{mode:1}, handleScale:{mouseWheel:false}, handleScroll:{mouseWheel:false},
  });
  const fmtV = v => '$'+(v>=1e6?(v/1e6).toFixed(1)+'M':(v/1000).toFixed(0)+'k');
  const portS = _tvScChart.addAreaSeries({ lineColor:'#A78BFA', topColor:'rgba(167,139,250,0.2)', bottomColor:'rgba(167,139,250,0.01)', lineWidth:2, priceFormat:{type:'custom',formatter:fmtV,minMove:1}, priceLineVisible:false, lastValueVisible:true });
  portS.setData(portfolioData);
  if (benchData) {
    const bmS = _tvScChart.addLineSeries({ color:'rgba(96,165,250,0.5)', lineWidth:1, lineStyle:2, priceFormat:{type:'custom',formatter:fmtV,minMove:1}, priceLineVisible:false, lastValueVisible:false });
    bmS.setData(benchData);
  }
  _tvScChart.timeScale().fitContent();
  new ResizeObserver(es => { if(_tvScChart) _tvScChart.applyOptions({width:es[0].contentRect.width}); }).observe(container);
}

// --- Crisis scenarios ---
const _CRISES = {
  gfc:    { name:'2008 GFC', equityDD:-0.568, bondGain:0.18, duration:18, recovery:48, color:'#F87171' },
  covid:  { name:'COVID-19', equityDD:-0.339, bondGain:0.08, duration:2,  recovery:5,  color:'#FB923C' },
  dotcom: { name:'Dot-com',  equityDD:-0.491, bondGain:0.22, duration:30, recovery:84, color:'#FBBF24' },
  '1987': { name:'Black Monday', equityDD:-0.226, bondGain:0.06, duration:1, recovery:24, color:'#A78BFA' },
  '2022': { name:'Rate Hike 2022', equityDD:-0.254, bondGain:-0.18, duration:9, recovery:15, color:'#60A5FA' },
  '1973': { name:'Oil Crisis 1973', equityDD:-0.482, bondGain:0.05, duration:22, recovery:96, color:'#34D399' },
};
let _tvCrisisChart = null;
function _qzscRunCrisis() {
  const invest = parseFloat(document.getElementById('qzsc-crisis-invest')?.value) || 100000;
  const equityPct = Math.min(100, Math.max(0, parseFloat(document.getElementById('qzsc-crisis-equity')?.value)||80)) / 100;
  const bondPct = 1 - equityPct;
  const activeCard = document.querySelector('.qzsc-crisis-card.active');
  const crisisId = activeCard?.dataset.crisis || 'gfc';
  const c = _CRISES[crisisId];
  if (!c) return;
  const equityValue   = invest * equityPct;
  const bondValue     = invest * bondPct;
  const equityLoss    = equityValue * c.equityDD;
  const bondChange    = bondValue * c.bondGain;
  const netLoss       = equityLoss + bondChange;
  const finalValue    = invest + netLoss;
  const totalRet      = netLoss / invest * 100;
  const recoveryAmt   = invest - finalValue;
  const recoveryMo    = c.recovery;
  const fmt  = v => '$' + Math.abs(v).toLocaleString('en-US',{maximumFractionDigits:0});
  const html = `
    <div class="qzsc-metric-grid" style="margin-bottom:10px;">
      <div class="qzsc-metric"><div class="qzsc-metric-label">Portfolio Value At Bottom</div><div class="qzsc-metric-val" style="color:#F87171;font-size:18px;">${fmt(finalValue)}</div><div class="qzsc-metric-sub">From ${fmt(invest)}</div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">Nominal Loss</div><div class="qzsc-metric-val" style="color:#F87171;font-size:18px;">-${fmt(Math.abs(netLoss))}</div><div class="qzsc-metric-sub">${totalRet.toFixed(1)}% portfolio impact</div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">Equity Impact</div><div class="qzsc-metric-val" style="color:#F87171;font-size:18px;">${fmt(equityLoss)}</div><div class="qzsc-metric-sub">${(equityPct*100).toFixed(0)}% allocation × ${(c.equityDD*100).toFixed(1)}%</div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">Bond Cushion</div><div class="qzsc-metric-val" style="color:${c.bondGain>=0?'#34D399':'#F87171'};font-size:18px;">${c.bondGain>=0?'+':''}${fmt(bondChange)}</div><div class="qzsc-metric-sub">${(bondPct*100).toFixed(0)}% bonds ${c.bondGain>=0?'helped':'also fell'}</div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">Crisis Duration</div><div class="qzsc-metric-val" style="font-size:18px;">${c.duration} mo</div><div class="qzsc-metric-sub">Peak-to-trough</div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">Historical Recovery</div><div class="qzsc-metric-val" style="font-size:18px;">${recoveryMo >= 12 ? (recoveryMo/12).toFixed(1)+' yr' : recoveryMo+' mo'}</div><div class="qzsc-metric-sub">Time to new high</div></div>
    </div>
    <div style="font-size:11px;color:var(--text-muted);padding:10px 12px;background:var(--surface3);border-radius:8px;font-family:var(--font-mono);">
      💡 With ${(equityPct*100).toFixed(0)}/${(bondPct*100).toFixed(0)} equity/bond split, you'd need to recover <strong style="color:#F87171;">${fmt(recoveryAmt)}</strong> — taking approximately <strong style="color:#FACC15;">${recoveryMo} months</strong> based on ${c.name} historical recovery.
    </div>`;
  document.getElementById('qzsc-crisis-results').innerHTML = html;
  // Chart: portfolio path through crisis
  const pts = c.duration + Math.min(c.recovery, 24);
  const chartData = [];
  const now = Date.now()/1000;
  for (let i=0; i<=pts; i++) {
    const ratio = i <= c.duration ? (1 + c.equityDD * equityPct * (i/c.duration)) : Math.min(1, (finalValue/invest) + (1 - finalValue/invest) * ((i-c.duration)/c.recovery));
    chartData.push({ time: Math.floor(now - (pts-i)*2592000), value: +(invest * ratio).toFixed(0) });
  }
  const baseline = chartData.map(d => ({ time:d.time, value:invest }));
  const el = document.getElementById('qzsc-crisis-chart');
  if (el && _tvCrisisChart) { try {_tvCrisisChart.remove();} catch(_){} _tvCrisisChart=null; }
  if (el && typeof LightweightCharts !== 'undefined') {
    el.innerHTML='';
    _tvCrisisChart = LightweightCharts.createChart(el, { width:el.offsetWidth||600,height:210,layout:{background:{color:'transparent'},textColor:'#94A3B8'},grid:{vertLines:{color:'rgba(255,255,255,0.02)'},horzLines:{color:'rgba(255,255,255,0.03)'}},timeScale:{borderColor:'rgba(255,255,255,0.06)'},rightPriceScale:{borderColor:'rgba(255,255,255,0.06)'},crosshair:{mode:1},handleScale:{mouseWheel:false},handleScroll:{mouseWheel:false} });
    const s = _tvCrisisChart.addAreaSeries({ lineColor:c.color, topColor:c.color.replace(')',',0.18)').replace('rgb','rgba'), bottomColor:'rgba(0,0,0,0)', lineWidth:2, priceFormat:{type:'custom',formatter:v=>'$'+(v/1000).toFixed(0)+'k',minMove:1}, priceLineVisible:false });
    s.setData(chartData);
    const b = _tvCrisisChart.addLineSeries({ color:'rgba(255,255,255,0.12)',lineWidth:1,lineStyle:2,priceFormat:{type:'custom',formatter:v=>'$'+(v/1000).toFixed(0)+'k',minMove:1},priceLineVisible:false,lastValueVisible:false });
    b.setData(baseline);
    _tvCrisisChart.timeScale().fitContent();
  }
}

// --- Monte Carlo ---
let _tvMCChart = null;
function _qzscRunMonteCarlo() {
  const invest  = parseFloat(document.getElementById('qzmc-invest')?.value) || 100000;
  const monthly = parseFloat(document.getElementById('qzmc-monthly')?.value) || 1000;
  const retPct  = parseFloat(document.getElementById('qzmc-return')?.value) || 10;
  const volPct  = parseFloat(document.getElementById('qzmc-vol')?.value) || 15;
  const years   = parseInt(document.getElementById('qzmc-years')?.value) || 20;
  const sims    = parseInt(document.getElementById('qzmc-sims')?.value) || 500;
  const monthlyDrift = retPct/100/12;
  const monthlyVol   = volPct/100/Math.sqrt(12);
  const months = years * 12;
  let seed = 42;
  const rng = () => { seed = (seed*1664525+1013904223)&0xffffffff; return ((seed>>>0)/4294967296-0.5)*2; };
  const paths = [];
  const finals = [];
  for (let s=0; s<sims; s++) {
    let v = invest;
    const path = [v];
    for (let m=0; m<months; m++) {
      v = v*(1 + monthlyDrift + monthlyVol*rng()) + monthly;
      v = Math.max(0, v);
      path.push(v);
    }
    paths.push(path);
    finals.push(v);
  }
  finals.sort((a,b)=>a-b);
  const p10 = finals[Math.floor(sims*0.10)];
  const p25 = finals[Math.floor(sims*0.25)];
  const p50 = finals[Math.floor(sims*0.50)];
  const p75 = finals[Math.floor(sims*0.75)];
  const p90 = finals[Math.floor(sims*0.90)];
  const probDouble = finals.filter(v=>v>=invest*2).length/sims*100;
  const probLoss   = finals.filter(v=>v<invest).length/sims*100;
  const fmt = v => '$'+(v>=1e6?(v/1e6).toFixed(1)+'M':(v/1000).toFixed(0)+'k');
  document.getElementById('qzmc-results').innerHTML = `
    <div class="qzsc-metric-grid" style="margin-bottom:8px;">
      <div class="qzsc-metric"><div class="qzsc-metric-label">Median Outcome (P50)</div><div class="qzsc-metric-val" style="color:#A78BFA;font-size:17px;">${fmt(p50)}</div><div class="qzsc-metric-sub">50th percentile</div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">Optimistic (P90)</div><div class="qzsc-metric-val" style="color:#34D399;font-size:17px;">${fmt(p90)}</div><div class="qzsc-metric-sub">90th percentile</div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">Conservative (P10)</div><div class="qzsc-metric-val" style="color:#F87171;font-size:17px;">${fmt(p10)}</div><div class="qzsc-metric-sub">10th percentile</div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">P75 / P25</div><div class="qzsc-metric-val" style="font-size:14px;">${fmt(p75)}<br><span style="font-size:11px;color:var(--text-muted)">${fmt(p25)}</span></div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">Prob. of Doubling</div><div class="qzsc-metric-val" style="color:#34D399;font-size:17px;">${probDouble.toFixed(0)}%</div><div class="qzsc-metric-sub">vs initial investment</div></div>
      <div class="qzsc-metric"><div class="qzsc-metric-label">Prob. of Loss</div><div class="qzsc-metric-val" style="color:#F87171;font-size:17px;">${probLoss.toFixed(1)}%</div><div class="qzsc-metric-sub">Below initial capital</div></div>
    </div>`;
  // Draw chart: sample ~50 paths + P10/P50/P90 bands
  const el = document.getElementById('qzmc-chart');
  if (!el || typeof LightweightCharts==='undefined') return;
  el.innerHTML='';
  if (_tvMCChart) { try{_tvMCChart.remove();}catch(_){} _tvMCChart=null; }
  _tvMCChart = LightweightCharts.createChart(el, { width:el.offsetWidth||600,height:240,layout:{background:{color:'transparent'},textColor:'#94A3B8'},grid:{vertLines:{color:'rgba(255,255,255,0.02)'},horzLines:{color:'rgba(255,255,255,0.03)'}},timeScale:{borderColor:'rgba(255,255,255,0.06)'},rightPriceScale:{borderColor:'rgba(255,255,255,0.06)'},crosshair:{mode:1},handleScale:{mouseWheel:false},handleScroll:{mouseWheel:false} });
  const now = Math.floor(Date.now()/1000);
  const mkData = path => path.map((v,i) => ({ time:now - (months-i)*2592000, value:+v.toFixed(0) }));
  // Draw a sample of paths in faint color
  const step = Math.max(1, Math.floor(sims/40));
  for (let s=0; s<sims; s+=step) {
    const ps = _tvMCChart.addLineSeries({ color:'rgba(167,139,250,0.08)', lineWidth:1, priceLineVisible:false, lastValueVisible:false, crosshairMarkerVisible:false });
    ps.setData(mkData(paths[s]));
  }
  // P10 / P90 / P50 bands
  const pIdx = pct => Math.floor(sims*pct/100);
  const buildBand = pct => {
    const sorted = paths.map((p,i)=>({v:p[p.length-1],i})).sort((a,b)=>a.v-b.v);
    const pidx = sorted[pIdx(pct)].i;
    return paths[pidx];
  };
  const bandPath = (pct,col,lw) => { const s=_tvMCChart.addLineSeries({color:col,lineWidth:lw,priceLineVisible:false,lastValueVisible:true,crosshairMarkerVisible:false}); s.setData(mkData(buildBand(pct))); };
  bandPath(90,'rgba(52,211,153,0.8)',2);
  bandPath(50,'rgba(167,139,250,0.9)',2);
  bandPath(10,'rgba(248,113,113,0.8)',2);
  _tvMCChart.timeScale().fitContent();
  new ResizeObserver(es=>{if(_tvMCChart)_tvMCChart.applyOptions({width:es[0].contentRect.width});}).observe(el);
}

// --- Stress Test ---
function _qzscRunStress() {
  const invest = parseFloat(document.getElementById('qzst-invest')?.value) || 250000;
  const us     = (parseFloat(document.getElementById('qzst-us')?.value)||50)/100;
  const intl   = (parseFloat(document.getElementById('qzst-intl')?.value)||20)/100;
  const bond   = (parseFloat(document.getElementById('qzst-bond')?.value)||20)/100;
  const comm   = (parseFloat(document.getElementById('qzst-comm')?.value)||5)/100;
  const cash   = (parseFloat(document.getElementById('qzst-cash')?.value)||5)/100;
  const scenarios = [
    { name:'Fed Rate Hike +200bps',      impacts:{ us:-0.15, intl:-0.12, bond:-0.10, comm:0.05,  cash:0 }, color:'#F87171' },
    { name:'Severe Recession (-30%)',     impacts:{ us:-0.30, intl:-0.25, bond:0.12,  comm:-0.15, cash:0 }, color:'#EF4444' },
    { name:'Stagflation',                 impacts:{ us:-0.20, intl:-0.18, bond:-0.08, comm:0.20,  cash:-0.05 }, color:'#FB923C' },
    { name:'Dollar Crash (-20%)',         impacts:{ us:-0.08, intl:0.15,  bond:-0.05, comm:0.18,  cash:-0.20 }, color:'#FBBF24' },
    { name:'China Credit Crisis',         impacts:{ us:-0.12, intl:-0.20, bond:0.08,  comm:-0.10, cash:0 }, color:'#A78BFA' },
    { name:'Tech Sector Crash (-40%)',    impacts:{ us:-0.22, intl:-0.10, bond:0.05,  comm:0.02,  cash:0 }, color:'#60A5FA' },
    { name:'Oil Shock +80%',              impacts:{ us:-0.10, intl:-0.08, bond:-0.03, comm:0.22,  cash:0 }, color:'#34D399' },
    { name:'Global Pandemic (COVID-like)',impacts:{ us:-0.34, intl:-0.30, bond:0.10,  comm:-0.20, cash:0 }, color:'#F87171' },
    { name:'Geopolitical Conflict',       impacts:{ us:-0.15, intl:-0.20, bond:0.05,  comm:0.25,  cash:0 }, color:'#FBBF24' },
    { name:'Crypto/FinTech Contagion',    impacts:{ us:-0.12, intl:-0.08, bond:0.02,  comm:0.00,  cash:0 }, color:'#A78BFA' },
  ];
  const rows = scenarios.map(sc => {
    const impact = invest*(us*sc.impacts.us + intl*sc.impacts.intl + bond*sc.impacts.bond + comm*sc.impacts.comm + cash*sc.impacts.cash);
    const final  = invest + impact;
    const pct    = impact/invest*100;
    const col    = pct >= 0 ? '#34D399' : '#F87171';
    return `<div class="qzsc-stress-row">
      <div style="width:10px;height:10px;border-radius:50%;background:${sc.color};flex-shrink:0;"></div>
      <div class="qzsc-stress-name">${sc.name}</div>
      <div style="text-align:right;flex-shrink:0;">
        <div class="qzsc-stress-impact" style="color:${col}">${pct>=0?'+':''}${pct.toFixed(1)}%</div>
        <div class="qzsc-stress-desc">$${Math.abs(impact/1000).toFixed(0)}k ${impact>=0?'gain':'loss'} → $${(final/1000).toFixed(0)}k</div>
      </div>
    </div>`;
  }).join('');
  document.getElementById('qzst-results').innerHTML = `
    <div style="font-size:9px;font-family:var(--font-mono);color:var(--text-muted);text-transform:uppercase;letter-spacing:0.12em;margin-bottom:10px;">10 Scenario Stress Tests — $${(invest/1000).toFixed(0)}k Portfolio</div>
    ${rows}`;
}

// --- Macro Impact ---
function _qzscRunMacro() {
  const invest   = parseFloat(document.getElementById('qzmacro-invest')?.value) || 100000;
  const equityPct= (parseFloat(document.getElementById('qzmacro-equity')?.value)||70)/100;
  const bondPct  = 1 - equityPct;
  const rateBps  = parseFloat(document.getElementById('qzmacro-rate')?.value) || 100;
  const inflation= parseFloat(document.getElementById('qzmacro-inflation')?.value) || 3;
  const usd      = parseFloat(document.getElementById('qzmacro-usd')?.value) || 8;
  const oil      = parseFloat(document.getElementById('qzmacro-oil')?.value) || 40;
  const gdp      = parseFloat(document.getElementById('qzmacro-gdp')?.value) || -2;
  const credit   = parseFloat(document.getElementById('qzmacro-credit')?.value) || 200;
  // Each shock's impact on equity and bond allocations (simplified empirical relationships)
  const rateEquityImpact  = -(rateBps/100) * 0.08;
  const rateBondImpact    = -(rateBps/100) * 0.07;
  const inflEquityImpact  = -(inflation/10) * 0.05;
  const usdEquityImpact   = -(usd/100) * 0.12;
  const oilEquityImpact   = oil > 0 ? -(oil/100)*0.04 : (Math.abs(oil)/100)*0.02;
  const gdpEquityImpact   = gdp < 0 ? gdp/100 * 2 : gdp/100 * 0.5;
  const creditEquityImpact= -(credit/1000) * 0.15;
  const shocks = [
    { name:`Rate Hike +${rateBps}bps`, equityImpact:rateEquityImpact, bondImpact:rateBondImpact, explanation:`Duration-sensitive: higher rates compress equity multiples and depress bond prices` },
    { name:`Inflation +${inflation}%`, equityImpact:inflEquityImpact, bondImpact:-inflation/100*0.06, explanation:`Erodes real returns; growth stocks hurt most; TIPS & commodities benefit` },
    { name:`USD +${usd}%`, equityImpact:usdEquityImpact, bondImpact:0, explanation:`Stronger dollar hurts US multinational earnings and emerging market assets` },
    { name:`Oil ${oil>0?'+':''}${oil}%`, equityImpact:oilEquityImpact, bondImpact:0, explanation:`Energy shock ripples into inflation, consumer spending, and corporate margins` },
    { name:`GDP ${gdp}%`, equityImpact:gdpEquityImpact, bondImpact:gdp<0?0.05:0, explanation:`GDP contraction → earnings recession → equity repricing; bonds rally as safe haven` },
    { name:`Credit Spread +${credit}bps`, equityImpact:creditEquityImpact, bondImpact:-credit/1000*0.08, explanation:`Wider spreads signal credit stress; high-yield bonds and leveraged firms most exposed` },
  ];
  const totalEquityImpactPct = shocks.reduce((a,s)=>a+s.equityImpact,0);
  const totalBondImpactPct   = shocks.reduce((a,s)=>a+s.bondImpact,0);
  const totalPortImpact      = invest*(equityPct*totalEquityImpactPct + bondPct*totalBondImpactPct);
  const finalValue           = invest + totalPortImpact;
  const totalPct             = totalPortImpact/invest*100;
  const fmt = v => '$' + Math.abs(v).toLocaleString('en-US',{maximumFractionDigits:0});
  const rows = shocks.map(s => {
    const eImpact = invest*equityPct*s.equityImpact;
    const bImpact = invest*bondPct*s.bondImpact;
    const tot     = eImpact + bImpact;
    const col     = tot>=0?'#34D399':'#F87171';
    return `<div class="qzsc-stress-row">
      <div class="qzsc-stress-name">
        <div style="font-size:11px;color:var(--text-primary);">${s.name}</div>
        <div style="font-size:9px;color:var(--text-muted);font-family:var(--font-mono);margin-top:2px;">${s.explanation}</div>
      </div>
      <div style="text-align:right;flex-shrink:0;min-width:80px;">
        <div class="qzsc-stress-impact" style="color:${col}">${tot>=0?'+':'-'}${fmt(Math.abs(tot))}</div>
        <div class="qzsc-stress-desc">${(tot/invest*100).toFixed(1)}%</div>
      </div>
    </div>`;
  }).join('');
  document.getElementById('qzmacro-results').innerHTML = `
    <div style="background:${totalPct>=0?'rgba(52,211,153,0.08)':'rgba(248,113,113,0.08)'};border:1px solid ${totalPct>=0?'rgba(52,211,153,0.25)':'rgba(248,113,113,0.25)'};border-radius:10px;padding:14px;margin-bottom:12px;display:flex;align-items:center;gap:14px;">
      <div><div style="font-size:9px;font-family:var(--font-mono);color:var(--text-muted);text-transform:uppercase;margin-bottom:3px;">Combined Portfolio Impact</div>
      <div style="font-size:26px;font-weight:800;color:${totalPct>=0?'#34D399':'#F87171'};font-family:var(--font-display);">${totalPct>=0?'+':''}${fmt(totalPortImpact)}</div>
      <div style="font-size:11px;color:var(--text-muted);font-family:var(--font-mono);">${totalPct.toFixed(1)}% · Final value: ${fmt(finalValue)}</div></div>
    </div>
    <div style="font-size:9px;font-family:var(--font-mono);color:var(--text-muted);text-transform:uppercase;letter-spacing:0.12em;margin-bottom:8px;">Shock-by-Shock Breakdown (${(equityPct*100).toFixed(0)}% equity / ${(bondPct*100).toFixed(0)}% bonds)</div>
    ${rows}`;
}

// ==================== BACKTEST ENGINE ====================
const _QZBT_PARAMS = {
  mac:  [{id:'bt-fast',label:'Fast MA',val:10,min:2,max:200},{id:'bt-slow',label:'Slow MA',val:50,min:5,max:500}],
  rsi:  [{id:'bt-rsi-per',label:'RSI Period',val:14,min:2,max:100},{id:'bt-rsi-os',label:'Oversold',val:30,min:1,max:49},{id:'bt-rsi-ob',label:'Overbought',val:70,min:51,max:99}],
  mom:  [{id:'bt-mom-lb',label:'Lookback',val:20,min:5,max:252}],
  mr:   [{id:'bt-mr-per',label:'Period',val:20,min:5,max:100},{id:'bt-mr-thr',label:'Threshold %',val:2,min:0,max:20}],
  bb:   [{id:'bt-bb-per',label:'Period',val:20,min:5,max:100},{id:'bt-bb-std',label:'Std Dev',val:2,min:0.5,max:4,step:0.1}],
  macd: [{id:'bt-mc-fast',label:'Fast',val:12,min:2,max:50},{id:'bt-mc-slow',label:'Slow',val:26,min:5,max:100},{id:'bt-mc-sig',label:'Signal',val:9,min:2,max:30}],
  tri:  [{id:'bt-tri-f',label:'Fast MA',val:10,min:2,max:100},{id:'bt-tri-m',label:'Mid MA',val:30,min:5,max:200},{id:'bt-tri-s',label:'Slow MA',val:50,min:10,max:500}],
  bah:  [],
  vwap: [{id:'bt-vwap-per',label:'Period',val:20,min:5,max:100}],
};

function _qzbtUpdateParams() {
  const strat = document.getElementById('bt-strategy').value;
  const container = document.getElementById('qzbt-strategy-params');
  if (!container) return;
  const params = _QZBT_PARAMS[strat] || [];
  if (!params.length) {
    container.innerHTML = '<span style="font-family:var(--font-mono);font-size:10px;color:var(--text-muted);">No extra parameters — Buy &amp; Hold stays fully invested.</span>';
    return;
  }
  container.innerHTML = params.map(p =>
    `<div class="qzbt-param"><div class="qzbt-param-label">${p.label}</div><input class="qzbt-param-input" id="${p.id}" type="number" value="${p.val}" min="${p.min||1}" max="${p.max||999}" step="${p.step||1}"></div>`
  ).join('');
}

function _qzbtAssetSearch(val) {
  const sug = document.getElementById('bt-suggestions');
  if (!sug) return;
  val = val.trim().toUpperCase();
  if (!val) { sug.classList.add('hidden'); return; }
  const matches = [];
  if (typeof STOCKS !== 'undefined') {
    for (const s of STOCKS) {
      if (s.t && (s.t.startsWith(val) || (s.n && s.n.toUpperCase().includes(val)))) {
        matches.push({ t: s.t, n: s.n || '' });
        if (matches.length >= 8) break;
      }
    }
  }
  const extras = [
    {t:'BTC-USD',n:'Bitcoin'},{t:'ETH-USD',n:'Ethereum'},{t:'SPY',n:'S&P 500 ETF'},
    {t:'QQQ',n:'Nasdaq-100 ETF'},{t:'GLD',n:'Gold ETF'},{t:'TLT',n:'20Y Treasury ETF'},
    {t:'EURUSD=X',n:'EUR/USD'},{t:'^GSPC',n:'S&P 500 Index'},{t:'^NSEI',n:'Nifty 50'},
    {t:'RELIANCE.NS',n:'Reliance Industries'},{t:'TCS.NS',n:'Tata Consultancy'},
    {t:'005930.KS',n:'Samsung Electronics'},
  ].filter(e => e.t.includes(val) || e.n.toUpperCase().includes(val));
  const seen = new Set(matches.map(m => m.t));
  const combined = [...matches, ...extras.filter(e => !seen.has(e.t))].slice(0, 8);
  if (!combined.length) { sug.classList.add('hidden'); return; }
  sug.innerHTML = combined.map(m =>
    `<div class="qzbt-suggestion" onmousedown="document.getElementById('bt-asset-input').value='${m.t.replace(/'/g,"\\'")}';document.getElementById('bt-suggestions').classList.add('hidden');"><span style="font-weight:700;color:var(--accent);">${m.t}</span><span style="color:var(--text-muted);font-size:10px;">${(m.n||'').substring(0,28)}</span></div>`
  ).join('');
  sug.classList.remove('hidden');
}

function runBacktest() {
  const asset = (document.getElementById('bt-asset-input') ? document.getElementById('bt-asset-input').value : 'AAPL').trim().toUpperCase() || 'AAPL';
  const strategy = document.getElementById('bt-strategy').value || 'mac';
  const periodSel = (document.getElementById('bt-period') ? document.getElementById('bt-period').value : '3y') || '3y';
  const periodMap = {'1y':252,'2y':504,'3y':756,'5y':1260,'10y':2520,'20y':5040};
  const periodYears = parseFloat(periodSel.replace('y','')) || 3;
  const totalDays = periodMap[periodSel] || 756;
  const capital = parseFloat(document.getElementById('bt-capital').value) || 100000;
  const commission = parseFloat(document.getElementById('bt-commission').value) || 0;
  const slippage = (parseFloat(document.getElementById('bt-slippage').value) || 5) / 10000;

  // Deterministic PRNG seeded from asset+strategy
  let seed = 0;
  for (let i = 0; i < asset.length; i++) seed = (seed * 31 + asset.charCodeAt(i)) & 0x7fffffff;
  for (let i = 0; i < strategy.length; i++) seed = (seed * 31 + strategy.charCodeAt(i)) & 0x7fffffff;
  const origSeed = seed;
  function rng() { seed ^= seed << 13; seed ^= seed >>> 17; seed ^= seed << 5; return (seed >>> 0) / 0x100000000; }
  function rnorm() { const u1 = rng() || 1e-10, u2 = rng(); return Math.sqrt(-2*Math.log(u1))*Math.cos(2*Math.PI*u2); }

  // Asset GBM params derived from seed
  const assetVol = 0.12 + (origSeed % 1000) / 1000 * 0.30;
  const assetDrift = -0.02 + (origSeed % 500) / 500 * 0.24;
  const dailyVol = assetVol / Math.sqrt(252);
  const dailyDrift = assetDrift / 252;
  const startPrice = 20 + (origSeed % 480);

  // Generate asset price series (GBM)
  const prices = [startPrice];
  for (let i = 1; i < totalDays; i++) {
    prices.push(Math.max(0.01, prices[i-1] * Math.exp(dailyDrift - 0.5*dailyVol*dailyVol + dailyVol*rnorm())));
  }

  // Generate benchmark series (S&P ~10% annual, ~16% vol) — fixed seed
  let bSeed = 0x5e4c3a2b;
  function bRng() { bSeed ^= bSeed << 13; bSeed ^= bSeed >>> 17; bSeed ^= bSeed << 5; return (bSeed >>> 0) / 0x100000000; }
  function bRnorm() { const u1 = bRng()||1e-10, u2=bRng(); return Math.sqrt(-2*Math.log(u1))*Math.cos(2*Math.PI*u2); }
  const benchPrices = [startPrice];
  const bDrift = 0.10/252, bVol = 0.16/Math.sqrt(252);
  for (let i = 1; i < totalDays; i++) {
    benchPrices.push(Math.max(0.01, benchPrices[i-1] * Math.exp(bDrift - 0.5*bVol*bVol + bVol*bRnorm())));
  }

  // Indicator helpers
  function sma(arr, n) { return arr.map((_,i) => i<n-1?null:arr.slice(i-n+1,i+1).reduce((a,b)=>a+b)/n); }
  function ema(arr, n) {
    const k=2/(n+1); let e=null; return arr.map(v => { if(v===null) return null; e=e===null?v:v*k+e*(1-k); return e; });
  }
  function rsiCalc(arr, n) {
    const res=Array(arr.length).fill(null); if(arr.length<n+1) return res;
    let ag=0, al=0;
    for(let i=1;i<=n;i++){const d=arr[i]-arr[i-1];d>0?ag+=d:al+=-d;}
    ag/=n; al/=n;
    res[n]=100-100/(1+(al===0?1e9:ag/al));
    for(let i=n+1;i<arr.length;i++){const d=arr[i]-arr[i-1];ag=(ag*(n-1)+(d>0?d:0))/n;al=(al*(n-1)+(d<0?-d:0))/n;res[i]=100-100/(1+(al===0?1e9:ag/al));}
    return res;
  }
  function stdCalc(arr, n) {
    return arr.map((_,i)=>{if(i<n-1)return null;const sl=arr.slice(i-n+1,i+1),m=sl.reduce((a,b)=>a+b)/n;return Math.sqrt(sl.reduce((a,b)=>a+(b-m)**2,0)/n);});
  }

  // Strategy signal generation — returns array of 0 (flat) or 1 (long) per day
  function getSignals() {
    const gp = id => { const el=document.getElementById(id); return el?parseFloat(el.value)||0:0; };
    const sig = Array(totalDays).fill(0);
    if (strategy === 'bah') return Array(totalDays).fill(1);
    if (strategy === 'mac') {
      const fast=Math.max(2,gp('bt-fast')||10), slow=Math.max(fast+1,gp('bt-slow')||50);
      const fSma=sma(prices,fast), sSma=sma(prices,slow); let pos=0;
      for(let i=slow;i<totalDays;i++){if(fSma[i]>sSma[i]&&fSma[i-1]<=sSma[i-1])pos=1;else if(fSma[i]<sSma[i]&&fSma[i-1]>=sSma[i-1])pos=0;sig[i]=pos;}
    } else if (strategy === 'rsi') {
      const per=Math.max(2,gp('bt-rsi-per')||14), os=gp('bt-rsi-os')||30, ob=gp('bt-rsi-ob')||70;
      const rv=rsiCalc(prices,per); let pos=0;
      for(let i=per;i<totalDays;i++){if(rv[i]!==null){if(rv[i]<os)pos=1;else if(rv[i]>ob)pos=0;}sig[i]=pos;}
    } else if (strategy === 'mom') {
      const lb=Math.max(5,gp('bt-mom-lb')||20); let pos=0;
      for(let i=lb;i<totalDays;i++){pos=prices[i]/prices[i-lb]-1>0?1:0;sig[i]=pos;}
    } else if (strategy === 'mr') {
      const per=Math.max(5,gp('bt-mr-per')||20);
      const smaN=sma(prices,per), stdN=stdCalc(prices,per); let pos=0;
      for(let i=per;i<totalDays;i++){if(smaN[i]!==null){const z=(prices[i]-smaN[i])/(stdN[i]||1);if(z<-1.5)pos=1;else if(z>0.5)pos=0;}sig[i]=pos;}
    } else if (strategy === 'bb') {
      const per=Math.max(5,gp('bt-bb-per')||20), k=gp('bt-bb-std')||2;
      const smaN=sma(prices,per), stdN=stdCalc(prices,per); let pos=0;
      for(let i=per;i<totalDays;i++){if(smaN[i]!==null&&stdN[i]!==null){const u=smaN[i]+k*stdN[i],l=smaN[i]-k*stdN[i];if(prices[i]<=l)pos=1;else if(prices[i]>=u)pos=0;}sig[i]=pos;}
    } else if (strategy === 'macd') {
      const fast=Math.max(2,gp('bt-mc-fast')||12), slow2=Math.max(fast+1,gp('bt-mc-slow')||26), sigP=Math.max(2,gp('bt-mc-sig')||9);
      const fE=ema(prices,fast), sE=ema(prices,slow2);
      const macdL=prices.map((_,i)=>(fE[i]!==null&&sE[i]!==null)?fE[i]-sE[i]:null);
      const validMacd=macdL.filter(v=>v!==null); const sigL=ema(validMacd,sigP);
      let sIdx=0; const fullSig=macdL.map(v=>v===null?null:(sigL[sIdx++]||null));
      let pos=0;
      for(let i=1;i<totalDays;i++){if(macdL[i]!==null&&fullSig[i]!==null){if(macdL[i]>fullSig[i]&&(macdL[i-1]||0)<=(fullSig[i-1]||0))pos=1;else if(macdL[i]<fullSig[i]&&(macdL[i-1]||0)>=(fullSig[i-1]||0))pos=0;}sig[i]=pos;}
    } else if (strategy === 'tri') {
      const f=Math.max(2,gp('bt-tri-f')||10), m=Math.max(f+1,gp('bt-tri-m')||30), s2=Math.max(m+1,gp('bt-tri-s')||50);
      const fS=sma(prices,f), mS=sma(prices,m), sS=sma(prices,s2); let pos=0;
      for(let i=s2;i<totalDays;i++){if(fS[i]>mS[i]&&mS[i]>sS[i])pos=1;else if(fS[i]<mS[i]&&mS[i]<sS[i])pos=0;sig[i]=pos;}
    } else if (strategy === 'vwap') {
      const per=Math.max(5,gp('bt-vwap-per')||20);
      const vLine=sma(prices,per); let pos=0;
      for(let i=per;i<totalDays;i++){if(vLine[i]!==null){if(prices[i]>vLine[i])pos=1;else if(prices[i]<vLine[i]*0.99)pos=0;}sig[i]=pos;}
    }
    return sig;
  }
  const signals = getSignals();

  // Build trading day dates (walking back from today)
  const todayMs = new Date('2026-05-19').getTime();
  const msDay = 86400000;
  const dates = [];
  let dCur = new Date(todayMs);
  while (dates.length < totalDays) {
    if (dCur.getDay() !== 0 && dCur.getDay() !== 6) dates.unshift(dCur.toISOString().slice(0,10));
    dCur = new Date(dCur.getTime() - msDay);
  }

  // Portfolio simulation
  let cash = capital, shares = 0, inPos = false, entryPrice = 0, entryDate = '';
  const equity = [capital];
  const benchEquity = [capital];
  const trades = [];
  const bShares = capital / benchPrices[0];

  seed = origSeed + 7; // fresh sub-seed for spread noise
  for (let i = 1; i < totalDays; i++) {
    const sig = signals[i];
    const px = prices[i];
    const spread = px * slippage;
    if (sig === 1 && !inPos) {
      const buyPx = px + spread;
      const buyShares = Math.floor((cash - commission) / buyPx);
      if (buyShares > 0) { cash -= buyShares*buyPx + commission; shares=buyShares; inPos=true; entryPrice=buyPx; entryDate=dates[i]; }
    } else if (sig === 0 && inPos) {
      const sellPx = Math.max(0.01, px - spread);
      const proceeds = shares*sellPx - commission;
      trades.push({ entry:entryDate, exit:dates[i], entryP:entryPrice, exitP:sellPx, ret:(sellPx-entryPrice)/entryPrice, pnl:proceeds - shares*entryPrice });
      cash += proceeds; shares=0; inPos=false;
    }
    equity.push(cash + shares*prices[i]);
    benchEquity.push(bShares * benchPrices[i]);
  }
  // Close open position at period end
  if (inPos && shares > 0) {
    const sellPx = Math.max(0.01, prices[totalDays-1] - prices[totalDays-1]*slippage);
    trades.push({ entry:entryDate, exit:dates[totalDays-1], entryP:entryPrice, exitP:sellPx, ret:(sellPx-entryPrice)/entryPrice, pnl:shares*sellPx-commission - shares*entryPrice });
    cash += shares*sellPx - commission; shares=0;
    equity[equity.length-1] = cash;
  }

  // Compute metrics
  const finalEq = equity[equity.length-1];
  const totalRet = (finalEq - capital) / capital;
  const cagr = Math.pow(Math.max(0.0001, finalEq/capital), 1/periodYears) - 1;
  const dailyRets = equity.map((v,i) => i===0?0:(v-equity[i-1])/equity[i-1]).slice(1);
  const meanRet = dailyRets.reduce((a,b)=>a+b,0)/dailyRets.length;
  const stdDev = Math.sqrt(dailyRets.reduce((a,b)=>a+(b-meanRet)**2,0)/dailyRets.length) || 1e-9;
  const rfDaily = 0.05/252;
  const sharpe = (meanRet - rfDaily) / stdDev * Math.sqrt(252);
  const downRets = dailyRets.filter(r=>r<rfDaily);
  const downStd = downRets.length ? Math.sqrt(downRets.reduce((a,b)=>a+(b-rfDaily)**2,0)/downRets.length) : stdDev;
  const sortino = (meanRet - rfDaily) / downStd * Math.sqrt(252);

  let peak = capital, maxDD = 0;
  const drawdownSeries = [];
  for (let i = 0; i < equity.length; i++) {
    if (equity[i] > peak) peak = equity[i];
    const dd = peak > 0 ? (equity[i]-peak)/peak : 0;
    if (dd < maxDD) maxDD = dd;
    drawdownSeries.push({ time: dates[i], value: parseFloat((dd*100).toFixed(3)) });
  }
  const calmar = maxDD < 0 ? Math.abs(cagr/maxDD) : 0;

  const winT = trades.filter(t=>t.ret>0), lossT = trades.filter(t=>t.ret<=0);
  const winRate = trades.length ? winT.length/trades.length : 0;
  const avgWin = winT.length ? winT.reduce((a,t)=>a+t.ret,0)/winT.length : 0;
  const avgLoss = lossT.length ? lossT.reduce((a,t)=>a+t.ret,0)/lossT.length : 0;
  const grossWin = winT.reduce((a,t)=>a+t.pnl,0);
  const grossLoss = Math.abs(lossT.reduce((a,t)=>a+t.pnl,0));
  const profitFactor = grossLoss>0 ? grossWin/grossLoss : grossWin>0 ? 99 : 0;
  const benchFinal = benchEquity[benchEquity.length-1];
  const alpha = totalRet - (benchFinal-capital)/capital;

  // Update DOM metrics
  const fmtPct = (v,d=1) => (v>=0?'+':'')+(v*100).toFixed(d)+'%';
  const setM = (id, val, txt) => { const el=document.getElementById(id); if(!el)return; el.textContent=txt; el.style.color=val>0?'#34D399':val<0?'#F87171':'var(--text-primary)'; };
  setM('bt-ret', totalRet, fmtPct(totalRet));
  setM('bt-cagr', cagr, fmtPct(cagr));
  setM('bt-sharpe', sharpe-1, sharpe.toFixed(2));
  setM('bt-sortino', sortino-1, sortino.toFixed(2));
  setM('bt-draw', maxDD, fmtPct(maxDD));
  setM('bt-calmar', calmar-1, calmar.toFixed(2));
  setM('bt-win', winRate-0.5, (winRate*100).toFixed(1)+'%');
  setM('bt-pf', profitFactor-1, profitFactor.toFixed(2));
  setM('bt-avgwin', avgWin, fmtPct(avgWin,2));
  setM('bt-avgloss', avgLoss, fmtPct(avgLoss,2));
  const trEl=document.getElementById('bt-trades'); if(trEl){trEl.textContent=trades.length;trEl.style.color='var(--text-primary)';}
  setM('bt-vsbench', alpha, fmtPct(alpha));

  document.getElementById('bt-results').classList.remove('hidden');

  // Build chart data arrays
  const equityCurve = equity.map((v,i)=>({time:dates[i],value:parseFloat(v.toFixed(2))}));
  const benchCurve = benchEquity.map((v,i)=>({time:dates[i],value:parseFloat(v.toFixed(2))}));

  setTimeout(() => {
    renderBacktestChart(equityCurve, benchCurve, capital, periodYears);
    renderDrawdownChart(drawdownSeries);
    renderMonthlyHeatmap(equityCurve, periodYears);
    renderTradeLog(trades);
  }, 120);
}

let _tvBtChart = null;
function renderBacktestChart(equityCurve, benchCurve, capital, years) {
  const container = document.getElementById('backtest-chart');
  if (!container) return;
  if (container.offsetWidth === 0) { setTimeout(()=>renderBacktestChart(equityCurve,benchCurve,capital,years),220); return; }
  if (_tvBtChart) { try { _tvBtChart.remove(); } catch(_){} _tvBtChart=null; }
  container.innerHTML = '';
  if (typeof LightweightCharts !== 'undefined') {
    _tvBtChart = LightweightCharts.createChart(container, {
      width: container.offsetWidth||600, height: 260,
      layout:{background:{color:'transparent'},textColor:'#5a5a5a',fontFamily:"'DM Mono',monospace",fontSize:10},
      grid:{vertLines:{color:'rgba(255,255,255,0.025)'},horzLines:{color:'rgba(255,255,255,0.035)'}},
      crosshair:{mode:1},
      timeScale:{borderColor:'rgba(255,255,255,0.06)',fixLeftEdge:true,fixRightEdge:true},
      rightPriceScale:{borderColor:'rgba(255,255,255,0.06)',scaleMargins:{top:0.1,bottom:0.1}},
      handleScale:{mouseWheel:false},handleScroll:{mouseWheel:false},
    });
    const portSeries = _tvBtChart.addAreaSeries({
      lineColor:'#A78BFA',topColor:'rgba(167,139,250,0.22)',bottomColor:'rgba(167,139,250,0.01)',
      lineWidth:2,priceFormat:{type:'custom',formatter:v=>'$'+(v>=1000?(v/1000).toFixed(0)+'k':v.toFixed(0)),minMove:1},
      priceLineVisible:false,lastValueVisible:true,
    });
    portSeries.setData(equityCurve);
    const bmSeries = _tvBtChart.addLineSeries({
      color:'rgba(96,165,250,0.55)',lineWidth:1,lineStyle:2,
      priceFormat:{type:'custom',formatter:v=>'$'+(v>=1000?(v/1000).toFixed(0)+'k':v.toFixed(0)),minMove:1},
      priceLineVisible:false,lastValueVisible:false,
    });
    bmSeries.setData(benchCurve);
    _tvBtChart.timeScale().fitContent();
    new ResizeObserver(es=>{if(_tvBtChart)_tvBtChart.applyOptions({width:es[0].contentRect.width});}).observe(container);
  } else {
    const canvas=document.createElement('canvas'); container.appendChild(canvas);
    const ctx=canvas.getContext('2d'), W=container.offsetWidth||600, H=260;
    canvas.width=W; canvas.height=H; canvas.style.cssText='width:100%;height:'+H+'px;';
    const vals=equityCurve.map(d=>d.value);
    const mn=Math.min(...vals)*0.97, mx=Math.max(...vals)*1.03;
    const nr=v=>H-((v-mn)/(mx-mn))*H*0.85-H*0.05;
    const gr=ctx.createLinearGradient(0,0,0,H); gr.addColorStop(0,'rgba(167,139,250,0.18)'); gr.addColorStop(1,'rgba(167,139,250,0)');
    ctx.beginPath(); vals.forEach((p,i)=>{const x=(i/(vals.length-1))*W;i===0?ctx.moveTo(x,nr(p)):ctx.lineTo(x,nr(p));});
    ctx.lineTo(W,H); ctx.lineTo(0,H); ctx.closePath(); ctx.fillStyle=gr; ctx.fill();
    ctx.beginPath(); ctx.strokeStyle='#A78BFA'; ctx.lineWidth=2;
    vals.forEach((p,i)=>{const x=(i/(vals.length-1))*W;i===0?ctx.moveTo(x,nr(p)):ctx.lineTo(x,nr(p));}); ctx.stroke();
  }
}

let _tvBtDDChart = null;
function renderDrawdownChart(drawdownSeries) {
  const container = document.getElementById('bt-drawdown-chart');
  if (!container) return;
  if (container.offsetWidth === 0) { setTimeout(()=>renderDrawdownChart(drawdownSeries),220); return; }
  if (_tvBtDDChart) { try { _tvBtDDChart.remove(); } catch(_){} _tvBtDDChart=null; }
  container.innerHTML = '';
  if (typeof LightweightCharts !== 'undefined') {
    _tvBtDDChart = LightweightCharts.createChart(container, {
      width:container.offsetWidth||600, height:90,
      layout:{background:{color:'transparent'},textColor:'#5a5a5a',fontFamily:"'DM Mono',monospace",fontSize:9},
      grid:{vertLines:{visible:false},horzLines:{color:'rgba(255,255,255,0.025)'}},
      crosshair:{mode:1},
      timeScale:{borderColor:'rgba(255,255,255,0.06)',fixLeftEdge:true,fixRightEdge:true,visible:false},
      rightPriceScale:{borderColor:'rgba(255,255,255,0.06)',scaleMargins:{top:0.05,bottom:0}},
      handleScale:{mouseWheel:false},handleScroll:{mouseWheel:false},
    });
    const ddS = _tvBtDDChart.addAreaSeries({
      lineColor:'#F87171',topColor:'rgba(248,113,113,0.35)',bottomColor:'rgba(248,113,113,0.0)',
      lineWidth:1,priceFormat:{type:'custom',formatter:v=>v.toFixed(1)+'%',minMove:0.01},
      priceLineVisible:false,lastValueVisible:false,
    });
    ddS.setData(drawdownSeries);
    _tvBtDDChart.timeScale().fitContent();
    new ResizeObserver(es=>{if(_tvBtDDChart)_tvBtDDChart.applyOptions({width:es[0].contentRect.width});}).observe(container);
  } else {
    const canvas=document.createElement('canvas'); container.appendChild(canvas);
    const ctx=canvas.getContext('2d'), W=container.offsetWidth||600, H=90;
    canvas.width=W; canvas.height=H; canvas.style.cssText='width:100%;height:'+H+'px;';
    const vals=drawdownSeries.map(d=>d.value);
    const mn=Math.min(...vals)*1.05;
    const nr=v=>H-((v-mn)/(0-mn||1))*H*0.85-H*0.05;
    ctx.fillStyle='rgba(248,113,113,0.18)'; ctx.beginPath();
    vals.forEach((p,i)=>{const x=(i/(vals.length-1))*W;i===0?ctx.moveTo(x,nr(p)):ctx.lineTo(x,nr(p));});
    ctx.lineTo(W,H); ctx.lineTo(0,H); ctx.closePath(); ctx.fill();
    ctx.beginPath(); ctx.strokeStyle='#F87171'; ctx.lineWidth=1;
    vals.forEach((p,i)=>{const x=(i/(vals.length-1))*W;i===0?ctx.moveTo(x,nr(p)):ctx.lineTo(x,nr(p));}); ctx.stroke();
  }
}

function renderMonthlyHeatmap(equityCurve, periodYears) {
  const container = document.getElementById('bt-monthly-heatmap');
  if (!container || !equityCurve.length) return;
  const monthMap = {};
  for (let i = 1; i < equityCurve.length; i++) {
    const ym = equityCurve[i].time.slice(0,7);
    if (!monthMap[ym]) monthMap[ym] = { start: equityCurve[i-1].value, end: equityCurve[i].value };
    else monthMap[ym].end = equityCurve[i].value;
  }
  const months = Object.keys(monthMap).sort();
  const years = [...new Set(months.map(m=>m.slice(0,4)))].sort();
  const MN = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  let html = `<div class="qzbt-hm-grid" style="grid-template-columns:34px repeat(12,1fr);">`;
  html += `<div></div>` + MN.map(m=>`<div style="font-size:7px;color:var(--text-muted);text-align:center;padding:2px 0;">${m}</div>`).join('');
  years.forEach(yr => {
    html += `<div style="font-size:8px;color:var(--text-muted);font-family:var(--font-mono);padding:2px;display:flex;align-items:center;justify-content:flex-end;padding-right:4px;">${yr}</div>`;
    for (let mo = 1; mo <= 12; mo++) {
      const key = `${yr}-${String(mo).padStart(2,'0')}`;
      const mr = monthMap[key];
      if (mr && mr.start > 0) {
        const ret = (mr.end - mr.start) / mr.start;
        const pct = (ret*100).toFixed(1);
        const intensity = Math.min(Math.abs(ret)*100, 15);
        const alpha = 0.15 + (intensity/15)*0.72;
        const bg = ret>=0 ? `rgba(52,211,153,${alpha.toFixed(2)})` : `rgba(248,113,113,${alpha.toFixed(2)})`;
        const col = intensity>5 ? '#fff' : (ret>=0?'#34D399':'#F87171');
        html += `<div class="qzbt-hm-cell" style="background:${bg};color:${col};" title="${key}: ${pct}%">${pct}%</div>`;
      } else {
        html += `<div class="qzbt-hm-cell" style="background:var(--surface3);color:var(--text-muted);">—</div>`;
      }
    }
  });
  html += '</div>';
  container.innerHTML = html;
}

function renderTradeLog(trades) {
  const tbody = document.getElementById('bt-trade-log-body');
  if (!tbody) return;
  const shown = trades.slice(-50).reverse();
  if (!shown.length) {
    tbody.innerHTML = `<tr><td colspan="7" style="text-align:center;color:var(--text-muted);padding:16px;font-family:var(--font-mono);font-size:10px;">No trades executed — try a more active strategy or shorter lookback.</td></tr>`;
    return;
  }
  tbody.innerHTML = shown.map((t, i) => {
    const retStr = (t.ret>=0?'+':'')+(t.ret*100).toFixed(2)+'%';
    const pnlStr = (t.pnl>=0?'+':'')+t.pnl.toFixed(0);
    const col = t.ret>=0?'#34D399':'#F87171';
    return `<tr><td style="color:var(--text-muted);">${i+1}</td><td>${t.entry}</td><td>${t.exit}</td><td style="font-family:var(--font-mono);">$${t.entryP.toFixed(2)}</td><td style="font-family:var(--font-mono);">$${t.exitP.toFixed(2)}</td><td style="color:${col};font-weight:600;">${retStr}</td><td style="color:${col};">${pnlStr}</td></tr>`;
  }).join('');
}

// ==================== ALERTS ====================
function _buildLiveAlerts() {
  // Generate signal alerts from STOCKS data dynamically
  const now = Date.now();
  const liveAlerts = STOCKS
    .filter(s => s.signal === 'BUY' && s.conf >= 80)
    .sort((a,b) => b.conf - a.conf)
    .slice(0, 3)
    .map((s, i) => ({
      icon:'📡',
      title:`${s.signal} Signal: ${s.ticker}`,
      sub:`Confidence ${s.conf}% — ${s.reason.split('.')[0]}.`,
      time: i === 0 ? 'Just now' : i === 1 ? '3m ago' : '8m ago',
      type:'signals'
    }));
  const sellAlerts = STOCKS
    .filter(s => s.signal === 'SELL')
    .map((s, i) => ({
      icon:'📡',
      title:`SELL Signal: ${s.ticker}`,
      sub:`Confidence ${s.conf}% — ${s.reason.split('.')[0]}.`,
      time: (i+1)*15 + 'm ago',
      type:'signals'
    }));
  return [...liveAlerts, ...ALERTS_DATA.filter(a => a.type === 'news'), ...sellAlerts];
}

function renderAlerts(filter='all') {
  const list = document.getElementById('alerts-list');
  if (!list) return;
  const all = _buildLiveAlerts();
  const filtered = filter === 'all' ? all : all.filter(a => a.type === filter);
  if (!filtered.length) {
    list.innerHTML = `<div style="text-align:center;padding:48px;color:var(--text-muted);">No alerts</div>`;
    return;
  }
  list.innerHTML = filtered.map(a => `
    <div class="alert-item">
      <div class="alert-icon">${a.icon}</div>
      <div style="flex:1;"><div class="alert-title">${a.title}</div><div class="alert-sub">${a.sub}</div></div>
      <div class="alert-time">${a.time}</div>
    </div>`).join('');
}
function switchAlertTab(type, btn) {
  // Only deactivate tabs within the alerts page tab bar
  const alertsPage = document.getElementById('page-alerts');
  if (alertsPage) alertsPage.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  btn.classList.add('active');
  renderAlerts(type);
}
function clearAlerts() {
  document.getElementById('alerts-list').innerHTML = `<div style="text-align:center;padding:48px;color:var(--text-muted);">No alerts</div>`;
}

// ==================== SUBSCRIPTION ====================
function subscribe() {
  state.subscribed = true;
  document.getElementById('subscription-gate').classList.add('hidden');
}
function redeemCode() {
  const code = document.getElementById('redeem-input').value.trim();
  const msg = document.getElementById('redeem-msg');
  if(code === REDEEM_CODE) {
    msg.style.color = 'var(--green)';
    msg.textContent = '✓ Code accepted! Access granted.';
    setTimeout(subscribe, 1000);
  } else {
    msg.style.color = 'var(--red)';
    msg.textContent = '✕ Invalid code. Try again.';
  }
}

// ==================== GLOBAL SEARCH (UNIVERSE + LIVE WEB FALLBACK) ====================
const _searchState = { items: [], selected: -1, lastQuery: '', webResults: [], webBusy: false, webDebounceId: null, webCache: new Map() };

// CORS proxy chain — tried in order. The wrapped variants extract `contents` from JSON envelopes.
const _SEARCH_PROXIES = [
  { url: s => `https://corsproxy.io/?url=${encodeURIComponent(s)}`,                   parse: 'direct' },
  { url: s => `https://api.allorigins.win/get?url=${encodeURIComponent(s)}`,           parse: 'allorigins' },
  { url: s => `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(s)}`,      parse: 'direct' },
  { url: s => `https://thingproxy.freeboard.io/fetch/${s}`,                            parse: 'direct' },
  { url: s => `https://cors.eu.org/${s}`,                                              parse: 'direct' },
];
async function _searchProxiedFetch(url, expectJson = true) {
  for (const p of _SEARCH_PROXIES) {
    try {
      const r = await fetch(p.url(url), { method:'GET', cache:'no-store', mode:'cors' });
      if (!r.ok) continue;
      if (p.parse === 'allorigins') {
        const env = await r.json();
        if (!env || !env.contents) continue;
        if (expectJson) {
          try { return JSON.parse(env.contents); } catch (_) { continue; }
        }
        return env.contents;
      } else {
        if (expectJson) {
          const txt = await r.text();
          try { return JSON.parse(txt); } catch (_) {
            // Some proxies double-wrap or html-escape — try to extract json
            const m = txt.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
            if (m) { try { return JSON.parse(m[0]); } catch(_) {} }
            continue;
          }
        }
        return await r.text();
      }
    } catch (_) { /* try next proxy */ }
  }
  return null;
}

// Symbol search — tries Yahoo v1/finance/search, falls back to local UNIVERSE prefix matching
async function _searchWebQuery(q) {
  if (!q || q.length < 2) return [];
  if (_searchState.webCache.has(q)) return _searchState.webCache.get(q);
  // Primary: Yahoo autocomplete
  const url = `https://query1.finance.yahoo.com/v1/finance/search?q=${encodeURIComponent(q)}&quotesCount=10&newsCount=0&enableFuzzyQuery=false`;
  let data = await _searchProxiedFetch(url);
  let quotes = (data && data.quotes) || [];
  let filtered = quotes.filter(it => it && it.symbol && !['OPTION','FUTURE'].includes(it.quoteType))
    .map(it => ({
      symbol: it.symbol,
      name: it.shortname || it.longname || it.symbol,
      exchange: it.exchDisp || it.exchange || '',
      type: it.quoteType || it.typeDisp || 'EQUITY',
      sector: it.sectorDisp || '',
      industry: it.industryDisp || '',
    }));
  // Fallback: local universe prefix/name match if web returns nothing
  if (filtered.length === 0 && typeof UNIVERSE !== 'undefined') {
    const ql = q.toLowerCase();
    filtered = UNIVERSE.filter(s => s.t.toLowerCase().startsWith(ql) || s.n.toLowerCase().includes(ql))
      .slice(0, 8)
      .map(s => ({ symbol: s.t, name: s.n, exchange: s.ex, type: 'EQUITY', sector: s.sec, industry: s.ind }));
  }
  _searchState.webCache.set(q, filtered);
  return filtered;
}

// Quote fetch — multi-source. Yahoo v8 chart > Yahoo v7 quote > Stooq CSV.
// v8 chart is far more CORS-permissive than v7 quote.
async function _searchWebQuote(symbol) {
  // 1) Yahoo v8 chart endpoint (returns price + meta, no crumb required)
  const v8 = await _searchProxiedFetch(`https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=1d&range=5d`);
  if (v8 && v8.chart && v8.chart.result && v8.chart.result[0]) {
    const r = v8.chart.result[0];
    const m = r.meta || {};
    const px = m.regularMarketPrice || (r.indicators?.quote?.[0]?.close?.slice(-1)[0]);
    const prev = m.chartPreviousClose || m.previousClose;
    const change = (prev && px) ? ((px - prev) / prev) * 100 : 0;
    return {
      symbol: m.symbol || symbol,
      shortName: m.symbol,
      longName: m.symbol,
      regularMarketPrice: px,
      regularMarketChange: px - (prev || px),
      regularMarketChangePercent: change,
      regularMarketPreviousClose: prev,
      regularMarketOpen: r.indicators?.quote?.[0]?.open?.slice(-1)[0],
      regularMarketDayHigh: m.regularMarketDayHigh || Math.max(...(r.indicators?.quote?.[0]?.high || [px])),
      regularMarketDayLow: m.regularMarketDayLow || Math.min(...(r.indicators?.quote?.[0]?.low || [px])),
      regularMarketVolume: m.regularMarketVolume,
      averageDailyVolume3Month: m.averageDailyVolume3Month,
      fiftyTwoWeekHigh: m.fiftyTwoWeekHigh,
      fiftyTwoWeekLow: m.fiftyTwoWeekLow,
      currency: m.currency,
      fullExchangeName: m.exchangeName,
      exchange: m.exchangeName,
      quoteType: m.instrumentType,
      regularMarketTime: m.regularMarketTime,
      _source: 'yahoo-v8'
    };
  }
  // 2) Yahoo v7 quote (richer fundamentals, sometimes blocked)
  const v7 = await _searchProxiedFetch(`https://query1.finance.yahoo.com/v7/finance/quote?symbols=${encodeURIComponent(symbol)}`);
  const q7 = v7 && v7.quoteResponse && v7.quoteResponse.result && v7.quoteResponse.result[0];
  if (q7) { q7._source = 'yahoo-v7'; return q7; }
  // 3) Stooq CSV fallback (works for US/UK/DE/NL stocks; symbol mapping required)
  const stooqSym = _toStooqSymbol(symbol);
  if (stooqSym) {
    const csv = await _searchProxiedFetch(`https://stooq.com/q/l/?s=${stooqSym}&f=sd2t2ohlcv&h&e=csv`, false);
    if (csv && typeof csv === 'string') {
      const lines = csv.trim().split('\n');
      if (lines.length >= 2) {
        const cols = lines[1].split(',');
        const [sym, date, time, open, high, low, close, volume] = cols;
        const px = parseFloat(close), o = parseFloat(open);
        if (!isNaN(px) && px > 0) {
          return {
            symbol, shortName: symbol, longName: symbol,
            regularMarketPrice: px, regularMarketOpen: o,
            regularMarketDayHigh: parseFloat(high), regularMarketDayLow: parseFloat(low),
            regularMarketVolume: parseInt(volume) || 0,
            regularMarketChange: o ? px - o : 0,
            regularMarketChangePercent: o ? ((px - o) / o) * 100 : 0,
            currency: 'USD', exchange: 'Stooq', fullExchangeName: 'Stooq Aggregate',
            regularMarketTime: Math.floor(Date.now()/1000),
            _source: 'stooq'
          };
        }
      }
    }
  }
  return null;
}
function _toStooqSymbol(t) {
  // Stooq symbol format: us tickers are lowercase + .us, e.g. aapl.us
  if (!t || /\W/.test(t.replace(/[.\-]/g, ''))) {
    if (/\.L$/i.test(t))    return t.replace(/\.L$/i, '').toLowerCase() + '.uk';
    if (/\.DE$/i.test(t))   return t.replace(/\.DE$/i, '').toLowerCase() + '.de';
    if (/\.PA$/i.test(t))   return t.replace(/\.PA$/i, '').toLowerCase() + '.fr';
    if (/\.AS$/i.test(t))   return t.replace(/\.AS$/i, '').toLowerCase() + '.nl';
    if (/\.HK$/i.test(t))   return t.replace(/\.HK$/i, '').toLowerCase() + '.hk';
    if (/\.T$/i.test(t))    return t.replace(/\.T$/i, '').toLowerCase() + '.jp';
    if (/\.AX$/i.test(t))   return t.replace(/\.AX$/i, '').toLowerCase() + '.au';
  }
  // Default: assume US
  if (/^[A-Z][A-Z.]*$/.test(t)) return t.toLowerCase() + '.us';
  return null;
}

function globalSearchFocus() {
  const v = document.getElementById('global-search').value;
  if (!v) globalSearch(''); // show empty-state hint
}

function globalSearch(q) {
  q = (q || '').trim();
  _searchState.lastQuery = q;
  const dd = document.getElementById('search-results-dropdown');
  if (!dd) return;
  // Schedule debounced web fetch (only if query has substance)
  if (_searchState.webDebounceId) clearTimeout(_searchState.webDebounceId);
  _searchState.webResults = [];
  if (q.length >= 2) {
    _searchState.webDebounceId = setTimeout(async () => {
      if (q !== _searchState.lastQuery) return; // user moved on
      _searchState.webBusy = true;
      _searchRender();   // show "Searching the web…" indicator
      try {
        const results = await _searchWebQuery(q);
        if (q !== _searchState.lastQuery) return; // race-guard
        // Filter out any tickers already covered by local universe to avoid dupes
        const localSet = new Set((typeof UNIVERSE !== 'undefined' ? UNIVERSE : []).slice(0, 2000).map(s => s.t.toUpperCase()));
        _searchState.webResults = results.filter(r => !localSet.has(r.symbol.toUpperCase())).slice(0, 6);
      } catch (_) {
        _searchState.webResults = [];
      } finally {
        _searchState.webBusy = false;
        if (q === _searchState.lastQuery) _searchRender();
      }
    }, 100);
  }
  _searchRender();
}

// Splitting render so it can rerun when web results arrive
function _searchRender() {
  const q = _searchState.lastQuery;
  const dd = document.getElementById('search-results-dropdown');
  if (!dd) return;
  if (!q) {
    // Empty state: show top 5 universe by mcap + quick actions
    const top = (typeof UNIVERSE !== 'undefined' ? UNIVERSE.slice(0, 5) : []);
    _searchState.items = top.map(s => ({type:'stock', s}));
    _searchState.selected = -1;
    dd.innerHTML = `
      <div class="search-empty-hint">Search across <b>100,000,000+ securities</b> · 100+ countries · news · sectors. Press <code>/</code> to focus, <kbd>↑↓</kbd> to navigate, <kbd>↵</kbd> to open.</div>
      <div class="search-results-section">
        <div class="search-results-label"><span>TOP UNIVERSE — BY MARKET CAP</span></div>
        ${top.map((s,i) => _searchStockRow(s, i)).join('')}
      </div>
      <div class="search-results-section">
        ${_searchActionRow('🌍', 'Browse the full Universe', "showPage('universe', document.querySelector(\"[onclick*='universe']\"))", 'G U')}
        ${_searchActionRow('📡', 'View AI Signals', "showPage('signals', document.querySelector(\"[onclick*='signals']\"))", 'G S')}
        ${_searchActionRow('📰', 'NewsJudge feed', "showPage('news', document.querySelector(\"[onclick*='news']\"))", 'G N')}
      </div>`;
    dd.classList.remove('hidden');
    return;
  }

  const ql = q.toLowerCase();

  // 1) UNIVERSE matches — split into ticker (exact/prefix) and name (substring)
  const universeArr = (typeof UNIVERSE !== 'undefined' ? UNIVERSE : []);
  const tickerExact = [];
  const tickerPrefix = [];
  const nameMatches = [];
  const isinMatches = [];
  const sectorMatches = [];
  const countryMatches = [];
  for (let i = 0; i < universeArr.length && (tickerExact.length + tickerPrefix.length + nameMatches.length) < 200; i++) {
    const s = universeArr[i];
    const tl = s.t.toLowerCase();
    if (tl === ql) tickerExact.push(s);
    else if (tl.startsWith(ql)) tickerPrefix.push(s);
    else if (s.n.toLowerCase().includes(ql)) nameMatches.push(s);
    else if (s.isin && s.isin.toLowerCase().includes(ql)) isinMatches.push(s);
    else if (s.sec && s.sec.toLowerCase().includes(ql)) sectorMatches.push(s);
    else if (s.cn && s.cn.toLowerCase().includes(ql)) countryMatches.push(s);
  }
  // Concat in priority order, dedupe by ticker
  const seen = new Set();
  let stockHits = [];
  [tickerExact, tickerPrefix, nameMatches, isinMatches, sectorMatches, countryMatches].forEach(arr => {
    arr.forEach(s => { if (!seen.has(s.t)) { seen.add(s.t); stockHits.push(s); } });
  });
  // Boost results from the user's selected country to the top within each match-tier
  if (typeof _searchPreferredCountry !== 'undefined' && _searchPreferredCountry) {
    const preferred = stockHits.filter(s => s.co === _searchPreferredCountry);
    const others = stockHits.filter(s => s.co !== _searchPreferredCountry);
    stockHits = [...preferred, ...others];
  }
  const stockTop = stockHits.slice(0, 8);

  // 2) NEWS matches
  const newsArr = (typeof NEWS !== 'undefined' ? NEWS : []);
  const newsHits = newsArr.filter(n =>
    (n.title && n.title.toLowerCase().includes(ql)) ||
    (n.excerpt && n.excerpt.toLowerCase().includes(ql)) ||
    (n.source && n.source.toLowerCase().includes(ql))
  ).slice(0, 3);

  // 3) Sector / country / region quick-filter actions
  const SECTORS = ['Technology','Financials','Healthcare','Consumer Discretionary','Consumer Staples','Industrials','Energy','Materials','Communication Services','Utilities','Real Estate'];
  const sectorActions = SECTORS.filter(s => s.toLowerCase().includes(ql)).slice(0, 2);
  const countryHits = (typeof UNIVERSE_COUNTRIES !== 'undefined') ? Object.entries(UNIVERSE_COUNTRIES)
    .filter(([co, m]) => m.n.toLowerCase().includes(ql) || co.toLowerCase() === ql)
    .slice(0, 3) : [];

  // Build flat item list for keyboard nav (web results appended)
  _searchState.items = [
    ...stockTop.map(s => ({type:'stock', s})),
    ...newsHits.map(n => ({type:'news', n})),
    ...sectorActions.map(sec => ({type:'sector', sec})),
    ...countryHits.map(([co, m]) => ({type:'country', co, m})),
    ..._searchState.webResults.map(w => ({type:'web', w})),
  ];
  if (_searchState.selected < 0 || _searchState.selected >= _searchState.items.length) {
    _searchState.selected = _searchState.items.length ? 0 : -1;
  }

  if (_searchState.items.length === 0 && !_searchState.webBusy) {
    dd.innerHTML = `<div class="search-no-results">No local matches for "<b>${_escapeHtml(q)}</b>".<br><span style="font-size:11px;">Searching the web…</span></div>`;
    dd.classList.remove('hidden');
    return;
  }

  let html = '';
  if (stockTop.length) {
    html += `<div class="search-results-section">
      <div class="search-results-label"><span>EQUITIES — UNIVERSE</span><span class="search-results-label-count">${stockHits.length.toLocaleString()} match${stockHits.length===1?'':'es'}</span></div>
      ${stockTop.map((s, i) => _searchStockRow(s, i)).join('')}
    </div>`;
  }
  if (newsHits.length) {
    const offset = stockTop.length;
    html += `<div class="search-results-section">
      <div class="search-results-label"><span>NEWSJUDGE</span><span class="search-results-label-count">${newsHits.length}</span></div>
      ${newsHits.map((n, i) => _searchNewsRow(n, offset + i)).join('')}
    </div>`;
  }
  if (sectorActions.length || countryHits.length) {
    const offset = stockTop.length + newsHits.length;
    html += `<div class="search-results-section">
      <div class="search-results-label"><span>QUICK FILTERS</span></div>
      ${sectorActions.map((sec, i) => `<div class="search-result-action ${(_searchState.selected === offset+i)?'active':''}" data-idx="${offset+i}" onclick="globalSearchPick(${offset+i})">📊 Filter Universe by sector → <b style="color:var(--text-primary);">${sec}</b><span class="action-key">↵</span></div>`).join('')}
      ${countryHits.map((c, i) => {
        const idx = offset + sectorActions.length + i;
        const flag = (typeof UNIVERSE_FLAGS !== 'undefined') ? (UNIVERSE_FLAGS[c[0]] || '🏳️') : '';
        return `<div class="search-result-action ${(_searchState.selected === idx)?'active':''}" data-idx="${idx}" onclick="globalSearchPick(${idx})">${flag} Filter Universe by country → <b style="color:var(--text-primary);">${c[1].n}</b><span class="action-key">↵</span></div>`;
      }).join('')}
    </div>`;
  }
  // === WEB RESULTS (Yahoo Finance live lookup) ===
  const webOffset = stockTop.length + newsHits.length + sectorActions.length + countryHits.length;
  if (_searchState.webBusy && _searchState.webResults.length === 0) {
    html += `<div class="search-results-section">
      <div class="search-results-label"><span>WEB — YAHOO FINANCE</span><span class="search-results-label-count">searching…</span></div>
      <div style="padding:14px;display:flex;align-items:center;gap:10px;color:var(--text-muted);font-size:12px;">
        <div style="width:14px;height:14px;border:2px solid var(--border);border-top-color:var(--green);border-radius:50%;animation:spin 0.8s linear infinite;"></div>
        Looking up "<b>${_escapeHtml(q)}</b>" across global exchanges…
      </div>
    </div>`;
  } else if (_searchState.webResults.length) {
    html += `<div class="search-results-section">
      <div class="search-results-label"><span>WEB — YAHOO FINANCE</span><span class="search-results-label-count">${_searchState.webResults.length} live</span></div>
      ${_searchState.webResults.map((w, i) => _searchWebRow(w, webOffset + i)).join('')}
    </div>`;
  }
  dd.innerHTML = html;
  dd.classList.remove('hidden');
}

function _searchWebRow(w, idx) {
  const typeBadge = w.type ? `<span style="font-family:var(--font-mono);font-size:9px;padding:1px 5px;background:rgba(30,144,255,0.15);color:var(--blue);border-radius:3px;margin-left:6px;">${w.type}</span>` : '';
  return `<div class="search-result-item ${(_searchState.selected === idx)?'active':''}" data-idx="${idx}" onclick="globalSearchPick(${idx})" style="grid-template-columns:54px 1fr auto;">
    <span class="search-result-ticker">${w.symbol}</span>
    <span class="search-result-name" title="${_escapeHtml(w.name)}">${_escapeHtml(w.name)}${typeBadge}</span>
    <span class="search-result-meta">🌐 ${w.exchange || 'Web'}</span>
  </div>`;
}

function _searchStockRow(s, idx) {
  const flag = (typeof UNIVERSE_FLAGS !== 'undefined') ? (UNIVERSE_FLAGS[s.co] || '🏳️') : '';
  const mc = s.mc >= 1000 ? `$${(s.mc/1000).toFixed(2)}T` : s.mc >= 1 ? `$${s.mc.toFixed(1)}B` : `$${(s.mc*1000).toFixed(0)}M`;
  return `<div class="search-result-item ${(_searchState.selected === idx)?'active':''}" data-idx="${idx}" onclick="globalSearchPick(${idx})">
    <span class="search-result-ticker">${s.t}</span>
    <span class="search-result-name" title="${_escapeHtml(s.n)}">${_escapeHtml(s.n)}</span>
    <span class="search-result-meta"><span class="search-result-flag">${flag}</span> ${s.cn}</span>
    <span class="search-result-mcap">${mc}</span>
  </div>`;
}
function _searchNewsRow(n, idx) {
  return `<div class="search-result-news ${(_searchState.selected === idx)?'active':''}" data-idx="${idx}" onclick="globalSearchPick(${idx})">
    <div class="search-result-news-title">${_escapeHtml(n.title)}</div>
    <div class="search-result-news-meta">${n.source || ''} · ${n.time || ''}</div>
  </div>`;
}
function _searchActionRow(icon, label, onclick, key) {
  return `<div class="search-result-action" onclick="${onclick}; globalSearchClose();">${icon}  ${label}<span class="action-key">${key}</span></div>`;
}
function _escapeHtml(s) { return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }

function globalSearchKey(e) {
  const dd = document.getElementById('search-results-dropdown');
  if (e.key === 'Escape') { globalSearchClose(); e.target.blur(); return; }
  if (dd.classList.contains('hidden')) return;
  if (e.key === 'ArrowDown') {
    e.preventDefault();
    if (!_searchState.items.length) return;
    _searchState.selected = (_searchState.selected + 1) % _searchState.items.length;
    _searchUpdateHighlight();
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    if (!_searchState.items.length) return;
    _searchState.selected = (_searchState.selected - 1 + _searchState.items.length) % _searchState.items.length;
    _searchUpdateHighlight();
  } else if (e.key === 'Enter') {
    e.preventDefault();
    if (_searchState.selected >= 0) globalSearchPick(_searchState.selected);
  }
}
function _searchUpdateHighlight() {
  const dd = document.getElementById('search-results-dropdown');
  dd.querySelectorAll('[data-idx]').forEach(el => {
    const idx = parseInt(el.dataset.idx);
    el.classList.toggle('active', idx === _searchState.selected);
    if (idx === _searchState.selected) {
      const r = el.getBoundingClientRect();
      const dr = dd.getBoundingClientRect();
      if (r.top < dr.top || r.bottom > dr.bottom) el.scrollIntoView({block:'nearest'});
    }
  });
}
function globalSearchPick(idx) {
  const item = _searchState.items[idx];
  if (!item) return;
  if (item.type === 'stock') _searchOpenStock(item.s);
  else if (item.type === 'news') _searchOpenNews(item.n);
  else if (item.type === 'sector') _searchOpenSector(item.sec);
  else if (item.type === 'country') _searchOpenCountry(item.co, item.m);
  else if (item.type === 'web') _searchOpenWeb(item.w);
}

// Open a Yahoo-discovered ticker: fetch full quote + display rich detail modal
async function _searchOpenWeb(w) {
  globalSearchClose();
  _showStockDetailModal({ loading: true, symbol: w.symbol, name: w.name, exchange: w.exchange, type: w.type });
  let q = null;
  try { q = await _searchWebQuote(w.symbol); } catch (_) {}
  if (!q) {
    // Last-ditch: check if local universe has it
    const localHit = (typeof UNIVERSE !== 'undefined') ? (_uvTickerMap.size > 0 ? _uvTickerMap.get(w.symbol) : UNIVERSE.find(s => s.t === w.symbol)) : null;
    if (localHit) { _showStockDetailModalFromLocal(localHit); return; }
    _showStockDetailModal({ error: true, symbol: w.symbol, name: w.name });
    return;
  }
  // If we got a quote and it's also in the local universe, merge richer fields
  if (typeof UNIVERSE !== 'undefined') {
    const localHit = (_uvTickerMap.size > 0 ? _uvTickerMap.get(w.symbol) : UNIVERSE.find(s => s.t === w.symbol));
    if (localHit) {
      q.longName = q.longName || localHit.n;
      if (!q.marketCap && localHit.mc) q.marketCap = localHit.mc * 1e9;
      if (!q.beta && localHit.beta) q.beta = localHit.beta;
      if (!q.trailingPE && localHit.pe) q.trailingPE = localHit.pe;
      if (!q.trailingAnnualDividendYield && localHit.dy) q.trailingAnnualDividendYield = localHit.dy / 100;
    }
  }
  _showStockDetailModal({ q, hint: w });
}

// Lightweight in-app modal for live web stock details (no extra HTML required — rendered on the fly)
function _showStockDetailModal(opts) {
  let modal = document.getElementById('stock-detail-modal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'stock-detail-modal';
    modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.78);z-index:9000;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(8px);animation:fadeInUp 220ms var(--ease-out-strong);';
    modal.onclick = (e) => { if (e.target === modal) modal.remove(); };
    document.body.appendChild(modal);
  }
  const fmtN = (n, dp=2) => (n==null||isNaN(n))?'—':Number(n).toLocaleString('en-US',{minimumFractionDigits:dp, maximumFractionDigits:dp});
  const fmtBn = (n) => { if(n==null||isNaN(n))return'—'; const v=Math.abs(n); if(v>=1e12)return '$'+(n/1e12).toFixed(2)+'T'; if(v>=1e9)return '$'+(n/1e9).toFixed(2)+'B'; if(v>=1e6)return '$'+(n/1e6).toFixed(1)+'M'; return '$'+fmtN(n,0); };
  if (opts.loading) {
    modal.innerHTML = `<div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius-lg);padding:32px 36px;min-width:380px;max-width:560px;text-align:center;">
      <div style="width:36px;height:36px;border:3px solid var(--border);border-top-color:var(--green);border-radius:50%;animation:spin 0.8s linear infinite;margin:0 auto 16px;"></div>
      <div style="font-family:var(--font-display);font-size:16px;font-weight:700;margin-bottom:6px;">${_escapeHtml(opts.name)}</div>
      <div style="font-family:var(--font-mono);font-size:12px;color:var(--text-muted);">${opts.symbol} · ${opts.exchange||''}</div>
      <div style="font-size:12px;color:var(--text-muted);margin-top:14px;">Fetching live data from Yahoo Finance…</div>
    </div>`;
    return;
  }
  if (opts.error) {
    modal.innerHTML = `<div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius-lg);padding:28px;min-width:380px;text-align:center;">
      <div style="font-size:32px;margin-bottom:10px;">⚠️</div>
      <div style="font-family:var(--font-display);font-weight:700;margin-bottom:6px;">Lookup Failed</div>
      <div style="font-size:13px;color:var(--text-muted);margin-bottom:18px;">Couldn't fetch live data for <b>${opts.symbol}</b>. CORS proxies may be rate-limited — try again in a moment.</div>
      <button class="btn btn-secondary btn-sm" onclick="document.getElementById('stock-detail-modal').remove()">Close</button>
    </div>`;
    return;
  }
  const q = opts.q;
  const isLive = q._source && q._source !== 'local-universe';
  const isLocal = q._source === 'local-universe' || (!q.regularMarketPrice && opts.localStock);
  const chg = q.regularMarketChangePercent || 0;
  const chgSign = chg >= 0 ? '▲' : '▼';
  const chgColor = chg >= 0 ? 'var(--green)' : 'var(--red)';
  const sector = (opts.hint && opts.hint.sector) || (opts.localStock && opts.localStock.sec) || '—';
  const industry = (opts.hint && opts.hint.industry) || (opts.localStock && opts.localStock.ind) || '—';
  const livePillHTML = isLive
    ? `<div class="live-pill"><div class="live-dot"></div>LIVE · ${q._source.toUpperCase()}</div>`
    : `<div class="live-pill" style="background:rgba(255,211,42,0.14);border-color:rgba(255,211,42,0.25);color:var(--yellow);"><div class="live-dot" style="background:var(--yellow);box-shadow:0 0 8px rgba(255,211,42,0.6);"></div>LOCAL CACHE</div>`;
  const priceDisplay = q.regularMarketPrice && q.regularMarketPrice > 0 ? fmtN(q.regularMarketPrice, 2) : '—';
  const localStockBlock = opts.localStock ? `
    <div style="padding:0 28px 24px;">
      <div style="font-family:var(--font-mono);font-size:10px;color:var(--text-muted);letter-spacing:0.08em;margin-bottom:10px;">QUANT ENTELLOQ FACTOR SCORES (LOCAL UNIVERSE)</div>
      <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:12px;">
        ${_statCard('Tier', 'T'+opts.localStock.tier)}
        ${_statCard('Momentum', opts.localStock.mom + '/100')}
        ${_statCard('Quality', opts.localStock.qua + '/100')}
        ${_statCard('30d Vol', opts.localStock.vol30 + '%')}
        ${_statCard('Free Float', opts.localStock.ff + '%')}
        ${_statCard('Rev Growth', (opts.localStock.rg>0?'+':'') + opts.localStock.rg + '%')}
        ${_statCard('EPS Growth', (opts.localStock.eg>0?'+':'') + opts.localStock.eg + '%')}
        ${_statCard('Global Rank', '#' + opts.localStock.gr.toLocaleString())}
      </div>
    </div>` : '';
  modal.innerHTML = `<div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius-lg);padding:0;min-width:520px;max-width:680px;max-height:90vh;overflow-y:auto;">
    <div style="padding:24px 28px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:flex-start;gap:16px;">
      <div>
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:6px;flex-wrap:wrap;">
          <div style="font-family:var(--font-display);font-size:22px;font-weight:800;letter-spacing:-0.01em;">${_escapeHtml(q.longName || q.shortName || q.symbol)}</div>
          ${livePillHTML}
        </div>
        <div style="font-family:var(--font-mono);font-size:12px;color:var(--text-muted);">
          <b style="color:var(--text-primary);">${_escapeHtml(q.symbol)}</b> · ${_escapeHtml(q.fullExchangeName || q.exchange || '')} · ${_escapeHtml(q.currency || 'USD')} · ${_escapeHtml(q.quoteType || 'EQUITY')}
        </div>
      </div>
      <button onclick="document.getElementById('stock-detail-modal').remove()" style="background:transparent;border:none;color:var(--text-muted);font-size:22px;cursor:pointer;padding:0 4px;">×</button>
    </div>
    <div style="padding:24px 28px;display:grid;grid-template-columns:1fr 1fr;gap:24px;">
      <div>
        <div style="font-family:var(--font-mono);font-size:10px;color:var(--text-muted);letter-spacing:0.08em;margin-bottom:6px;">${isLive ? 'LIVE PRICE' : 'PRICE (UNAVAILABLE)'}</div>
        <div style="font-family:var(--font-display);font-size:36px;font-weight:800;line-height:1;${isLocal?'color:var(--text-muted);':''}">${priceDisplay}</div>
        ${isLive ? `<div style="margin-top:6px;font-family:var(--font-mono);font-size:14px;color:${chgColor};">
          ${chgSign} ${fmtN(q.regularMarketChange||0, 2)} (${fmtN(chg, 2)}%)
        </div>` : `<div style="margin-top:6px;font-size:12px;color:var(--text-muted);font-style:italic;">CORS proxies offline — showing cached fundamentals</div>`}
        <div style="font-size:11px;color:var(--text-muted);margin-top:4px;">${q.regularMarketTime ? new Date(q.regularMarketTime*1000).toLocaleString() : ''}</div>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px 16px;font-size:12px;">
        ${_kvRow('Day Range', `${fmtN(q.regularMarketDayLow,2)} – ${fmtN(q.regularMarketDayHigh,2)}`)}
        ${_kvRow('52w Range', `${fmtN(q.fiftyTwoWeekLow,2)} – ${fmtN(q.fiftyTwoWeekHigh,2)}`)}
        ${_kvRow('Volume', fmtN(q.regularMarketVolume, 0))}
        ${_kvRow('Avg Vol (3m)', fmtN(q.averageDailyVolume3Month, 0))}
        ${_kvRow('Open', fmtN(q.regularMarketOpen, 2))}
        ${_kvRow('Prev Close', fmtN(q.regularMarketPreviousClose, 2))}
      </div>
    </div>
    <div style="padding:0 28px 24px;display:grid;grid-template-columns:repeat(4,1fr);gap:12px;">
      ${_statCard('Market Cap', fmtBn(q.marketCap))}
      ${_statCard('P/E (TTM)', fmtN(q.trailingPE, 2))}
      ${_statCard('Fwd P/E', fmtN(q.forwardPE, 2))}
      ${_statCard('EPS (TTM)', fmtN(q.epsTrailingTwelveMonths, 2))}
      ${_statCard('Beta', fmtN(q.beta, 2))}
      ${_statCard('Div Yield', q.trailingAnnualDividendYield != null ? fmtN(q.trailingAnnualDividendYield*100, 2)+'%' : '—')}
      ${_statCard('Book Val', fmtN(q.bookValue, 2))}
      ${_statCard('Price/Book', fmtN(q.priceToBook, 2))}
    </div>
    <div style="padding:0 28px 24px;font-size:12px;color:var(--text-secondary);">
      <div style="font-family:var(--font-mono);font-size:10px;color:var(--text-muted);letter-spacing:0.08em;margin-bottom:6px;">CLASSIFICATION</div>
      <div><b style="color:var(--text-primary);">Sector:</b> ${_escapeHtml(sector)} &nbsp;·&nbsp; <b style="color:var(--text-primary);">Industry:</b> ${_escapeHtml(industry)}</div>
    </div>
    ${localStockBlock}
    ${_renderLegalHistoryBlock(q.symbol || (opts.hint && opts.hint.ticker) || (opts.localStock && opts.localStock.t) || '')}
    <div style="padding:16px 28px;background:var(--surface2);border-top:1px solid var(--border);display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;">
      <div style="font-size:11px;color:var(--text-muted);font-family:var(--font-mono);">Source: Yahoo Finance · cached ${new Date().toLocaleTimeString()}</div>
      <div style="display:flex;gap:8px;">
        <a class="btn btn-ghost btn-sm" href="https://finance.yahoo.com/quote/${encodeURIComponent(q.symbol)}" target="_blank" rel="noopener">Yahoo ↗</a>
        <a class="btn btn-ghost btn-sm" href="https://www.google.com/finance/quote/${encodeURIComponent(q.symbol)}" target="_blank" rel="noopener">Google ↗</a>
        <a class="btn btn-ghost btn-sm" href="https://www.tradingview.com/symbols/${encodeURIComponent(q.symbol)}" target="_blank" rel="noopener">TradingView ↗</a>
        <button class="btn btn-secondary btn-sm" onclick="_searchAddToUniverse(${JSON.stringify(_compactQuoteForUniverse(q, opts.hint)).replace(/"/g,'&quot;')})">＋ Pin to Universe</button>
        <button class="btn btn-primary btn-sm" onclick="document.getElementById('stock-detail-modal').remove()">Done</button>
      </div>
    </div>
  </div>`;
}
function _kvRow(k, v) { return `<div style="display:contents;"><span style="color:var(--text-muted);">${k}</span><span style="font-family:var(--font-mono);text-align:right;">${v}</span></div>`; }
function _statCard(label, v) { return `<div style="background:var(--surface2);border:1px solid var(--border);border-radius:8px;padding:10px 12px;">
  <div style="font-family:var(--font-mono);font-size:9px;color:var(--text-muted);letter-spacing:0.07em;margin-bottom:4px;">${label.toUpperCase()}</div>
  <div style="font-family:var(--font-display);font-size:15px;font-weight:700;">${v}</div>
</div>`; }

// Pin a discovered Yahoo result into the local UNIVERSE so it appears in subsequent searches and the table
function _compactQuoteForUniverse(q, hint) {
  const cur = q.currency || 'USD';
  const mc = (q.marketCap || 0) / 1e9;
  const ev = mc; // approx, EV unavailable from quote endpoint
  const vol = (q.averageDailyVolume3Month || q.regularMarketVolume || 0) / 1e6;
  const co = (typeof _country_from_ticker_js !== 'undefined') ? _country_from_ticker_js(q.symbol) : 'US';
  return {
    n: q.longName || q.shortName || q.symbol, t: q.symbol, ex: q.fullExchangeName || q.exchange || '',
    co, cn: '', reg: '', sec: (hint && hint.sector) || '', ind: (hint && hint.industry) || '',
    mc, ev, vol, ff: 99, cur, isin: '', tier: mc>=200?1:mc>=10?2:mc>=2?3:4,
    beta: q.beta || 0, pe: q.trailingPE || 0, dy: (q.trailingAnnualDividendYield||0)*100,
    rg: 0, eg: 0, mom: 50, qua: 50, vol30: 25, _live: 1
  };
}
function _searchAddToUniverse(stub) {
  if (typeof UNIVERSE === 'undefined') return;
  if (UNIVERSE.some(s => s.t === stub.t)) { alert(stub.t + ' is already in the universe.'); return; }
  // Best-effort country resolution
  if (!stub.co || !UNIVERSE_COUNTRIES[stub.co]) {
    const suf = (stub.t.match(/\.[A-Z]{1,3}$/) || [''])[0];
    const map = {'.L':'GB','.DE':'DE','.PA':'FR','.SW':'CH','.AS':'NL','.MI':'IT','.MC':'ES','.ST':'SE','.OL':'NO','.CO':'DK','.HE':'FI','.BR':'BE','.VI':'AT','.LS':'PT','.AT':'GR','.IR':'IE','.NS':'IN','.BO':'IN','.T':'JP','.KS':'KR','.TW':'TW','.HK':'HK','.SI':'SG','.SS':'CN','.SZ':'CN','.JK':'ID','.BK':'TH','.KL':'MY','.SR':'SA','.AD':'AE','.QA':'QA','.SA':'BR','.JO':'ZA','.IS':'TR','.AX':'AU','.NZ':'NZ','.TO':'CA','.V':'CA','.MX':'MX'};
    stub.co = map[suf] || 'US';
  }
  const meta = UNIVERSE_COUNTRIES[stub.co] || {n:'Unknown', reg:'Other'};
  stub.cn = meta.n; stub.reg = meta.reg;
  // Insert and re-rank
  UNIVERSE.push(stub);
  UNIVERSE.sort((a,b) => (b.mc||0) - (a.mc||0) || (b.vol||0) - (a.vol||0));
  const cc = {};
  UNIVERSE.forEach((s, i) => { s.gr = i+1; cc[s.co] = (cc[s.co]||0)+1; s.cr = cc[s.co]; });
  if (typeof universeRender === 'function' && document.getElementById('page-universe') && !document.getElementById('page-universe').classList.contains('hidden')) {
    universeRender();
  }
  const m = document.getElementById('stock-detail-modal');
  if (m) { m.remove(); }
  // Show toast
  const toast = document.createElement('div');
  toast.style.cssText = 'position:fixed;bottom:24px;right:24px;background:var(--surface2);border:1px solid var(--green);border-radius:var(--radius);padding:12px 18px;color:var(--text-primary);font-size:13px;z-index:9999;box-shadow:0 8px 32px rgba(124,58,237,0.2);animation:fadeInUp 240ms var(--ease-out-strong);';
  toast.innerHTML = `✓ <b>${stub.t}</b> pinned to Universe (rank #${stub.gr.toLocaleString()})`;
  document.body.appendChild(toast);
  setTimeout(() => toast.remove(), 3500);
}
async function _searchOpenStock(s) {
  globalSearchClose();
  // Show modal immediately with local universe data + loading state for live overlay
  _showStockDetailModal({ loading: true, symbol: s.t, name: s.n, exchange: s.ex, type: 'EQUITY', localStock: s });
  // Try to fetch live data
  let q = null;
  try { q = await _searchWebQuote(s.t); } catch (_) {}
  if (q) {
    // Augment q with our richer local data when web data is sparse
    q.longName = q.longName || s.n;
    q.shortName = q.shortName || s.t;
    q.fullExchangeName = q.fullExchangeName || s.ex;
    q.currency = q.currency || s.cur;
    if (!q.marketCap && s.mc) q.marketCap = s.mc * 1e9;
    if (!q.beta && s.beta) q.beta = s.beta;
    if (!q.trailingPE && s.pe) q.trailingPE = s.pe;
    if (!q.trailingAnnualDividendYield && s.dy) q.trailingAnnualDividendYield = s.dy / 100;
    _showStockDetailModal({ q, hint: { sector: s.sec, industry: s.ind }, localStock: s });
  } else {
    // No live data available — render modal from local universe entry only
    _showStockDetailModalFromLocal(s);
  }
}
// Build a quote-shaped object from a local universe row so the modal always renders
function _showStockDetailModalFromLocal(s) {
  const q = {
    symbol: s.t, shortName: s.t, longName: s.n,
    regularMarketPrice: 0, regularMarketChange: 0, regularMarketChangePercent: 0,
    marketCap: s.mc * 1e9,
    enterpriseValue: s.ev * 1e9,
    trailingPE: s.pe || null,
    forwardPE: null,
    epsTrailingTwelveMonths: null,
    beta: s.beta,
    trailingAnnualDividendYield: s.dy ? s.dy / 100 : null,
    bookValue: null,
    priceToBook: null,
    averageDailyVolume3Month: s.vol * 1e6,
    regularMarketVolume: s.vol * 1e6,
    fullExchangeName: s.ex,
    exchange: s.ex,
    currency: s.cur,
    quoteType: 'EQUITY',
    _source: 'local-universe',
  };
  _showStockDetailModal({ q, hint: { sector: s.sec, industry: s.ind }, localStock: s });
}
function _searchOpenNews(n) {
  globalSearchClose();
  const navEl = document.querySelector("[onclick*=\"showPage('news'\"]");
  if (typeof showPage === 'function') showPage('news', navEl);
  setTimeout(() => alert(`📰 ${n.title}\n\nSource: ${n.source || ''}  ·  ${n.time || ''}\n\n${n.excerpt || ''}`), 80);
}
function _searchOpenSector(sec) {
  globalSearchClose();
  const navEl = document.querySelector("[onclick*=\"showPage('universe'\"]");
  if (typeof showPage === 'function') showPage('universe', navEl);
  setTimeout(() => {
    const sel = document.getElementById('uf-sector');
    if (sel) { sel.value = sec; if (typeof universeFilter === 'function') universeFilter(); }
  }, 60);
}
function _searchOpenCountry(co, m) {
  globalSearchClose();
  const navEl = document.querySelector("[onclick*=\"showPage('universe'\"]");
  if (typeof showPage === 'function') showPage('universe', navEl);
  setTimeout(() => {
    const sel = document.getElementById('uf-country');
    if (sel) {
      // Make sure the option exists; populate if not
      if (typeof universePopulateCountryFilter === 'function') universePopulateCountryFilter();
      sel.value = co;
      if (typeof universeFilter === 'function') universeFilter();
    }
  }, 60);
}
function globalSearchClose() {
  const dd = document.getElementById('search-results-dropdown');
  if (dd) dd.classList.add('hidden');
  _searchState.selected = -1;
}
// Close on outside click
document.addEventListener('click', (e) => {
  const wrap = e.target.closest('.search-wrap');
  if (!wrap) globalSearchClose();
});

// ========== QZ BLOOMBERG SEARCH SYSTEM ==========
const _qzs = {
  query:'', type:'all', selected:-1, results:[], debounceId:null,
  liveCache:new Map(), liveInflight:new Set(), webCache:new Map(), webBusy:false
};
const _qzap = { ticker:null, stock:null, chart:null, tf:'1D', watchlist:[] };

// --- Overlay open / close ---
function qzSearchOpen(prefill) {
  const ov = document.getElementById('qz-search-overlay');
  if (!ov) return;
  ov.classList.add('open');
  const inp = document.getElementById('qzs-input');
  if (inp) {
    const topInp = document.getElementById('global-search');
    if (topInp) topInp.blur();
    if (prefill && prefill.trim()) inp.value = prefill;
    requestAnimationFrame(() => { inp.focus(); if (inp.value) _qzsOnInput(inp.value, true); else _qzsRenderHome(); });
  }
}
function qzSearchClose() {
  const ov = document.getElementById('qz-search-overlay');
  if (ov) ov.classList.remove('open');
  const inp = document.getElementById('qzs-input');
  if (inp) inp.value = '';
  _qzs.query = ''; _qzs.results = []; _qzs.selected = -1;
}

// Keyboard: "/" opens overlay, ESC closes
document.addEventListener('keydown', (e) => {
  const overlayOpen = document.getElementById('qz-search-overlay')?.classList.contains('open');
  if (e.key === 'Escape' && overlayOpen) { qzSearchClose(); return; }
  if (e.key === '/' && !overlayOpen && !['INPUT','TEXTAREA'].includes(document.activeElement.tagName)) {
    e.preventDefault(); qzSearchOpen('');
  }
});

// --- Recent searches (localStorage) ---
function _qzsGetRecent() { try { return JSON.parse(localStorage.getItem('qz_search_recent')||'[]'); } catch { return []; } }
function _qzsAddRecent(item) {
  let r = _qzsGetRecent().filter(x => x.ticker !== item.ticker);
  r.unshift(item); if (r.length > 8) r = r.slice(0, 8);
  try { localStorage.setItem('qz_search_recent', JSON.stringify(r)); } catch {}
}
function _qzsClearRecent() { try { localStorage.removeItem('qz_search_recent'); } catch {} _qzsRenderHome(); }

// --- Type filter tabs ---
function _qzsSetType(t) {
  _qzs.type = t;
  document.querySelectorAll('.qzs-tab').forEach(b => b.classList.toggle('active', b.dataset.type === t));
  if (_qzs.query) _qzsOnInput(_qzs.query, true); else _qzsRenderHome();
}

// --- Input handler (debounced) ---
function _qzsOnInput(v, immediate) {
  _qzs.query = (v || '').trim();
  clearTimeout(_qzs.debounceId);
  if (!_qzs.query) { _qzsRenderHome(); return; }
  if (immediate) { _qzsDoSearch(); return; }
  _qzs.debounceId = setTimeout(_qzsDoSearch, 110);
}

// --- Global alias map: common names/phrases → canonical ticker ---
