  'johnson':'JNJ','j&j':'JNJ','pfizer':'PFE','moderna':'MRNA','abbvie':'ABBV','merck':'MRK',
  'eli lilly':'LLY','unitedhealth':'UNH','visa':'V','mastercard':'MA','paypal':'PYPL',
  'exxon':'XOM','chevron':'CVX','walmart':'WMT','costco':'COST','home depot':'HD',
  'mcdonalds':'MCD','coca cola':'KO','pepsi':'PEP','disney':'DIS','intel':'INTC',
  'amd':'AMD','broadcom':'AVGO','qualcomm':'QCOM','at&t':'T','verizon':'VZ',
  'general electric':'GE','boeing':'BA','caterpillar':'CAT','raytheon':'RTX','ups':'UPS',
  'starbucks':'SBUX','uber':'UBER','lyft':'LYFT','coinbase':'COIN','palantir':'PLTR',
  'snowflake':'SNOW','airbnb':'ABNB','doordash':'DASH','spotify':'SPOT','twitter':'X',
  // Crypto
  'bitcoin':'BTC-USD','ethereum':'ETH-USD','solana':'SOL-USD','ripple':'XRP-USD',
  'cardano':'ADA-USD','dogecoin':'DOGE-USD','polkadot':'DOT-USD','avalanche':'AVAX-USD',
  'chainlink':'LINK-USD','litecoin':'LTC-USD','binance coin':'BNB-USD','bnb':'BNB-USD',
  // ETFs
  's&p 500 etf':'SPY','sp500':'SPY','nasdaq etf':'QQQ','nasdaq100':'QQQ',
  'gold etf':'GLD','silver etf':'SLV','bond etf':'TLT','emerging markets':'EEM',
  'small cap':'IWM','real estate etf':'VNQ','dividend etf':'VYM','vanguard etf':'VTI',
  // Indices
  's&p 500':'^GSPC','sp500 index':'^GSPC','dow jones':'^DJI','dow':'^DJI',
  'nasdaq index':'^IXIC','nasdaq composite':'^IXIC','vix':'^VIX','russell 2000':'^RUT',
  'nifty':'NIFTY50','nifty 50':'^NSEI','sensex':'^BSESN','ftse':'^FTSE',
  'nikkei':'^N225','hang seng':'^HSI','dax':'^GDAXI','cac':'^FCHI',
  // Forex
  'euro':'EURUSD=X','eur/usd':'EURUSD=X','gbp':'GBPUSD=X','pound':'GBPUSD=X',
  'yen':'USDJPY=X','usd/jpy':'USDJPY=X','yuan':'USDCNY=X','cad':'USDCAD=X',
  // Indian stocks
  'reliance':'RELIANCE.NS','tcs':'TCS.NS','tata consultancy':'TCS.NS','infosys':'INFY.NS',
  'hdfc bank':'HDFCBANK.NS','icici bank':'ICICIBANK.NS','wipro':'WIPRO.NS',
  'tata motors':'TATAMOTORS.NS','itc':'ITC.NS','bajaj finance':'BAJFINANCE.NS',
  // European
  'samsung':'005930.KS','asml':'ASML','tsmc':'TSM','novo nordisk':'NVO','lvmh':'MC.PA',
  'shell':'SHEL','bp':'BP','siemens':'SIE.DE','volkswagen':'VOW3.DE','nestle':'NESN.SW',
