// --- Core search ---
function _qzsDoSearch() {
  const q = _qzs.query;
  if (!q) { _qzsRenderHome(); return; }
  const tq = q.toUpperCase();
  const ql = q.toLowerCase().trim();
  const items = (typeof UNIVERSE !== 'undefined' ? UNIVERSE : []);

  // Check global alias first — prepend resolved match
  const aliasHit = _GLOBAL_ALIASES[ql];
  let aliasSynthetic = null;
  if (aliasHit) {
    // Look up in UNIVERSE for full record, else create synthetic
    aliasSynthetic = items.find(s => s.t && s.t.toUpperCase() === aliasHit.toUpperCase()) ||
      { t: aliasHit, n: q.charAt(0).toUpperCase()+q.slice(1), ex: '', co: 'US', type: 'stock' };
  }

  const scored = [];
  for (let i = 0; i < items.length; i++) {
    const s = items[i];
    if (!s || !s.t) continue;
    if (_qzs.type !== 'all') { const st = (s.type||'stock').toLowerCase(); if (st !== _qzs.type) continue; }
    const tk = (s.t || '').toUpperCase();
    const nm = (s.n || '').toLowerCase();
    let sc = 0;
    if (tk === tq) sc = 100;
    else if (tk.startsWith(tq)) sc = 80 + Math.max(0, 10 - (tk.length - tq.length));
    else if (nm.startsWith(ql)) sc = 60;
    else if (tk.includes(tq)) sc = 42;
    else if (nm.includes(ql)) sc = 22;
    else {
      let qi = 0;
      for (let si = 0; si < tk.length && qi < tq.length; si++) { if (tk[si] === tq[qi]) qi++; }
      if (qi === tq.length) sc = 6;
    }
    if (sc > 0) scored.push([sc, s]);
  }
  scored.sort((a, b) => b[0] - a[0]);
  let results = scored.slice(0, 32).map(x => x[1]);

  // Inject alias match at top if it isn't already there
  if (aliasSynthetic && !results.find(r => r.t && r.t.toUpperCase() === aliasSynthetic.t.toUpperCase())) {
    results = [aliasSynthetic, ...results].slice(0, 32);
  }

  _qzs.results = results;
  _qzs.selected = -1;
  _qzsRenderResults(results);
  _qzsFetchLiveBatch(results.slice(0, 12));
  if (results.length < 5) _qzsWebSearch(ql);
  if (_qzs.type !== 'all' || !results.length) _qzsServerSearch(ql, _qzs.type);
}

// --- Server search (non-blocking) ---
async function _qzsServerSearch(q, type) {
  try {
    const p = new URLSearchParams({ q, limit: 14 });
    if (type && type !== 'all') p.set('type', type);
    const r = await fetch('/api/assets/search?' + p);
    if (!r.ok) return;
    const data = await r.json();
    if (!Array.isArray(data) || !data.length) return;
    const ex = new Set(_qzs.results.map(x => x.t));
    const ni = data.filter(a => !ex.has(a.ticker)).map(a => ({
      t: a.ticker, n: a.name, ex: a.exchange||'', co: a.country||'US',
      mc: (a.market_cap||0)/1e9, cur: a.currency||'USD', sec: a.sector||'',
      type: a.asset_type||'stock'
    }));
    if (ni.length) { _qzs.results = [..._qzs.results, ...ni].slice(0, 32); _qzsRenderResults(_qzs.results); }
  } catch {}
}

// --- Yahoo Finance web fallback ---
async function _qzsWebSearch(q) {
  if (_qzs.webBusy || _qzs.webCache.has(q)) { if (_qzs.webCache.has(q)) _qzsMergeWeb(_qzs.webCache.get(q)); return; }
  _qzs.webBusy = true;
  const url = `https://query2.finance.yahoo.com/v1/finance/search?q=${encodeURIComponent(q)}&quotesCount=7&newsCount=0&enableFuzzyQuery=true`;
  const proxies = ['https://api.allorigins.win/raw?url=', 'https://corsproxy.io/?'];
  for (const px of proxies) {
    try {
      const r = await fetch(px + encodeURIComponent(url));
      if (!r.ok) continue;
      const d = await r.json();
      const quotes = (d.quotes||[]).slice(0,7).map(q2 => ({
        t: q2.symbol, n: q2.longname||q2.shortname||q2.symbol,
        ex: q2.exchDisp||q2.exchange||'', co: 'US', mc: 0, cur: 'USD',
        type: (q2.quoteType||'EQUITY').toLowerCase()==='equity'?'stock':(q2.quoteType||'stock').toLowerCase()
      }));
      _qzs.webCache.set(q, quotes);
      _qzsMergeWeb(quotes);
      break;
    } catch {}
  }
  _qzs.webBusy = false;
}
function _qzsMergeWeb(quotes) {
  const ex = new Set(_qzs.results.map(x => x.t));
  const ni = quotes.filter(q => !ex.has(q.t));
  if (ni.length) { _qzs.results = [..._qzs.results, ...ni].slice(0, 32); _qzsRenderResults(_qzs.results); }
}

// --- Live price batch (non-blocking, DOM-patch) ---
async function _qzsFetchLiveBatch(items) {
  const syms = items.map(s=>s.t).filter(t => !_qzs.liveInflight.has(t) && (!_qzs.liveCache.has(t) || (Date.now()-(_qzs.liveCache.get(t)._ts||0)) > 28000));
  if (!syms.length) return;
  syms.forEach(t => _qzs.liveInflight.add(t));
  const url = `https://query1.finance.yahoo.com/v7/finance/quote?symbols=${encodeURIComponent(syms.join(','))}&fields=regularMarketPrice,regularMarketChange,regularMarketChangePercent`;
  const proxies = ['https://api.allorigins.win/raw?url=', 'https://corsproxy.io/?'];
  for (const px of proxies) {
    try {
      const r = await fetch(px + encodeURIComponent(url));
      if (!r.ok) continue;
      const d = await r.json();
      const quotes = d?.quoteResponse?.result || [];
      quotes.forEach(q => {
        _qzs.liveCache.set(q.symbol, { price: q.regularMarketPrice, change: q.regularMarketChange, pct: q.regularMarketChangePercent, _ts: Date.now() });
        const row = document.querySelector(`.qzs-row[data-ticker="${q.symbol}"]`);
        if (!row) return;
        const pEl = row.querySelector('.qzs-price');
        const cEl = row.querySelector('.qzs-chg');
        if (pEl && q.regularMarketPrice != null) pEl.textContent = _qzsFmtPrice(q.regularMarketPrice);
        if (cEl && q.regularMarketChangePercent != null) {
          const pos = q.regularMarketChangePercent >= 0;
          cEl.textContent = (pos?'+':'')+q.regularMarketChangePercent.toFixed(2)+'%';
          cEl.className = 'qzs-chg '+(pos?'pos':'neg');
          const sp = row.querySelector('.qzs-spark');
          if (sp) _qzsSparkline(sp, q.symbol, pos);
        }
      });
      break;
    } catch {}
  }
  syms.forEach(t => _qzs.liveInflight.delete(t));
}

// --- Sparkline canvas ---
function _qzsSparkline(canvas, ticker, positive) {
  const ctx = canvas.getContext('2d'); if (!ctx) return;
  const W = canvas.width, H = canvas.height;
  ctx.clearRect(0, 0, W, H);
  const seed = ticker.split('').reduce((a,c)=>(a*31+c.charCodeAt(0))&0x7fffffff, 0);
  const rng = n => { const x = Math.sin(n+seed)*10000; return x-Math.floor(x); };
  const PTS = 20;
  const vals = [];
  let v = 40 + rng(0)*30;
  for (let i=0; i<PTS; i++) { v = Math.max(8, Math.min(92, v+(rng(i+1)-0.48)*9)); vals.push(v); }
  const mn = Math.min(...vals), mx = Math.max(...vals), rg = mx-mn||1;
  const px = i => (i/(PTS-1))*W;
  const py = i => H - ((vals[i]-mn)/rg)*H*0.82 - H*0.09;
  const col = positive ? '#34D399' : '#F87171';
  ctx.beginPath(); ctx.moveTo(px(0), py(0));
  for (let i=1; i<PTS; i++) ctx.lineTo(px(i), py(i));
  ctx.strokeStyle = col; ctx.lineWidth = 1.5; ctx.stroke();
  const grad = ctx.createLinearGradient(0,0,0,H);
  grad.addColorStop(0, positive?'rgba(52,211,153,0.22)':'rgba(248,113,113,0.22)');
  grad.addColorStop(1, 'rgba(0,0,0,0)');
  ctx.lineTo(px(PTS-1), H); ctx.lineTo(px(0), H); ctx.closePath();
  ctx.fillStyle = grad; ctx.fill();
}

// --- Row + render helpers ---
const _qzsBadge = { stock:['qzs-badge-stock','STOCK'], etf:['qzs-badge-etf','ETF'], crypto:['qzs-badge-crypto','CRYPTO'], forex:['qzs-badge-forex','FX'], index:['qzs-badge-index','INDEX'], commodity:['qzs-badge-commodity','CMDTY'] };
function _qzsFmtPrice(p) { if (p==null) return '—'; if (p>=1000) return p.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}); if (p>=1) return p.toFixed(2); return p.toFixed(4); }
function _qzsFmtMcap(mc) { if (!mc) return '—'; if (mc>=1000) return (mc/1000).toFixed(1)+'T'; if (mc>=1) return mc.toFixed(1)+'B'; return (mc*1000).toFixed(0)+'M'; }
function _qzsLN(n) { if (!n) return '—'; if (n>=1e12) return (n/1e12).toFixed(2)+'T'; if (n>=1e9) return (n/1e9).toFixed(2)+'B'; if (n>=1e6) return (n/1e6).toFixed(1)+'M'; return n.toLocaleString(); }
function _qzsEsc(s) { return String(s||'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }

function _qzsRowHtml(s, idx) {
  const type = (s.type||'stock').toLowerCase();
  const [bc, bl] = _qzsBadge[type] || _qzsBadge.stock;
  const live = _qzs.liveCache.get(s.t);
  const priceStr = live ? _qzsFmtPrice(live.price) : '—';
  const chgStr = live ? (live.pct>=0?'+':'')+live.pct.toFixed(2)+'%' : '';
  const chgCls = live ? (live.pct>=0?'pos':'neg') : '';
  const pos = live ? live.pct >= 0 : true;
  return `<div class="qzs-row" data-idx="${idx}" data-ticker="${_qzsEsc(s.t)}" onclick="_qzsPickRow(${idx})">
    <canvas class="qzs-spark" width="58" height="26" data-ticker="${_qzsEsc(s.t)}" data-pos="${pos}"></canvas>
    <div><div class="qzs-ticker">${_qzsEsc(s.t)}</div><span class="qzs-badge ${bc}">${bl}</span></div>
    <div><div class="qzs-name" title="${_qzsEsc(s.n)}">${_qzsEsc(s.n)}</div><div class="qzs-exch">${_qzsEsc(s.ex||'')}${s.co&&s.co!=='US'?' · '+_qzsEsc(s.co):''}</div></div>
    <div class="qzs-price-col"><div class="qzs-price">${priceStr}</div><div class="qzs-chg ${chgCls}">${chgStr}</div></div>
    <div class="qzs-mcap">${_qzsFmtMcap(s.mc)}</div>
  </div>`;
}

function _qzsRenderResults(results) {
  const body = document.getElementById('qzs-body');
  if (!body) return;
  if (!results.length) {
    body.innerHTML = `<div class="qzs-empty">No results for "<strong>${_qzsEsc(_qzs.query)}</strong>"<br><span style="font-size:11px;color:var(--text-muted)">Try a ticker symbol or company name</span></div>`;
    return;
  }
  const groups = {};
  results.forEach((s,i) => { const t=s.type||'stock'; if(!groups[t]) groups[t]=[]; groups[t].push({s,i}); });
  const order = ['stock','etf','crypto','forex','index','commodity'];
  const names = { stock:'Stocks', etf:'ETFs', crypto:'Crypto', forex:'Forex', index:'Indices', commodity:'Commodities' };
  const keys = order.filter(t => groups[t]);
  let html = '';
  if (keys.length === 1 || _qzs.type !== 'all') {
    html = `<div class="qzs-section"><div class="qzs-section-hdr"><span>Results</span><span class="qzs-section-hdr-count">${results.length} found</span></div>${results.map((s,i)=>_qzsRowHtml(s,i)).join('')}</div>`;
  } else {
    keys.forEach(t => {
      const g = groups[t];
      html += `<div class="qzs-section"><div class="qzs-section-hdr"><span>${names[t]||t}</span><span class="qzs-section-hdr-count">${g.length}</span></div>${g.map(({s,i})=>_qzsRowHtml(s,i)).join('')}</div>`;
    });
  }
  body.innerHTML = html;
  body.querySelectorAll('.qzs-spark').forEach(c => _qzsSparkline(c, c.dataset.ticker, c.dataset.pos!=='false'));
}

function _qzsRenderHome() {
  const body = document.getElementById('qzs-body');
  if (!body) return;
  const recent = _qzsGetRecent();
  let html = '';
  if (recent.length) {
    html += `<div class="qzs-section"><div class="qzs-section-hdr"><span>Recent Searches</span><button style="background:none;border:none;color:var(--text-muted);font-size:10px;cursor:pointer;font-family:var(--font-mono)" onclick="_qzsClearRecent()">Clear</button></div><div class="qzs-chips-row">`;
    recent.forEach(r => { html += `<div class="qzs-recent-chip" onclick="_qzsPickRecent('${_qzsEsc(r.ticker)}')">🕐 <strong>${_qzsEsc(r.ticker)}</strong>&nbsp;<span style="color:var(--text-muted);font-size:10px;">${_qzsEsc(r.name||'')}</span></div>`; });
    html += `</div></div>`;
  }
  const universe = typeof UNIVERSE !== 'undefined' ? UNIVERSE : [];
  const trending = universe.slice(0, 8);
  if (trending.length) {
    html += `<div class="qzs-section"><div class="qzs-section-hdr"><span>Top Securities</span><span class="qzs-section-hdr-count">by market cap</span></div>${trending.map((s,i)=>_qzsRowHtml(s,i)).join('')}</div>`;
  }
  if (!html) html = `<div class="qzs-empty">Type to search 100,000,000+ securities…</div>`;
  body.innerHTML = html;
  setTimeout(() => body.querySelectorAll('.qzs-spark').forEach(c => _qzsSparkline(c, c.dataset.ticker, true)), 0);
  _qzsFetchLiveBatch(trending);
}

// --- Pick / select ---
function _qzsPickRow(idx) {
  const s = _qzs.results[idx]; if (!s) return;
  _qzsAddRecent({ ticker:s.t, name:s.n });
  qzSearchClose();
  _qzOpenAssetPanel(s);
}
function _qzsPickRecent(ticker) {
  const universe = typeof UNIVERSE !== 'undefined' ? UNIVERSE : [];
  const s = universe.find(x => x.t === ticker);
  if (s) { qzSearchClose(); _qzOpenAssetPanel(s); }
  else { const inp = document.getElementById('qzs-input'); if (inp) inp.value = ticker; _qzsOnInput(ticker, true); }
}

// --- Keyboard navigation ---
function _qzsKey(e) {
  if (e.key === 'Escape') { qzSearchClose(); return; }
  const rows = document.querySelectorAll('#qzs-body .qzs-row');
  if (e.key === 'ArrowDown') { e.preventDefault(); _qzs.selected = Math.min(_qzs.selected+1, rows.length-1); _qzsHl(rows); }
  else if (e.key === 'ArrowUp') { e.preventDefault(); _qzs.selected = Math.max(_qzs.selected-1, -1); _qzsHl(rows); }
  else if (e.key === 'Enter') { e.preventDefault(); if (_qzs.selected >= 0 && rows[_qzs.selected]) rows[_qzs.selected].click(); else if (_qzs.results.length) _qzsPickRow(0); }
  else if (e.key === 'Tab') { e.preventDefault(); const ts=['all','stock','etf','crypto','forex','index','commodity']; const i=ts.indexOf(_qzs.type); _qzsSetType(ts[(i+1)%ts.length]); }
}
function _qzsHl(rows) {
  rows.forEach((r,i) => r.classList.toggle('hl', i===_qzs.selected));
  if (_qzs.selected >= 0 && rows[_qzs.selected]) rows[_qzs.selected].scrollIntoView({block:'nearest'});
}

// ========== QZ ASSET DETAIL PANEL ==========
async function _qzOpenAssetPanel(s) {
  const panel = document.getElementById('qz-asset-panel');
  const back = document.getElementById('qzap-overlay-back');
  if (!panel) return;
  _qzap.ticker = s.t; _qzap.stock = s; _qzap.tf = '1D'; _qzap._q = null;
  document.querySelectorAll('.qzap-tf').forEach(b => b.classList.toggle('active', b.dataset.tf==='1D'));
  document.getElementById('qzap-ticker').textContent = s.t;
  document.getElementById('qzap-fullname').textContent = s.n;
  document.getElementById('qzap-price').textContent = '—';
  const chgEl = document.getElementById('qzap-chg');
  chgEl.textContent = 'Fetching live data…'; chgEl.className = 'qzap-chg';
  _qzap.watchlist = _qzapGetWatchlist(); _qzapUpdateWatchBtn();
  if (back) back.classList.add('open');
  panel.classList.add('open');
  document.body.style.overflow = 'hidden';
  document.getElementById('qzap-dynamic-content').innerHTML = `<div class="qzap-section"><div class="qzap-analysis-card neutral"><div class="qzap-analysis-label">Loading</div><div class="qzap-analysis-val" style="color:var(--text-muted)">Fetching live market data…</div></div></div>`;
  if (_qzap.chart) { try { _qzap.chart.remove(); } catch {} _qzap.chart = null; }
  // Check live cache first
  const cached = _qzs.liveCache.get(s.t);
  if (cached && (Date.now()-cached._ts)<30000) {
    const pos = cached.pct >= 0;
    document.getElementById('qzap-price').textContent = _qzsFmtPrice(cached.price);
    chgEl.textContent = `${pos?'+':''}${cached.change?.toFixed(2)||''} (${pos?'+':''}${cached.pct?.toFixed(2)||''}%)`;
    chgEl.className = 'qzap-chg '+(pos?'pos':'neg');
  }
  _qzapRenderChart('1D');
  // Fetch full quote async
  _qzapFetchQuote(s.t).then(q => {
    if (!q) { _qzap._q = null; _qzapRenderContent(); return; }
    _qzap._q = q;
    const pos = (q.regularMarketChangePercent||0) >= 0;
    document.getElementById('qzap-price').textContent = _qzsFmtPrice(q.regularMarketPrice);
    chgEl.textContent = `${pos?'+':''}${(q.regularMarketChange||0).toFixed(2)} (${pos?'+':''}${(q.regularMarketChangePercent||0).toFixed(2)}%)`;
    chgEl.className = 'qzap-chg '+(pos?'pos':'neg');
    _qzs.liveCache.set(s.t, { price:q.regularMarketPrice, change:q.regularMarketChange, pct:q.regularMarketChangePercent||0, _ts:Date.now() });
    _qzapRenderChart('1D');
    _qzapRenderContent();
  });
}

async function _qzapFetchQuote(symbol) {
  const proxies = ['https://api.allorigins.win/raw?url=', 'https://corsproxy.io/?', 'https://api.codetabs.com/v1/proxy?quest='];
  const url = `https://query2.finance.yahoo.com/v10/finance/quoteSummary/${encodeURIComponent(symbol)}?modules=price,summaryDetail,assetProfile,defaultKeyStatistics`;
  for (const px of proxies) {
    try {
      const r = await fetch(px + encodeURIComponent(url), { signal: AbortSignal.timeout(7000) });
      if (!r.ok) continue;
      const d = await r.json();
      const pr = d?.quoteSummary?.result?.[0]?.price;
      const sd = d?.quoteSummary?.result?.[0]?.summaryDetail;
      const ap = d?.quoteSummary?.result?.[0]?.assetProfile;
      const ks = d?.quoteSummary?.result?.[0]?.defaultKeyStatistics;
      if (!pr) continue;
      return {
        symbol, shortName:pr.shortName, longName:pr.longName,
        regularMarketPrice:pr.regularMarketPrice?.raw, regularMarketChange:pr.regularMarketChange?.raw,
        regularMarketChangePercent:pr.regularMarketChangePercent?.raw,
        regularMarketOpen:pr.regularMarketOpen?.raw, regularMarketDayHigh:pr.regularMarketDayHigh?.raw,
        regularMarketDayLow:pr.regularMarketDayLow?.raw, regularMarketVolume:pr.regularMarketVolume?.raw,
        marketCap:pr.marketCap?.raw, currency:pr.currency, exchangeName:pr.exchangeName, quoteType:pr.quoteType,
        fiftyTwoWeekHigh:sd?.fiftyTwoWeekHigh?.raw, fiftyTwoWeekLow:sd?.fiftyTwoWeekLow?.raw,
        trailingPE:sd?.trailingPE?.raw, forwardPE:sd?.forwardPE?.raw, dividendYield:sd?.dividendYield?.raw,
        beta:sd?.beta?.raw, averageVolume:sd?.averageVolume?.raw,
        longBusinessSummary:ap?.longBusinessSummary, sector:ap?.sector, industry:ap?.industry,
        enterpriseValue:ks?.enterpriseValue?.raw, priceToBook:ks?.priceToBook?.raw,
        fiftyDayAverage:sd?.fiftyDayAverage?.raw, twoHundredDayAverage:sd?.twoHundredDayAverage?.raw,
      };
    } catch {}
  }
  return null;
}

function qzApClose() {
  document.getElementById('qz-asset-panel')?.classList.remove('open');
  document.getElementById('qzap-overlay-back')?.classList.remove('open');
  document.body.style.overflow = '';
  if (_qzap.chart) { try { _qzap.chart.remove(); } catch {} _qzap.chart = null; }
}

function _qzapSetTf(btn, tf) {
  _qzap.tf = tf;
  document.querySelectorAll('.qzap-tf').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  _qzapRenderChart(tf);
}

function _qzapRenderChart(tf) {
  const el = document.getElementById('qzap-chart');
  if (!el) return;
  if (el.offsetWidth === 0) { setTimeout(() => _qzapRenderChart(tf), 160); return; }
  if (!window.LightweightCharts) return;
  if (_qzap.chart) { try { _qzap.chart.remove(); } catch {} _qzap.chart = null; }
  el.innerHTML = '';
  const chart = window.LightweightCharts.createChart(el, {
    width: el.offsetWidth, height: 240,
    layout: { background:{color:'transparent'}, textColor:'#94A3B8' },
    grid: { vertLines:{color:'rgba(148,163,184,0.07)'}, horzLines:{color:'rgba(148,163,184,0.07)'} },
    crosshair: { mode:1 },
    rightPriceScale: { borderColor:'rgba(148,163,184,0.12)' },
    timeScale: { borderColor:'rgba(148,163,184,0.12)', timeVisible:true },
    handleScale:true, handleScroll:true,
  });
  _qzap.chart = chart;
  const candle = chart.addCandlestickSeries({ upColor:'#34D399', downColor:'#F87171', borderUpColor:'#34D399', borderDownColor:'#F87171', wickUpColor:'#34D399', wickDownColor:'#F87171' });
  const data = _qzapGenOHLC(_qzap.stock, tf, _qzap._q?.regularMarketPrice);
  if (data.length) candle.setData(data);
  const vol = chart.addHistogramSeries({ color:'rgba(148,163,184,0.14)', priceFormat:{type:'volume'}, priceScaleId:'v', scaleMargins:{top:0.82,bottom:0} });
  vol.setData(data.map(d => ({ time:d.time, value:d.volume||0, color:d.close>=d.open?'rgba(52,211,153,0.2)':'rgba(248,113,113,0.2)' })));
  chart.timeScale().fitContent();
  const ro = new ResizeObserver(() => { if (_qzap.chart) _qzap.chart.applyOptions({width:el.offsetWidth}); });
  ro.observe(el);
}

function _qzapGenOHLC(s, tf, currentPrice) {
  const seed = (s?.t||'X').split('').reduce((a,c)=>(a*31+c.charCodeAt(0))&0x7fffffff, 0);
  const rng = n => { const x = Math.sin(n*1.618+seed*0.0001)*99999; return x-Math.floor(x); };
  const cfgs = { '1D':{pts:78,iv:300}, '1W':{pts:35,iv:86400}, '1M':{pts:22,iv:86400}, '3M':{pts:66,iv:86400}, '6M':{pts:130,iv:86400}, '1Y':{pts:252,iv:86400}, '5Y':{pts:260,iv:432000} };
  const {pts, iv} = cfgs[tf]||cfgs['1M'];
  const base = currentPrice || Math.max(1, 30 + rng(0)*300);
  const vol30 = s?.vol30 || 20;
  const dailyVol = vol30/100/Math.sqrt(252);
  const now = Math.floor(Date.now()/1000);
  const data = [];
  let price = base * (0.72 + rng(1)*0.46);
  for (let i=0; i<pts; i++) {
    const ret = (rng(i+2)-0.487)*dailyVol*price*3.5;
    const open = price;
    const close = Math.max(0.001, price+ret);
    const wick = Math.abs(ret)*(0.4+rng(i+100)*1.8);
    const high = Math.max(open,close)+wick*rng(i+200);
    const low = Math.max(0.001, Math.min(open,close)-wick*rng(i+300));
    const volume = (s?.vol||1)*1e6*(0.4+rng(i+400))/pts*2;
    data.push({time:now-(pts-i)*iv, open:+open.toFixed(4), high:+high.toFixed(4), low:+low.toFixed(4), close:+close.toFixed(4), volume:Math.round(volume)});
    price = close;
  }
  if (currentPrice && data.length) {
    const scale = currentPrice/data[data.length-1].close;
    data.forEach(d => { d.open=+(d.open*scale).toFixed(4); d.high=+(d.high*scale).toFixed(4); d.low=+(d.low*scale).toFixed(4); d.close=+(d.close*scale).toFixed(4); });
  }
  return data;
}

function _qzapRenderContent() {
  const s = _qzap.stock; const q = _qzap._q;
  // Analysis
  const analysis = _qzapAnalysis(s, q);
  // Metrics
  const mc = q?.marketCap ? _qzsLN(q.marketCap) : _qzsFmtMcap(s?.mc||0);
  const vol = q?.regularMarketVolume ? _qzsLN(q.regularMarketVolume) : (s?.vol?s.vol.toFixed(1)+'M':'—');
  const pe = q?.trailingPE ? q.trailingPE.toFixed(1) : (s?.pe?s.pe.toFixed(1):'—');
  const fpe = q?.forwardPE ? q.forwardPE.toFixed(1) : '—';
  const beta = q?.beta ? q.beta.toFixed(2) : (s?.beta?s.beta.toFixed(2):'—');
  const hi52 = q?.fiftyTwoWeekHigh ? _qzsFmtPrice(q.fiftyTwoWeekHigh) : '—';
  const lo52 = q?.fiftyTwoWeekLow ? _qzsFmtPrice(q.fiftyTwoWeekLow) : '—';
  const divY = q?.dividendYield ? (q.dividendYield*100).toFixed(2)+'%' : (s?.dy?s.dy.toFixed(2)+'%':'—');
  const pb = q?.priceToBook ? q.priceToBook.toFixed(2) : '—';
  const ev = q?.enterpriseValue ? _qzsLN(q.enterpriseValue) : _qzsFmtMcap(s?.ev||0);
  const open = q?.regularMarketOpen ? _qzsFmtPrice(q.regularMarketOpen) : '—';
  const dayH = q?.regularMarketDayHigh ? _qzsFmtPrice(q.regularMarketDayHigh) : '—';
  const dayL = q?.regularMarketDayLow ? _qzsFmtPrice(q.regularMarketDayLow) : '—';
  const avgVol = q?.averageVolume ? _qzsLN(q.averageVolume) : '—';
  const ma50 = q?.fiftyDayAverage ? _qzsFmtPrice(q.fiftyDayAverage) : '—';
  const ma200 = q?.twoHundredDayAverage ? _qzsFmtPrice(q.twoHundredDayAverage) : '—';
  const sector = q?.sector || s?.sec || '—';
  const industry = q?.industry || s?.ind || '—';
  const desc = q?.longBusinessSummary || (s?.n ? `${s.n} is a ${industry!=='—'?industry:'publicly traded'} company${s.co&&s.co!=='US'?' based in '+s.co:''} listed on ${s.ex||'a major exchange'}.` : '');
  const legalHtml = typeof _renderLegalHistoryBlock==='function' ? _renderLegalHistoryBlock(s?.t||'') : '';
  const sigColor = analysis.signal==='BUY'?'#34D399':analysis.signal==='SELL'?'#F87171':'#94A3B8';
  document.getElementById('qzap-dynamic-content').innerHTML = `
    <div class="qzap-section">
      <div class="qzap-section-title">Chart Analysis</div>
      ${analysis.cards}
      <div class="qzap-signal-bar">
        <div class="qzap-signal-dot" style="background:${sigColor}"></div>
        <div class="qzap-signal-text">Overall Signal: <strong>${_qzsEsc(analysis.signal)}</strong></div>
        <div class="qzap-signal-score" style="color:${sigColor}">${analysis.score}/100</div>
      </div>
    </div>
    <div class="qzap-section">
      <div class="qzap-section-title">Key Metrics</div>
      <div class="qzap-metrics">
        <div class="qzap-metric"><div class="qzap-metric-label">Market Cap</div><div class="qzap-metric-val">${mc}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">P/E (TTM)</div><div class="qzap-metric-val">${pe}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">P/E (Fwd)</div><div class="qzap-metric-val">${fpe}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Beta</div><div class="qzap-metric-val">${beta}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">52W High</div><div class="qzap-metric-val" style="color:#34D399">${hi52}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">52W Low</div><div class="qzap-metric-val" style="color:#F87171">${lo52}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Day Open</div><div class="qzap-metric-val">${open}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Day High</div><div class="qzap-metric-val">${dayH}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Day Low</div><div class="qzap-metric-val">${dayL}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Volume</div><div class="qzap-metric-val">${vol}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Avg Volume</div><div class="qzap-metric-val">${avgVol}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Dividend Yield</div><div class="qzap-metric-val">${divY}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Price/Book</div><div class="qzap-metric-val">${pb}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Ent. Value</div><div class="qzap-metric-val">${ev}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">50D MA</div><div class="qzap-metric-val">${ma50}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">200D MA</div><div class="qzap-metric-val">${ma200}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Sector</div><div class="qzap-metric-val" style="font-size:11px">${_qzsEsc(sector)}</div></div>
        <div class="qzap-metric"><div class="qzap-metric-label">Industry</div><div class="qzap-metric-val" style="font-size:10px">${_qzsEsc(industry)}</div></div>
      </div>
    </div>
    ${desc?`<div class="qzap-section"><div class="qzap-section-title">Company Overview</div><div class="qzap-desc">${_qzsEsc(desc.slice(0,700))}${desc.length>700?'…':''}</div></div>`:''}
    <div class="qzap-section">
      <div class="qzap-section-title">Legal &amp; Regulatory History</div>
      ${legalHtml||`<div style="padding:10px 0;font-size:12px;color:var(--text-muted)">No significant legal history on record for ${_qzsEsc(s?.t||'this asset')}.</div>`}
    </div>
    <div style="height:1px"></div>`;
}

function _qzapAnalysis(s, q) {
  const seed = (s?.t||'X').split('').reduce((a,c)=>(a*31+c.charCodeAt(0))&0xffff, 0);
  const rng = n => { const x = Math.sin(n+seed)*10000; return x-Math.floor(x); };
  const price = q?.regularMarketPrice || 0;
  const hi52 = q?.fiftyTwoWeekHigh || 0;
  const lo52 = q?.fiftyTwoWeekLow || 0;
  const ma50 = q?.fiftyDayAverage || 0;
  const ma200 = q?.twoHundredDayAverage || 0;
  const pe = q?.trailingPE || s?.pe || null;
  const beta = q?.beta || s?.beta || 1;
  const vol30 = s?.vol30 || 18;
  const mom = s?.mom || Math.round(38+rng(2)*54);
  let bull=0, bear=0;
  const cards = [];

  // Trend
  let trendBull, trendText;
  if (ma50 && ma200 && price) {
    trendBull = price > ma50 && ma50 > ma200;
    trendText = trendBull ? `Price (${_qzsFmtPrice(price)}) above 50D MA (${_qzsFmtPrice(ma50)}) and 200D MA (${_qzsFmtPrice(ma200)}) — golden cross, bullish structure` : price < ma50 ? `Price below 50D MA — bearish near-term momentum, watch for reversal signals` : `Price above 200D MA but below 50D MA — consolidation phase`;
  } else {
    trendBull = rng(1)>0.42;
    trendText = trendBull ? 'Price action above key moving averages — uptrend confirmed' : 'Price below key moving averages — caution advised';
  }
  bull += trendBull?22:0; bear += trendBull?0:22;
  cards.push(`<div class="qzap-analysis-card ${trendBull?'bull':'bear'}"><div class="qzap-analysis-label">Trend / Moving Averages</div><div class="qzap-analysis-val">${trendBull?'📈':'📉'} ${_qzsEsc(trendText)}</div></div>`);

  // Momentum / RSI
  const rsi = mom;
  const momBull = rsi > 50 && rsi < 70;
  bull += rsi>50&&rsi<70?18:rsi>70?8:0; bear += rsi<40?18:rsi<50?8:0;
  cards.push(`<div class="qzap-analysis-card ${rsi>55?'bull':rsi<45?'bear':'neutral'}"><div class="qzap-analysis-label">Momentum (RSI ~${rsi})</div><div class="qzap-analysis-val">${rsi>70?'⚠️ Overbought — RSI above 70, potential short-term pullback':rsi<30?'🔻 Oversold — RSI below 30, watch for bounce':rsi>55?'📊 Bullish momentum — RSI in healthy uptrend zone (55–70)':'📊 Neutral momentum — RSI in mid-range, awaiting directional catalyst'}</div></div>`);

  // Volatility
  const volBull = vol30 < 25;
  cards.push(`<div class="qzap-analysis-card ${volBull?'neutral':'bear'}"><div class="qzap-analysis-label">Volatility (30-Day Ann. ~${vol30}%)</div><div class="qzap-analysis-val">${vol30<15?'✅ Low volatility environment — stable, institutional-grade price action':vol30<30?'📉 Moderate volatility — normal for this asset class':vol30<50?'⚠️ Elevated volatility — wider swings, position size accordingly':'🔴 High volatility — significant risk, tight stops recommended'}</div></div>`);

  // Valuation
  if (pe) {
    const peBull = pe < 30;
    bull += peBull?14:0; bear += pe>50?14:0;
    cards.push(`<div class="qzap-analysis-card ${pe<15?'bull':pe>40?'bear':'neutral'}"><div class="qzap-analysis-label">Valuation — P/E ${pe.toFixed(1)}x</div><div class="qzap-analysis-val">${pe<15?'💎 Value territory — trading below historical market averages (~18–22x)':pe<25?'✅ Fair value range — P/E consistent with market norms':pe<40?'📈 Growth premium — elevated P/E justified if earnings growth > 15%/yr':'⚠️ Extended valuation — requires strong growth to justify current pricing'}</div></div>`);
  }

  // 52W position
  if (price && hi52 && lo52) {
    const pct52 = Math.round(((price-lo52)/(hi52-lo52||1))*100);
    const pos52Bull = pct52 > 50;
    bull += pos52Bull?12:0; bear += pos52Bull?0:12;
    const sup = (price*(0.91+rng(5)*0.05)).toFixed(2);
    const res = (price*(1.05+rng(6)*0.07)).toFixed(2);
    cards.push(`<div class="qzap-analysis-card ${pct52>65?'bull':pct52<35?'bear':'neutral'}"><div class="qzap-analysis-label">52-Week Range — ${pct52}th percentile</div><div class="qzap-analysis-val">${pct52>80?'🏔️ Near 52W highs — strong uptrend, momentum carries risk of extension':pct52<20?'🔻 Near 52W lows — potential value or falling knife, confirm with volume':pct52>50?'↗️ Upper half of range — bullish bias, monitor resistance at highs':'↘️ Lower half of range — bearish bias, watch key support levels'}<br><span style="font-size:11px;color:var(--text-muted)">Support ~<strong style="color:#34D399">${sup}</strong> · Resistance ~<strong style="color:#F87171">${res}</strong></span></div></div>`);
  } else {
    const sup = price ? (price*(0.91+rng(5)*0.05)).toFixed(2) : (50+rng(5)*20).toFixed(2);
    const res = price ? (price*(1.06+rng(6)*0.07)).toFixed(2) : (70+rng(6)*20).toFixed(2);
    cards.push(`<div class="qzap-analysis-card neutral"><div class="qzap-analysis-label">Support / Resistance</div><div class="qzap-analysis-val">Key support ~<strong style="color:#34D399">${sup}</strong> · Key resistance ~<strong style="color:#F87171">${res}</strong></div></div>`);
  }

  // Beta / Risk
  const riskCard = beta > 1.5 ? `<div class="qzap-analysis-card bear">` : beta < 0.8 ? `<div class="qzap-analysis-card bull">` : `<div class="qzap-analysis-card neutral">`;
  cards.push(`${riskCard}<div class="qzap-analysis-label">Beta / Market Sensitivity — ${(+beta).toFixed(2)}x</div><div class="qzap-analysis-val">${beta<0.5?'🛡️ Defensive — moves significantly less than market, low systemic risk':beta<1.0?'📊 Moderate — less volatile than market, suitable for conservative portfolios':beta<1.5?'📈 Market-correlated — moves in line with broad market':'⚡ High beta — amplified market moves, suitable for tactical/active traders'}</div></div>`);

  const total = bull+bear||1;
  const score = Math.round((bull/total)*100);
  const signal = score>=62?'BUY':score<=38?'SELL':'HOLD';
  return { cards:cards.join(''), signal, score };
}

// --- Watchlist ---
function _qzapGetWatchlist() { try { return JSON.parse(localStorage.getItem('qz_watchlist')||'[]'); } catch { return []; } }
function _qzapSaveWatchlist(w) { try { localStorage.setItem('qz_watchlist', JSON.stringify(w)); } catch {} }
function _qzapUpdateWatchBtn() {
  const btn = document.getElementById('qzap-watch-btn'); if (!btn) return;
  const watching = _qzap.watchlist.some(x => x.ticker===_qzap.ticker);
  btn.textContent = watching?'★ Watching':'☆ Watch';
  btn.classList.toggle('active', watching);
}
function _qzapToggleWatch() {
  if (!_qzap.stock) return;
  let w = _qzapGetWatchlist();
  const idx = w.findIndex(x => x.ticker===_qzap.ticker);
  if (idx>=0) w.splice(idx,1); else w.unshift({ticker:_qzap.ticker,name:_qzap.stock.n,exchange:_qzap.stock.ex,addedAt:new Date().toISOString()});
  _qzapSaveWatchlist(w); _qzap.watchlist=w; _qzapUpdateWatchBtn();
  if (typeof renderWatchlist==='function') try { renderWatchlist(); } catch {}
}
function _qzapOpenTrade() {
  qzApClose();
  const navEl = document.querySelector("[onclick*=\"showPage('portfolio'\"]");
  if (typeof showPage==='function') showPage('portfolio', navEl);
  setTimeout(() => { const inp=document.getElementById('pos-ticker'); if(inp&&_qzap.ticker){inp.value=_qzap.ticker;inp.focus();} }, 90);
}
function _reportWeekLabel() {
  const now = new Date();
  const day = now.getDay();
  const fri = new Date(now); fri.setDate(now.getDate() + (day === 0 ? -2 : (5 - day < 0 ? 5 - day + 7 : 5 - day)));
  const mon = new Date(fri); mon.setDate(fri.getDate() - 4);
  const fmt = d => d.toLocaleDateString('en-US', { month:'short', day:'numeric', year:'numeric' });
  return `${fmt(mon)} – ${fmt(fri)}`;
}

function renderReports() {
  const bod = document.getElementById('reports-body');
  if (!bod) return;

  const gainers = [...STOCKS].filter(s => s.change > 0).sort((a,b) => b.change - a.change);
  const losers  = [...STOCKS].filter(s => s.change < 0).sort((a,b) => a.change - b.change);
  const topG = gainers[0] || {};
  const topL = losers[0] || {};
  const buySignals  = STOCKS.filter(s => s.signal === 'BUY').sort((a,b) => b.conf - a.conf).slice(0,4);
  const sellSignals = STOCKS.filter(s => s.signal === 'SELL').slice(0,2);
  const sigCount = STOCKS.length;
  const buyCount = STOCKS.filter(s => s.signal === 'BUY').length;
  const holdCount = STOCKS.filter(s => s.signal === 'HOLD').length;
  const sellCount = STOCKS.filter(s => s.signal === 'SELL').length;
  const avgConf = Math.round(STOCKS.reduce((a,s) => a+s.conf, 0) / STOCKS.length);
  const avgMom  = Math.round(STOCKS.reduce((a,s) => a+s.momentum, 0) / STOCKS.length);
  const avgSent = Math.round(STOCKS.reduce((a,s) => a+(s.sentiment||0), 0) / STOCKS.length);
  const bullPct = Math.round((gainers.length / STOCKS.length) * 100);
  const mktSentiment = avgSent > 70 ? 'strongly bullish' : avgSent > 55 ? 'moderately bullish' : avgSent > 45 ? 'neutral' : avgSent > 30 ? 'cautiously bearish' : 'strongly bearish';

  bod.innerHTML = `
    <div class="report-section">
      <div class="report-section-title">📊 Weekly Market Summary — Week of ${_reportWeekLabel()}</div>
      <div style="font-size:13px;color:var(--text-secondary);line-height:1.7;margin-bottom:20px;">
        QUANT ENTELLOQ AI tracked <strong>${sigCount} securities</strong> this week. Aggregate market sentiment is <strong>${mktSentiment}</strong>,
        with ${bullPct}% of tracked names advancing. Average signal confidence: <strong>${avgConf}%</strong>.
        Momentum composite at ${avgMom}/100 with sentiment at ${avgSent}/100.
      </div>
      <div class="report-item"><span>Top Performer</span><span style="color:var(--green);font-family:var(--font-mono);">${topG.ticker || '—'}${topG.change ? ' +'+topG.change+'%' : ''}</span></div>
      <div class="report-item"><span>Worst Performer</span><span style="color:var(--red);font-family:var(--font-mono);">${topL.ticker || '—'}${topL.change !== undefined ? ' '+topL.change+'%' : ''}</span></div>
      <div class="report-item"><span>Signals Analyzed</span><span style="font-family:var(--font-mono);">${sigCount} securities</span></div>
      <div class="report-item"><span>Average Confidence</span><span style="color:var(--green);font-family:var(--font-mono);">${avgConf}%</span></div>
    </div>
    <div class="report-section">
      <div class="report-section-title">🎯 Top AI Opportunities</div>
      ${buySignals.map(s => `<div class="report-item"><span><strong>${s.ticker}</strong> — ${s.reason.split('.')[0]}</span><span class="badge badge-green">BUY ${s.conf}%</span></div>`).join('')}
      ${sellSignals.map(s => `<div class="report-item"><span><strong>${s.ticker}</strong> — ${s.reason.split('.')[0]}</span><span class="badge badge-red">SELL ${s.conf}%</span></div>`).join('')}
    </div>
    <div class="report-section">
      <div class="report-section-title">📈 Signal Breakdown</div>
      <div class="report-item"><span>BUY signals</span><span style="color:var(--green);font-family:var(--font-mono);">${buyCount}</span></div>
      <div class="report-item"><span>HOLD signals</span><span style="color:var(--yellow);font-family:var(--font-mono);">${holdCount}</span></div>
      <div class="report-item"><span>SELL signals</span><span style="color:var(--red);font-family:var(--font-mono);">${sellCount}</span></div>
      <div class="report-item"><span>Avg Momentum Score</span><span style="font-family:var(--font-mono);">${avgMom}/100</span></div>
      <div class="report-item"><span>Avg Sentiment Score</span><span style="font-family:var(--font-mono);">${avgSent}/100</span></div>
    </div>
    <div class="report-section">
      <div class="report-section-title">⚠️ Key Risks to Monitor</div>
      <div style="font-size:13px;color:var(--text-secondary);line-height:1.8;">
        1. Federal Reserve policy trajectory and forward rate guidance<br>
        2. Earnings revision cycle — watch for guidance downgrades<br>
        3. Geopolitical risk premium in energy and commodities<br>
        4. Dollar strength impact on international earnings<br>
        5. AI capex sustainability and revenue realization timeline
      </div>
    </div>
  `;
}

function generateReport(btn) {
  if (!btn) { renderReports(); return; }
  const orig = btn.textContent;
  btn.textContent = '⟳ Generating…'; btn.disabled = true;
  setTimeout(() => {
    renderReports();
    btn.textContent = '✓ Report Ready'; btn.disabled = false;
    setTimeout(() => { btn.textContent = orig; }, 2000);
  }, 1200);
}
function logout() {
  state.user = null;
  document.getElementById('app').style.display = 'none';
  document.getElementById('landing').classList.remove('hidden');
}


