      { type:"Risk Constraint Violation", detect:"Signal package fails any VaR, drawdown, or user-defined rule deterministically", response:"BLOCK emission; route signal to Failure Handler; generate specific rule-violation report; emit REVIEW alert to user", recovery:"Failure Handler attempts: (1) position-size reduction, (2) time-horizon extension, (3) HOLD substitution. If unresolvable → discard + log to audit trail" },
      { type:"Agent Node / Pod Failure", detect:"Missed Kubernetes liveness probe (3 consecutive failures) or Kafka consumer lag >10k messages", response:"K8s terminates and restarts pod; Orchestrator switches routing to healthy replicas; in-flight messages acknowledged only on success (at-least-once delivery)", recovery:"Pod restart with exponential backoff; DLQ captures orphaned tasks; replayed on healthy pod; incident logged with root-cause tagging for post-mortem" }
