function renderAgentSystem() {
  const level = (window.state && state.profile && state.profile.level) || 'intermediate';
  const spec = AGENT_SPECS[level] || AGENT_SPECS.intermediate;

  // Update description
  const descEl = document.getElementById('agent-system-desc');
  if(descEl) descEl.textContent = spec.desc;

  // Update scalability sections
  const sh = document.getElementById('scalability-horizontal');
  const sf = document.getElementById('scalability-fault');
  const so = document.getElementById('scalability-optimize');
  if(sh) sh.textContent = spec.scalabilityH;
  if(sf) sf.textContent = spec.scalabilityF;
  if(so) so.textContent = spec.scalabilityO;

  // Render agent cards
  const grid = document.getElementById('agent-cards-grid');
  if(grid) {
    grid.innerHTML = spec.agents.map(a => `
      <div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:20px;transition:all 0.2s;" onmouseover="this.style.borderColor='rgba(255,255,255,0.15)'" onmouseout="this.style.borderColor='var(--border)'">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:14px;">
          <div style="width:36px;height:36px;background:rgba(255,255,255,0.04);border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:16px;border:1px solid rgba(255,255,255,0.06);">${a.emoji}</div>
          <div style="font-family:var(--font-display);font-size:13px;font-weight:700;color:${a.color};">${a.name}</div>
        </div>
        <div style="font-size:13px;color:var(--text-secondary);line-height:1.6;margin-bottom:14px;">${a.role}</div>
        <div style="display:flex;flex-direction:column;gap:8px;">
          <div style="padding:8px 10px;background:var(--surface2);border-radius:6px;border-left:2px solid rgba(255,255,255,0.1);">
            <div style="font-size:9px;font-family:var(--font-mono);color:var(--text-muted);margin-bottom:3px;">INPUT</div>
            <div style="font-size:11px;color:var(--text-secondary);">${a.input}</div>
          </div>
          <div style="padding:8px 10px;background:var(--surface2);border-radius:6px;border-left:2px solid ${a.color}30;">
            <div style="font-size:9px;font-family:var(--font-mono);color:var(--text-muted);margin-bottom:3px;">OUTPUT</div>
            <div style="font-size:11px;color:var(--text-secondary);">${a.output}</div>
          </div>
          <div style="padding:8px 10px;background:var(--surface2);border-radius:6px;border-left:2px solid rgba(255,211,42,0.3);">
            <div style="font-size:9px;font-family:var(--font-mono);color:var(--text-muted);margin-bottom:3px;">DECISION LOGIC</div>
            <div style="font-size:11px;color:var(--text-secondary);">${a.decision}</div>
          </div>
        </div>
      </div>
    `).join('');
  }

  // Render failure table
  const tbody = document.getElementById('failure-table-body');
  if(tbody) {
    tbody.innerHTML = spec.failures.map((f,i) => `
      <tr style="border-bottom:1px solid var(--border-light);">
        <td style="padding:12px 16px;color:var(--red);font-family:var(--font-mono);font-size:12px;white-space:nowrap;">${f.type}</td>
        <td style="padding:12px 16px;color:var(--text-secondary);font-size:12px;">${f.detect}</td>
        <td style="padding:12px 16px;color:var(--text-secondary);font-size:12px;">${f.response}</td>
        <td style="padding:12px 16px;color:var(--green);font-size:12px;">${f.recovery}</td>
      </tr>
    `).join('');
  }
}

