const _agentState = { activeId: null, history: {} };
function renderAgentsGrid() {
  const grid = document.getElementById('agents-grid');
  if (!grid) return;
  grid.innerHTML = AGENT_DEFINITIONS.map(a => {
    const queries = (_agentState.history[a.id] || []).filter(m => m.role === 'user').length;
    const accuracy = 88 + Math.floor((a.id.charCodeAt(0)*7) % 11);
    const latency = 80 + Math.floor((a.id.charCodeAt(0)*13) % 200);
    return `<div class="agent-card" style="--accent-color:${a.color};" onclick="openAgentDrawer('${a.id}')">
      <div class="agent-status-pill">● ONLINE</div>
      <div class="agent-icon">${a.icon}</div>
      <div class="agent-name">${a.name}</div>
      <div class="agent-role">${a.role}</div>
      <div class="agent-desc">${a.desc}</div>
      <div class="agent-stats-row">
        <div class="agent-stat"><span>QUERIES</span><span class="agent-stat-val">${queries}</span></div>
        <div class="agent-stat"><span>ACCURACY</span><span class="agent-stat-val">${accuracy}%</span></div>
        <div class="agent-stat"><span>LATENCY</span><span class="agent-stat-val">${latency}ms</span></div>
      </div>
    </div>`;
  }).join('');
  const total = Object.values(_agentState.history).reduce((s, h) => s + h.filter(m=>m.role==='user').length, 0);
  const el = document.getElementById('agents-queries-today');
  if (el) el.textContent = total.toLocaleString();
}
function openAgentDrawer(agentId) {
  const a = AGENT_DEFINITIONS.find(x => x.id === agentId);
  if (!a) return;
  _agentState.activeId = agentId;
  document.getElementById('agent-drawer-icon').textContent = a.icon;
  document.getElementById('agent-drawer-name').textContent = a.name;
  document.getElementById('agent-drawer-name').style.color = a.color;
  document.getElementById('agent-drawer-role').textContent = a.role.toUpperCase();
  document.getElementById('agent-drawer-desc').textContent = a.desc;
  const chips = document.getElementById('agent-suggest-chips');
  chips.innerHTML = a.suggests.map(q => `<div class="agent-suggest-chip" onclick="setAgentInput(this.textContent)">${q}</div>`).join('');
  renderAgentMessages();
  document.getElementById('agent-drawer').classList.add('open');
  document.getElementById('agent-drawer-overlay').classList.add('open');
  setTimeout(() => document.getElementById('agent-drawer-input').focus(), 200);
}
function closeAgentDrawer() {
  document.getElementById('agent-drawer').classList.remove('open');
  document.getElementById('agent-drawer-overlay').classList.remove('open');
  _agentState.activeId = null;
}
function setAgentInput(text) { const inp = document.getElementById('agent-drawer-input'); inp.value = text; inp.focus(); }
function renderAgentMessages() {
  const id = _agentState.activeId; if (!id) return;
  const a = AGENT_DEFINITIONS.find(x => x.id === id);
  const box = document.getElementById('agent-drawer-messages');
  const history = _agentState.history[id] || [];
  if (history.length === 0) {
    box.innerHTML = `<div style="text-align:center;padding:48px 20px;color:var(--text-muted);font-size:13px;">
      <div style="font-size:36px;margin-bottom:14px;opacity:0.5;">${a.icon}</div>
      <div style="font-family:var(--font-display);font-weight:700;color:var(--text-primary);margin-bottom:4px;">Ask ${a.name} anything</div>
      <div style="font-size:12px;line-height:1.6;">${a.desc}</div>
    </div>`;
  } else {
    box.innerHTML = history.map(m => {
      if (m.role === 'user') return `<div class="agent-message user"><div class="agent-message-bubble">${_escapeHtml(m.text)}</div></div>`;
      if (m.role === 'thinking') return `<div class="agent-message agent"><div class="agent-message-bubble"><div class="agent-thinking"><span></span><span></span><span></span></div></div></div>`;
      return `<div class="agent-message agent"><div class="agent-message-bubble">${m.text}</div></div>`;
    }).join('');
    box.scrollTop = box.scrollHeight;
  }
}
async function submitAgentQuery() {
  const id = _agentState.activeId; if (!id) return;
  const inp = document.getElementById('agent-drawer-input');
  const q = inp.value.trim(); if (!q) return;
  inp.value = '';
  if (!_agentState.history[id]) _agentState.history[id] = [];
  _agentState.history[id].push({ role:'user', text:q });
  _agentState.history[id].push({ role:'thinking' });
  renderAgentMessages();
  await new Promise(r => setTimeout(r, 400 + Math.random()*900));
  _agentState.history[id] = _agentState.history[id].filter(m => m.role !== 'thinking');
  const reply = composeAgentReply(id, q);
  _agentState.history[id].push({ role:'agent', text:reply });
  renderAgentMessages();
  renderAgentsGrid();
}
function composeAgentReply(agentId, q) {
  const ql = q.toLowerCase();
  let stock = null;
  if (typeof UNIVERSE !== 'undefined') {
    const tokens = q.toUpperCase().match(/\b[A-Z]{1,6}(?:\.[A-Z]{1,3})?\b/g) || [];
    for (const tk of tokens) { const hit = (_uvTickerMap.size > 0 ? _uvTickerMap.get(tk) : UNIVERSE.find(s => s.t === tk)); if (hit) { stock = hit; break; } }
    if (!stock) {
      const lookup = UNIVERSE.find(s => s.n.toLowerCase().includes(ql) || (s.n.length>4 && ql.includes(s.n.toLowerCase().split(' ')[0])));
      if (lookup) stock = lookup;
    }
  }
  const fmt = n => n>=1000?'$'+(n/1000).toFixed(2)+'T':n>=1?'$'+n.toFixed(2)+'B':'$'+(n*1000).toFixed(0)+'M';
  const a = AGENT_DEFINITIONS.find(x => x.id === agentId);
  switch (agentId) {
    case 'orchestrator':
      if (stock) return `<strong>Routing plan for ${stock.t}:</strong><br>1. <span style="color:var(--green);">Ingestor</span> → fetch latest tick + 30d history<br>2. <span style="color:var(--green);">Sentiment</span> → score recent news (~12 articles in cache)<br>3. <span style="color:var(--blue);">Signal Gen</span> → recompute factor scores<br>4. <span style="color:var(--blue);">LLM Reasoner</span> → synthesize narrative<br>5. <span style="color:var(--yellow);">Risk Validator</span> → check position limits<br>6. <span style="color:#A78BFA;">Output</span> → personalize for your level<br><br>Total estimated latency: <strong>~480ms</strong>. Workflow ID: <code style="background:var(--surface3);padding:1px 5px;border-radius:3px;">orch_${Date.now().toString(36)}</code>`;
      return `Workflow priority is decided by 3 inputs: (1) <strong>query type</strong> — alerts beat reports beat backtests; (2) <strong>data freshness</strong> — live signals route fast-lane; (3) <strong>user tier</strong>. P95 first-token latency is <strong>182ms</strong>.`;
    case 'ingestor':
      return `<strong>Live feed status:</strong><br>• 🇺🇸 NYSE/NASDAQ — <span style="color:var(--green);">connected</span>, lag 80ms<br>• 🇬🇧 LSE — <span style="color:var(--green);">connected</span>, lag 110ms<br>• 🇯🇵 TSE — <span style="color:var(--yellow);">stale</span> (market closed)<br>• 🇨🇳 SSE/SZSE — <span style="color:var(--green);">connected</span>, lag 220ms<br>• 🇮🇳 NSE — <span style="color:var(--green);">connected</span>, lag 95ms<br><br>Universe coverage: <strong>100,000,000+ securities across 100+ exchanges</strong>. ${stock ? 'Latest tick on '+stock.t+' was ingested ~'+Math.floor(Math.random()*60)+'s ago.' : ''}`;
    case 'sentiment':
      if (stock) {
        const score = stock.mom > 70 ? '+'+(stock.mom/2|0) : stock.mom > 40 ? '+'+(stock.mom/4|0) : '-'+((100-stock.mom)/4|0);
        return `<strong>${stock.t} sentiment:</strong> <span style="color:${parseInt(score)>0?'var(--green)':'var(--red)'};font-size:18px;font-weight:700;">${score}</span> (scale -100 to +100)<br><br>• Article count (24h): ${15 + (stock.gr % 30)}<br>• Average tone: ${stock.mom > 60 ? 'Constructive' : stock.mom > 40 ? 'Neutral' : 'Cautious'}<br>• Velocity: ${stock.mom > 80 ? 'Accelerating bullish' : 'Stable'}<br>• Notable mentions: WSJ, Bloomberg, Reuters<br><br>Sentiment cross-correlates with momentum factor at <strong>r = 0.34</strong>.`;
      }
      return `Today's top sentiment movers (24h):<br>• <strong>NVDA</strong> +82 — chip cycle commentary<br>• <strong>LLY</strong> +71 — GLP-1 trial readouts<br>• <strong>TSLA</strong> -18 — robotaxi delay rumors<br>• <strong>BABA</strong> +44 — China stimulus flow<br><br>Aggregate market sentiment: <strong>+12 (mildly bullish)</strong>.`;
    case 'signal':
      if (stock) {
        const sig = stock.mom > 65 && stock.qua > 75 ? 'BUY' : stock.mom < 40 ? 'SELL' : 'HOLD';
        const conf = Math.min(95, Math.round(stock.qua * 0.6 + stock.mom * 0.4));
        const sigColor = sig==='BUY'?'var(--green)':sig==='SELL'?'var(--red)':'var(--yellow)';
        return `<strong>${stock.n} (${stock.t})</strong><br>Signal: <span style="color:${sigColor};font-size:18px;font-weight:700;">${sig}</span> &nbsp; Confidence: <strong>${conf}%</strong><br><br><strong>Factors:</strong><br>• Momentum: ${stock.mom}/100<br>• Quality: ${stock.qua}/100<br>• Beta: ${stock.beta} &nbsp; P/E: ${stock.pe || '—'} &nbsp; Div: ${stock.dy}%<br>• Rev gr: ${stock.rg>0?'+':''}${stock.rg}% &nbsp; EPS gr: ${stock.eg>0?'+':''}${stock.eg}%<br>• 30d vol: ${stock.vol30}%<br><br>Mkt cap: ${fmt(stock.mc)} (Tier ${stock.tier})<br><br>${sig==='BUY' ? 'Top quartile of peer group on composite.' : sig==='SELL'?'Underperforms peers on momentum + quality.':'Sitting near median — wait for clearer break.'}`;
      }
      return `Today's <strong>top BUY signals</strong>:<br>${(typeof UNIVERSE !== 'undefined' ? UNIVERSE.filter(s => s.mom > 75 && s.qua > 70).slice(0, 8) : []).map((s, i) => `${i+1}. <strong>${s.t}</strong> ${s.n.length>32?s.n.slice(0,32)+'…':s.n} — ${fmt(s.mc)} · mom ${s.mom}, qual ${s.qua}`).join('<br>')}`;
    case 'portfolio':
      // Dynamic — pulled from live state.portfolio
      const _pos = (typeof state !== 'undefined' && Array.isArray(state.portfolio)) ? state.portfolio : [];
      const _sym = (typeof regionState !== 'undefined' && regionState.selectedCountry) ? (regionState.selectedCountry.symbol || '$') : '$';
      const _tv  = _pos.reduce((s, p) => s + p.qty * p.current, 0);
      const _tc  = _pos.reduce((s, p) => s + p.qty * p.cost, 0);
      const _pnl = _tv - _tc;
      if (_pos.length === 0) {
        return `<strong>Your portfolio is empty.</strong><br>Add positions via the Portfolio page or say <em>"Hey Quant Entelloq, add a position"</em>. Once you've got holdings, I'll analyze sector concentration, beta-weighted exposure, Sharpe ratio, and rebalance recommendations.`;
      }
      return `<strong>Portfolio analysis:</strong><br>• Total value: <strong>${_sym}${_tv.toLocaleString('en-US',{maximumFractionDigits:0})}</strong> across ${_pos.length} positions<br>• Total P&L: <strong style="color:${_pnl>=0?'var(--green)':'var(--red)'};">${_pnl>=0?'+':'-'}${_sym}${Math.abs(_pnl).toLocaleString('en-US',{maximumFractionDigits:0})}</strong><br>• Top holding: <strong>${_pos[0].ticker}</strong> at ${_sym}${(_pos[0].qty * _pos[0].current).toLocaleString('en-US',{maximumFractionDigits:0})}<br><br>I can drill into sector concentration, beta exposure, or recommend rebalances — just ask.`;
    case 'llm':
      if (stock) return `<strong>${stock.n}</strong> is a ${(['','mega','large','mid','small'][stock.tier])}-cap ${stock.sec.toLowerCase()} company in ${stock.cn}, trading at ${fmt(stock.mc)} mkt cap.<br><br>Currently exhibiting <strong>${stock.mom > 70 ? 'strong positive' : stock.mom > 40 ? 'mixed' : 'weakening'} momentum</strong> (${stock.mom}/100), with quality ${stock.qua}/100 driven by ${stock.qua > 80 ? 'durable margins and balance-sheet strength' : 'a mix of growth and discipline'}.<br><br>Beta ${stock.beta}, trailing P/E ${stock.pe || '—'}. Rev grew ${stock.rg>0?'+':''}${stock.rg}% YoY, EPS ${stock.eg>0?'+':''}${stock.eg}%. ${stock.dy > 2 ? 'Pays '+stock.dy+'% div.' : 'Reinvests cash flow.'} Free float ${stock.ff}%.`;
      return `Ask me about any of the 100,000,000+ stocks in the universe, or compare two — like "compare ASML vs AMAT" or "explain India equity bull case".`;
    case 'risk':
      if (stock) {
        const risks = [];
        if (stock.beta > 1.5) risks.push('• High beta (' + stock.beta + ') — amplifies market moves');
        if (stock.vol30 > 35) risks.push('• Elevated 30d vol (' + stock.vol30 + '%)');
        if (stock.ff < 60) risks.push('• Low free float (' + stock.ff + '%) — liquidity risk');
        if (stock.tier === 4) risks.push('• Small-cap — slippage risk on size');
        if (stock.eg < 0) risks.push('• Negative earnings growth');
        return `<strong>Risk for ${stock.t}:</strong><br><br>${risks.length ? risks.join('<br>') : '<span style="color:var(--green);">✓ No flagged risks at standard limits</span>'}<br><br><strong>Position cap:</strong> Max single-name ${stock.tier===1?'10':stock.tier===2?'5':stock.tier===3?'3':'1.5'}% of portfolio.<br><br>Pre-trade gate: <span style="color:var(--green);">PASSED</span>.`;
      }
      return `<strong>Risk validation rules:</strong><br>• Single-name cap: 10% (T1) / 5% (T2) / 3% (T3) / 1.5% (T4)<br>• Sector cap: 35%<br>• Country cap: 75%<br>• Min liquidity: $5M ADV<br>• Max gross: 150%<br><br>Vetoed signals this week: <strong>4</strong>.`;
    case 'macro':
      return `<strong>Macro regime:</strong> <span style="color:var(--green);">Late-cycle, easing tailwind</span><br><br>• Fed funds: 4.25–4.50%, market pricing 2 cuts<br>• 10Y: 4.28% (flat 30d)<br>• DXY: 104.3 (-2% MoM)<br>• Brent: $78<br>• Gold: $2,341 (+12% YTD)<br><br>Yield curve dis-inverting (positive for cyclicals). Credit spreads tight. VIX 16.2.<br><br>Fed cuts <strong>typically benefit tech</strong> (long-duration). Rate-sensitive sectors well-positioned.`;
    case 'output':
      return `<strong>Your delivery preferences:</strong><br>• Explanation level: <strong>Advanced</strong><br>• Risk framing: <strong>Moderate</strong><br>• Push: ON<br><br>Surface routing:<br>• <strong>BUY/SELL signals</strong> → push + in-app + dashboard<br>• <strong>News alerts</strong> → in-app<br>• <strong>Weekly digest</strong> → email Sunday 8am<br>• <strong>Risk warnings</strong> → push + in-app<br><br>Say "switch me to simple mode" anytime.`;
  }
  return `Reply from ${a.name}: noted "${q}" — try a suggested prompt above.`;
}

