// Procedurally extend the universe to N entries with realistic distributions.
// Uses deterministic PRNG so the universe is stable across renders.
function _prng(seed) { let s=seed>>>0; return ()=>{ s=(s*1664525+1013904223)>>>0; return (s&0xffffffff)/0x100000000; }; }

function _padIsin(prefix, idx) {
  const body = String(idx).padStart(9, '0');
  const checksum = (idx % 10).toString();
  return prefix + body + checksum;
}

function _rngTicker(co, idx, rng) {
  // Country-coded synthetic tickers for procedural fill.
  const letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  let stub='';
  for (let i=0;i<3;i++) stub += letters[Math.floor(rng()*26)];
  const suffixMap = {US:'',CN:'.SS',HK:'.HK',IN:'.NS',JP:'.T',KR:'.KS',TW:'.TW',GB:'.L',DE:'.DE',FR:'.PA',CH:'.SW',NL:'.AS',
    IT:'.MI',ES:'.MC',SE:'.ST',NO:'.OL',DK:'.CO',FI:'.HE',PL:'.WA',BE:'.BR',AT:'.VI',PT:'.LS',GR:'.AT',IE:'.IR',
    SG:'.SI',ID:'.JK',TH:'.BK',MY:'.KL',VN:'.HM',PH:'.PS',PK:'.KA',BD:'.DH',
    SA:'.SR',AE:'.AD',QA:'.QA',KW:'.KW',IL:'.TA',TR:'.IS',
    BR:'.SA',AR:'.BA',CL:'.SN',CO:'.CN',PE:'.LM',
    ZA:'.JO',EG:'.CA',NG:'.LG',KE:'.NR',MA:'.CS',
    AU:'.AX',NZ:'.NZ',CA:'.TO',MX:'.MX'};
  return stub + (suffixMap[co] !== undefined ? suffixMap[co] : '') + (idx > 100000 ? '' : '');
}

function _genSyntheticCompany(globalRank, co, countryRank, rng) {
  const meta = UNIVERSE_COUNTRIES[co];
  const sector = UNIVERSE_SECTORS[Math.floor(rng()*UNIVERSE_SECTORS.length)];
  const industries = UNIVERSE_INDUSTRIES[sector];
  const ind = industries[Math.floor(rng()*industries.length)];
  // Power-law market cap distribution: top entries large, tail small.
  // Anchored to globalRank — rank 500 ≈ $20B, rank 5000 ≈ $0.5B, rank 10000 ≈ $0.05B
  const baseMc = Math.max(0.02, 200 * Math.pow(globalRank, -0.85) + rng()*0.5);
  const mc = +(baseMc * (0.6 + rng()*0.8)).toFixed(3);
  const ev = +(mc * (0.85 + rng()*0.45)).toFixed(3);
  const vol = +(Math.max(0.005, mc * (0.05 + rng()*0.6) * 10)).toFixed(2);
  const ff = Math.round(40 + rng()*59);
  const tier = mc >= 200 ? 1 : mc >= 10 ? 2 : mc >= 2 ? 3 : 4;
  const beta = +(0.4 + rng()*1.6).toFixed(2);
  const pe = mc < 1 && rng() < 0.3 ? 0 : Math.round(8 + rng()*45);
  const dy = +(rng()*5).toFixed(1);
  const rg = Math.round(-15 + rng()*60);
  const eg = Math.round(-30 + rng()*80);
  const mom = Math.round(rng()*100);
  const qua = Math.round(40 + rng()*55);
  const vol30 = Math.round(10 + rng()*55);
  const ex = meta.ex[Math.floor(rng()*meta.ex.length)];
  const isin = _padIsin(meta.isin, globalRank);
  const t = _rngTicker(co, globalRank, rng);
  // Generate believable name
  const stems = ['Holdings','Industries','Capital','Corp.','Group','Tech','Energy','Bank','Pharma','Logistics','Resources','Partners','Solutions','International','Limited','Plc'];
  const prefixes = ['Northern','Pacific','Central','Atlas','Apex','Vertex','Summit','Sterling','Crescent','Meridian','Nexus','Quantum','Helios','Iron','Polar','Cascade','Granite','Horizon','Sequoia','Aegis'];
  const namePrefix = prefixes[Math.floor(rng()*prefixes.length)];
  const nameStem = stems[Math.floor(rng()*stems.length)];
  const n = `${namePrefix} ${t.replace(/\..*/,'')} ${nameStem}`;
  return {n,t,ex,co,cn:meta.n,reg:meta.reg,sec:sector,ind,mc,ev,vol,ff,cur:meta.cur,isin,tier,beta,pe,dy,rg,eg,mom,qua,vol30,_synth:1};
}

