// Helper: retrieve legal records for a ticker (also tries base ticker without exchange suffix)
function getCompanyLegalHistory(ticker) {
  if (!ticker) return null;
  const t = String(ticker).toUpperCase().trim();
  if (COMPANY_LEGAL_HISTORY[t]) return COMPANY_LEGAL_HISTORY[t];
  // Try stripping exchange suffix (e.g. NOVO-B.CO → NOVO-B.CO, 0700.HK → skip)
  const base = t.split('.')[0];
  if (base !== t && COMPANY_LEGAL_HISTORY[base]) return COMPANY_LEGAL_HISTORY[base];
  return null;
}

// Render legal history HTML block for the stock detail modal
function _renderLegalHistoryBlock(ticker) {
  const records = getCompanyLegalHistory(ticker);
  if (!records || !records.length) return '';
  const statusColor = { 'Settled':'#22C55E', 'Dismissed':'#60A5FA', 'Cleared':'#22C55E', 'Blocked':'#EF4444', 'Verdict against':'#EF4444', 'Verdict':'#F59E0B', 'Mixed':'#F59E0B', 'Partially decided':'#F59E0B', 'Abandoned':'#60A5FA', 'Ongoing':'#F59E0B' };
  const typeColor = { 'Antitrust':'#A78BFA', 'Criminal':'#EF4444', 'Securities':'#60A5FA', 'Privacy':'#34D399', 'Consumer':'#FBBF24', 'Environmental':'#4ADE80', 'Employment':'#FB923C', 'Tax':'#F472B6', 'Labor':'#FB923C', 'Data Breach':'#60A5FA', 'Bribery':'#EF4444', 'Product Liability':'#EF4444', 'Export Control':'#F59E0B', 'Consumer Safety':'#EF4444', 'Trade Secret':'#A78BFA', 'Patent':'#A78BFA', 'Operational':'#60A5FA', 'Mortgage':'#FBBF24', 'Regulatory':'#60A5FA', 'Commodity':'#FBBF24', 'Civil':'#60A5FA' };
  const rows = records.map(r => {
    const sc = statusColor[r.status] || '#888';
    const tc = typeColor[r.type] || '#A78BFA';
    const amt = r.amount ? `<span style="color:#22C55E;font-weight:700;margin-left:8px;">${_escapeHtml(r.amount)}</span>` : '';
    return `<div style="padding:12px;border:1px solid rgba(255,255,255,0.06);border-radius:8px;background:rgba(255,255,255,0.02);margin-bottom:8px;">
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:6px;">
        <span style="font-size:10px;font-weight:700;padding:2px 7px;border-radius:4px;background:rgba(167,139,250,0.1);color:${tc};font-family:var(--font-mono);">${_escapeHtml(r.type)}</span>
        <span style="font-size:10px;font-weight:700;padding:2px 7px;border-radius:4px;background:rgba(0,0,0,0.3);color:${sc};font-family:var(--font-mono);">${_escapeHtml(r.status)}</span>
        <span style="font-size:11px;color:var(--text-muted);margin-left:auto;">${r.year}${amt}</span>
      </div>
      <div style="font-size:13px;font-weight:600;color:var(--text-primary);margin-bottom:4px;">${_escapeHtml(r.title)}</div>
      <div style="font-size:12px;color:var(--text-secondary);line-height:1.6;">${_escapeHtml(r.desc)}</div>
    </div>`;
  }).join('');
  return `<div style="padding:0 28px 24px;">
    <div style="font-family:var(--font-mono);font-size:10px;color:var(--text-muted);letter-spacing:0.08em;margin-bottom:10px;">⚖ LEGAL &amp; REGULATORY HISTORY</div>
    ${rows}
    <div style="font-size:10px;color:var(--text-muted);margin-top:4px;font-family:var(--font-mono);">Sources: DOJ · SEC · FTC · EU Commission · Public court records. Not legal advice.</div>
  </div>`;
}

// Build the full 1,000,000-entry universe once.
let UNIVERSE = [];
function buildUniverse(targetSize=1000000) {
  // 1) Normalize seed: assign region/country name from country meta, set tier from mcap
  const seeded = UNIVERSE_SEED.map(s => {
    const m = UNIVERSE_COUNTRIES[s.co] || {n:s.co,reg:'Other'};
    return {...s, cn:m.n, reg:m.reg, tier: s.mc>=200?1: s.mc>=10?2: s.mc>=2?3:4};
  });
  // 2) Sort by market cap descending
  seeded.sort((a,b) => b.mc - a.mc);
  // 3) Procedural fill for remaining slots.
  // Distribute by country weight (UNIVERSE_COUNTRIES.w) — ensures e.g. ~30% US, 13% CN, etc.
  const remain = targetSize - seeded.length;
  const codes = Object.keys(UNIVERSE_COUNTRIES);
  const totalW = codes.reduce((s,c)=>s+UNIVERSE_COUNTRIES[c].w,0);
  const allocations = {};
  let assigned = 0;
  codes.forEach(c => { allocations[c] = Math.floor(remain * (UNIVERSE_COUNTRIES[c].w / totalW)); assigned += allocations[c]; });
  // Top up rounding leftovers to US
  allocations.US += (remain - assigned);
  const rng = _prng(42);
  const synth = [];
  let synthRank = seeded.length + 1;
  codes.forEach(c => {
    for (let i=0; i<allocations[c]; i++) {
      synth.push(_genSyntheticCompany(synthRank++, c, i+1, rng));
    }
  });
  // 4) Sort all by market cap
  const all = [...seeded, ...synth].sort((a,b) => b.mc - a.mc || b.vol - a.vol);
  // 5) Assign global rank + country rank
  const countryCounters = {};
  all.forEach((s, i) => {
    s.gr = i+1;
    countryCounters[s.co] = (countryCounters[s.co]||0) + 1;
    s.cr = countryCounters[s.co];
  });
  return all;
}
// Build seed companies immediately (~400 real stocks — instant render)
UNIVERSE = buildUniverse(UNIVERSE_SEED.length);
// Generate synthetics lazily so the page appears instantly
// (realOnly=true by default so synthetics are never shown on first load)
(function _buildSyntheticsLazy() {
  const go = () => {
    // Try 1,000,000; fall back gracefully if memory is constrained
    const targets = [1000000, 500000, 200000, 100000];
    for (const t of targets) {
      try {
        UNIVERSE = buildUniverse(t);
        if (typeof uvBuildIndexes === 'function') uvBuildIndexes();
        return;
      } catch(e) { /* try smaller */ }
    }
  };
  if (typeof requestIdleCallback !== 'undefined') {
    requestIdleCallback(go, { timeout: 5000 });
  } else {
    setTimeout(go, 800);
  }
})();

// ==================== HIGH-PERFORMANCE INDEXES ====================
// Built once after UNIVERSE is ready. Replace O(n) scans with O(1) lookups.

// Ticker → asset object (O(1) replacement for every UNIVERSE.find(x => x.t === t))
let _uvTickerMap = new Map();
// Pre-lowercased concatenated search string per asset (8× faster than per-field .includes())
let _uvSearchIdx = [];
// Memoize filter results — skip full recompute when params unchanged
let _uvFilterHash = null;
// Cache sort between page/view changes when sort key/dir unchanged
let _uvSortCache = { key: null, dir: null, arr: null };
// Aggregation cache — single-pass sector/country/factor stats, invalidated on filter change
let _uvAggCache = null;

function uvBuildIndexes() {
  if (typeof UNIVERSE === 'undefined' || !UNIVERSE.length) return;
  _uvTickerMap = new Map(UNIVERSE.map(s => [s.t, s]));
  _uvSearchIdx = UNIVERSE.map(s =>
    [(s.t||''),(s.n||''),(s.cn||''),(s.co||''),(s.sec||''),(s.ind||''),(s.isin||''),(s.ex||'')].join(' ').toLowerCase()
  );
  // Invalidate all caches since the universe changed
  _uvFilterHash = null;
  _uvSortCache  = { key: null, dir: null, arr: null };
  _uvAggCache   = null;
}

// ==================== UNIVERSE — REBUILT ENGINE ====================
// Bulletproof, designer-quality. Reads from UNIVERSE constant built earlier.
const uvState = {
  view: 'table',
  page: 1,
  pageSize: 100,
  sortKey: 'mc',
  sortDir: 'desc',
  filters: { search:'', region:'', country:'', sector:'', tier:'', mcap:'', assetType:'' },
  filtered: [],
  serverMode: false,    // true when browsing non-stock asset types from server registry
  serverResults: [],    // cached server results for current assetType+search combo
  serverFetching: false,
  liveQuotes: {},      // ticker -> { price, change, ts, simulated }
  liveStatus: 'SYNTHETIC',
  populatedCountryFilter: false,
};

// Number formatters
function uvFmtBn(v) {
  if (v == null || isNaN(v)) return '—';
  if (v >= 1000) return '$' + (v/1000).toFixed(2) + 'T';
  if (v >= 1)    return '$' + v.toFixed(1)  + 'B';
  if (v > 0)     return '$' + (v*1000).toFixed(0) + 'M';
  return '—';
}
function uvFmtN(v, dp=2) {
  if (v == null || isNaN(v)) return '—';
  return Number(v).toLocaleString('en-US',{minimumFractionDigits:dp, maximumFractionDigits:dp});
}
function uvEsc(s) { return String(s==null?'':s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }

// Apply filters → produces uvState.filtered
// Memoized: skips full recompute when filters unchanged; uses pre-built search index.
function uvApplyFilters() {
  if (typeof UNIVERSE === 'undefined') { uvState.filtered = []; return; }
  const f = uvState.filters;
  const realOnly = document.getElementById('uv-real-only')?.checked ?? true;
  const q = (f.search || '').toLowerCase().trim();
  const sk = uvState.sortKey, sd = uvState.sortDir;

  // Hash all filter params + universe size (size changes after lazy 100K build)
  const hash = q + '|' + (f.region||'') + '|' + (f.country||'') + '|' + (f.sector||'') + '|'
             + (f.tier||'') + '|' + (f.mcap||'') + '|' + (realOnly?'1':'0') + '|' + UNIVERSE.length;

  if (hash === _uvFilterHash && _uvSortCache.arr) {
    // Same filter params — reuse set, only re-sort if sort changed
    if (_uvSortCache.key !== sk || _uvSortCache.dir !== sd) {
      const dir2 = sd === 'asc' ? 1 : -1;
      _uvSortCache.arr = _uvSortCache.arr.slice().sort((a, b) => {
        const av = a[sk], bv = b[sk];
        if (typeof av === 'string') return av.localeCompare(bv) * dir2;
        return ((av||0) - (bv||0)) * dir2;
      });
      _uvSortCache.key = sk; _uvSortCache.dir = sd;
    }
    uvState.filtered = _uvSortCache.arr;
    return;
  }

  // Filters changed — full recompute
  _uvFilterHash = hash;
  _uvAggCache   = null; // stale aggregations

  const hasIdx  = _uvSearchIdx.length === UNIVERSE.length;
  const mcapMin = f.mcap ? parseFloat(f.mcap) : 0;
  const tierStr = f.tier ? String(f.tier) : '';
  const arr     = [];

  for (let i = 0, len = UNIVERSE.length; i < len; i++) {
    const s = UNIVERSE[i];
    if (realOnly && s._synth)                      continue;
    if (f.region  && s.reg !== f.region)           continue;
    if (f.country && s.co  !== f.country)          continue;
    if (f.sector  && s.sec !== f.sector)           continue;
    if (tierStr   && String(s.tier) !== tierStr)   continue;
    if (mcapMin   && s.mc  <  mcapMin)             continue;
    if (q) {
      const qi = hasIdx
        ? _uvSearchIdx[i]
        : [(s.t||''),(s.n||''),(s.cn||''),(s.co||''),(s.sec||''),(s.ind||''),(s.isin||''),(s.ex||'')].join(' ').toLowerCase();
      if (!qi.includes(q)) continue;
    }
    arr.push(s);
  }

  // Sort once and cache
  const dir = sd === 'asc' ? 1 : -1;
  arr.sort((a, b) => {
    const av = a[sk], bv = b[sk];
    if (typeof av === 'string') return av.localeCompare(bv) * dir;
    return ((av||0) - (bv||0)) * dir;
  });

  _uvSortCache  = { key: sk, dir: sd, arr };
  uvState.filtered = arr;
}

// Update top hero stats
function uvUpdateHero() {
  const f = uvState.filtered;
  const totalMc = f.reduce((s,x) => s + (x.mc||0), 0);
  const countries = new Set(f.map(x => x.co)).size;
  const tier1 = f.filter(x => x.tier === 1).length;
  const setText = (id, v) => { const el = document.getElementById(id); if (el) el.textContent = v; };
  setText('uv-mcap', uvFmtBn(totalMc));
  setText('uv-count', f.length.toLocaleString());
  setText('uv-countries', countries.toLocaleString());
  setText('uv-tier1', tier1.toLocaleString());
}

// Active filter chips
function uvUpdateChips() {
  const c = document.getElementById('uv-active-chips'); if (!c) return;
  const f = uvState.filters;
  const chips = [];
  if (f.search)  chips.push({ k:'search', label:'🔍 "' + f.search + '"' });
  if (f.region)  chips.push({ k:'region', label:'🌍 ' + f.region });
  if (f.country) chips.push({ k:'country', label:(UNIVERSE_FLAGS[f.country]||'') + ' ' + (UNIVERSE_COUNTRIES[f.country]?.n || f.country) });
  if (f.sector)  chips.push({ k:'sector', label:'📊 ' + f.sector });
  if (f.tier)    chips.push({ k:'tier', label:'⚡ Tier ' + f.tier });
  if (f.mcap)    chips.push({ k:'mcap', label:'💰 ≥ $' + f.mcap + 'B' });
  if (chips.length === 0) { c.innerHTML = ''; c.style.display = 'none'; return; }
  c.style.display = 'flex';
  c.innerHTML = chips.map(ch => '<span class="uv-chip" onclick="uvClearOneFilter(\'' + ch.k + '\')">' + uvEsc(ch.label) + ' <span class="uv-chip-x">×</span></span>').join('') +
    (chips.length > 1 ? '<button class="uv-chip-all" onclick="uvClearFilters()">Clear all</button>' : '');
}
function uvClearOneFilter(k) {
  uvState.filters[k] = '';
  const map = { search:'uv-search', region:'uv-region', country:'uv-country', sector:'uv-sector', tier:'uv-tier', mcap:'uv-mcap' };
  const el = document.getElementById(map[k]); if (el) el.value = '';
  uvState.page = 1;
  uvRender();
}

// View renderers
function uvRender() {
  try {
    if (typeof UNIVERSE === 'undefined' || !UNIVERSE.length) {
      const tb = document.getElementById('uv-tbody');
      if (tb) tb.innerHTML = '<tr><td colspan="11" style="padding:60px;text-align:center;color:var(--text-muted);">' +
        '<div style="display:flex;flex-direction:column;align-items:center;gap:10px;">' +
        '<div style="display:flex;gap:6px;">' +
        '<span style="width:8px;height:8px;border-radius:50%;background:var(--accent);animation:uvDot 1.2s ease-in-out infinite;"></span>' +
        '<span style="width:8px;height:8px;border-radius:50%;background:var(--accent);animation:uvDot 1.2s ease-in-out 0.2s infinite;"></span>' +
        '<span style="width:8px;height:8px;border-radius:50%;background:var(--accent);animation:uvDot 1.2s ease-in-out 0.4s infinite;"></span>' +
        '</div>' +
        '<span style="font-family:var(--font-mono);font-size:11px;letter-spacing:0.08em;">BUILDING UNIVERSE…</span>' +
        '</div></td></tr>';
      setTimeout(uvRender, 200);
      return;
    }
    if (!uvState.populatedCountryFilter) uvPopulateCountryFilter();
    uvApplyFilters();
    uvUpdateHero();
    uvUpdateChips();
    uvUpdateSortIndicators();
    uvRenderInsights();   // intelligence panel
    if (uvState.view === 'table')   uvRenderTable();
    if (uvState.view === 'cards')   uvRenderCards();
    if (uvState.view === 'map')     uvRenderMap();
    if (uvState.view === 'sectors') uvRenderSectors();
    if (uvState.view === 'movers')  uvRenderMovers();
  } catch (e) {
    console.error('uvRender error', e);
    const tb = document.getElementById('uv-tbody');
    if (tb) tb.innerHTML = '<tr><td colspan="11" style="padding:60px;text-align:center;color:var(--red);">Render error: ' + uvEsc(e.message) + '</td></tr>';
  }
}

// ============== INTELLIGENCE INSIGHTS — single-pass aggregation with caching ==============

// Compute ALL aggregations in one pass over the universe array, then cache.
// Replaces 6 separate forEach/filter/reduce calls (O(6n)) with O(1n) + cached renders.
function _uvComputeAggs(universe) {
  // Return cached result if filtered set identity hasn't changed
  if (_uvAggCache && _uvAggCache._src === uvState.filtered) return _uvAggCache;

  const bySec = {}, byCo = {};
  const anomalies = [], picksRaw = [];
  let momSum = 0, quaSum = 0, peSum = 0, rgSum = 0, dySum = 0;

  for (let i = 0, len = universe.length; i < len; i++) {
    const s = universe[i];
    // Sectors
    if (!bySec[s.sec]) bySec[s.sec] = { sec: s.sec, mc: 0, mom: 0, n: 0 };
    bySec[s.sec].mc  += s.mc || 0;
    bySec[s.sec].mom += s.mom || 50;
    bySec[s.sec].n++;
    // Countries
    if (!byCo[s.co]) byCo[s.co] = { co: s.co, cn: s.cn, mc: 0, n: 0 };
    byCo[s.co].mc += s.mc || 0;
    byCo[s.co].n++;
    // Factor sums (one accumulation per field, not 5 separate reduces)
    momSum += s.mom || 0; quaSum += s.qua || 0; peSum += s.pe || 30;
    rgSum  += s.rg  || 0; dySum  += s.dy  || 0;
    // Anomaly flags (early-exit when 10 found)
    if (anomalies.length < 10 &&
        ((s.vol30 > 50) || (s.eg < -25 && s.mom > 60) || (s.tier === 4 && s.ff < 50))) {
      anomalies.push(s);
    }
    // AI-picks candidates
    if (s.mom >= 70 && s.qua >= 70 && s.tier <= 2) {
      picksRaw.push({ s, score: s.mom * 0.5 + s.qua * 0.5 - (s.tier - 1) * 5 });
    }
  }

  const n = universe.length || 1;
  picksRaw.sort((a, b) => b.score - a.score);

  _uvAggCache = {
    _src:      uvState.filtered,
    bySec,
    byCo,
    anomalies: anomalies.slice(0, 5),
    topPicks:  picksRaw.slice(0, 3),
    factors:   [
      momSum / n,
      quaSum / n,
      100 - Math.min(100, peSum / n * 1.5),
      Math.max(0, Math.min(100, 50 + rgSum / n * 2)),
      Math.min(100, dySum / n * 18)
    ]
  };
  return _uvAggCache;
}

function uvRenderInsights() {
  try {
    const E = (window.QESecurity && window.QESecurity.escapeHtml) || (s => String(s||'').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])));
    const universe = uvState.filtered.length ? uvState.filtered : UNIVERSE;
    if (!universe || !universe.length) return;

    const agg = _uvComputeAggs(universe); // O(n) once, then O(1) on repeat renders

    // === Top Movers (sample first 200 to keep this fast; already sorted by mcap) ===
    const elMovers = document.getElementById('uv-intel-movers');
    if (elMovers) {
      const withChange = universe.slice(0, 200).map(s => {
        const live = uvState.liveQuotes[s.t];
        return { s, ch: live ? live.change : (s.mom - 50) / 8 };
      });
      const top5 = withChange.slice().sort((a, b) => Math.abs(b.ch) - Math.abs(a.ch)).slice(0, 5);
      elMovers.innerHTML = top5.map(({ s, ch }) => {
        const flag = (typeof UNIVERSE_FLAGS !== 'undefined') ? (UNIVERSE_FLAGS[s.co] || '🏳️') : '';
        return `<div class="uv-intel-row" onclick="uvOpenStock('${E(s.t).replace(/[\\']/g,'')}')">
          <span class="ir-flag">${E(flag)}</span>
          <span class="ir-tk">${E(s.t)}</span>
          <span class="ir-name" title="${E(s.n)}">${E(s.n)}</span>
          <span class="ir-ch ${ch>=0?'ir-up':'ir-down'}">${ch>=0?'▲':'▼'} ${Math.abs(ch).toFixed(2)}%</span>
        </div>`;
      }).join('');
    }

    // === Sector Heatmap (from cached agg) ===
    const elSec = document.getElementById('uv-intel-sectors');
    if (elSec) {
      const sorted = Object.values(agg.bySec).sort((a, b) => b.mc - a.mc).slice(0, 6);
      const maxMc  = sorted[0]?.mc || 1;
      elSec.innerHTML = sorted.map(s => {
        const avgMom = (s.mom / s.n).toFixed(0);
        const pct    = (s.mc / maxMc * 100).toFixed(0);
        const col    = avgMom > 60 ? 'var(--green)' : avgMom < 40 ? 'var(--red)' : 'var(--yellow)';
        return `<div class="uv-intel-sector-row">
          <span class="sr-name">${E(s.sec)}</span>
          <div class="uv-intel-bar"><div class="uv-intel-bar-fill ${avgMom < 40 ? 'neg' : ''}" style="width:${pct}%;"></div></div>
          <span class="sr-pct" style="color:${col};">${avgMom}</span>
        </div>`;
      }).join('');
    }

    // === Country Leaderboard (from cached agg) ===
    const elCo = document.getElementById('uv-intel-countries');
    if (elCo) {
      const sorted = Object.values(agg.byCo).sort((a, b) => b.mc - a.mc).slice(0, 5);
      elCo.innerHTML = sorted.map((c, i) => {
        const flag = (typeof UNIVERSE_FLAGS !== 'undefined') ? (UNIVERSE_FLAGS[c.co] || '🏳️') : '';
        const mc   = c.mc >= 1000 ? '$' + (c.mc/1000).toFixed(1) + 'T' : '$' + c.mc.toFixed(0) + 'B';
        return `<div class="uv-intel-row" onclick="uvFilterByCountry('${E(c.co)}')">
          <span class="ir-flag">${E(flag)}</span>
          <span class="ir-tk" style="min-width:30px;">#${i+1}</span>
          <span class="ir-name">${E(c.cn)}</span>
          <span class="ir-mc">${E(c.n)} sec</span>
          <span class="ir-ch ir-up">${E(mc)}</span>
        </div>`;
      }).join('');
    }

    // === AI Picks (from cached agg) ===
    const elPicks = document.getElementById('uv-intel-picks');
    if (elPicks) {
      elPicks.innerHTML = agg.topPicks.map(({ s }) => {
        const flag   = (typeof UNIVERSE_FLAGS !== 'undefined') ? (UNIVERSE_FLAGS[s.co] || '🏳️') : '';
        const thesis = s.mom >= 85 ? 'Strong momentum + premium quality. Top-decile composite.'
                     : s.qua >= 85 ? 'Highest quality factor — durable margins, balance-sheet strength.'
                     : 'Balanced growth + quality. Tier-' + s.tier + ' liquidity.';
        return `<div class="uv-intel-pick" onclick="uvOpenStock('${E(s.t).replace(/[\\']/g,'')}')">
          <div class="uv-intel-pick-head">
            <span class="uv-intel-pick-tk">${E(flag)} ${E(s.t)}</span>
            <span class="uv-intel-pick-sig">BUY ${(s.mom * 0.5 + s.qua * 0.5).toFixed(0)}</span>
          </div>
          <div class="uv-intel-pick-thesis">${E(thesis)} <b style="color:var(--text-primary);">${E(s.n)}</b> · ${E(s.cn)}</div>
        </div>`;
      }).join('');
    }

    // === Unusual Activity (from cached agg) ===
    const elAnom = document.getElementById('uv-intel-anomalies');
    if (elAnom) {
      if (agg.anomalies.length === 0) {
        elAnom.innerHTML = '<div style="padding:18px;text-align:center;color:var(--text-muted);font-size:11px;font-style:italic;">No anomalies detected in current view.</div>';
      } else {
        elAnom.innerHTML = agg.anomalies.map(s => {
          const flag   = (typeof UNIVERSE_FLAGS !== 'undefined') ? (UNIVERSE_FLAGS[s.co] || '🏳️') : '';
          const reason = s.vol30 > 50 ? `vol ${s.vol30}%`
                       : (s.eg < -25 && s.mom > 60) ? 'mom-EPS divergence'
                       : 'low float ' + s.ff + '%';
          return `<div class="uv-intel-row" onclick="uvOpenStock('${E(s.t).replace(/[\\']/g,'')}')">
            <span class="ir-flag">${E(flag)}</span>
            <span class="ir-tk">${E(s.t)}</span>
            <span class="ir-name" style="color:#ffd966;">⚠ ${E(reason)}</span>
            <span class="ir-ch ir-down">T${E(s.tier)}</span>
          </div>`;
        }).join('');
      }
    }

    // === Factor Composite (from cached agg — no more 5 separate reduces) ===
    const elFac = document.getElementById('uv-intel-factors');
    if (elFac) {
      const labels = ['Momentum', 'Quality', 'Value (low PE)', 'Growth (rev)', 'Yield (div%)'];
      elFac.innerHTML = labels.map((lbl, i) => {
        const v   = agg.factors[i];
        const col = v > 60 ? 'var(--green)' : v < 40 ? 'var(--red)' : 'var(--yellow)';
        return `<div class="uv-intel-sector-row">
          <span class="sr-name">${E(lbl)}</span>
          <div class="uv-intel-bar"><div class="uv-intel-bar-fill ${v < 40 ? 'neg' : ''}" style="width:${v}%;"></div></div>
          <span class="sr-pct" style="color:${col};">${v.toFixed(0)}</span>
        </div>`;
      }).join('');
    }
  } catch (e) {
    console.warn('uvRenderInsights', e);
  }
}

function uvUpdateSortIndicators() {
  document.querySelectorAll('#uv-main-table thead th[data-sort], .uv-table thead th[data-sort]').forEach(th => {
    th.classList.remove('uv-sort-asc','uv-sort-desc','uv-active-sort');
    if (th.dataset.sort === uvState.sortKey) {
      th.classList.add('uv-active-sort', uvState.sortDir==='asc' ? 'uv-sort-asc' : 'uv-sort-desc');
    }
  });
}

// === Table view — clean 11-column design ===
function uvRenderTable() {
  const tb = document.getElementById('uv-tbody'); if (!tb) return;
  const f = uvState.filtered;
  const ps = uvState.pageSize;
  const totalPages = Math.max(1, Math.ceil(f.length / ps));
  if (uvState.page > totalPages) uvState.page = totalPages;
  const start = (uvState.page - 1) * ps;
  const slice = f.slice(start, start + ps);

  const infoEl = document.getElementById('uv-page-info');
  const hasQuery = (uvState.filters.search || '').trim().length > 0;
  if (infoEl) infoEl.textContent = f.length === 0
    ? (hasQuery ? 'No local matches — searching global registry…' : 'No matches — try clearing filters')
    : (start+1) + '–' + Math.min(start+ps, f.length) + ' of ' + f.length.toLocaleString() + ' securities';
  const curEl = document.getElementById('uv-page-current');
  if (curEl) curEl.textContent = 'Page ' + uvState.page + ' / ' + totalPages.toLocaleString();

  // No local results — auto-trigger global server search if there's a query
  if (f.length === 0 && hasQuery && !uvState.serverMode) {
    const q = uvState.filters.search.trim();
    const at = uvState.filters.assetType || '';
    tb.innerHTML = `<tr><td colspan="12" style="padding:40px;text-align:center;">
      <div style="display:flex;flex-direction:column;align-items:center;gap:12px;">
        <div style="font-size:28px;">🌐</div>
        <div style="font-size:14px;font-weight:600;color:var(--text-primary);">Searching global financial universe…</div>
        <div style="font-size:12px;color:var(--text-muted);">Looking for "<strong style="color:var(--accent-2);">${uvEsc(q)}</strong>" across 100M+ entities</div>
        <button class="btn btn-secondary btn-sm" onclick="uvServerSearch(${JSON.stringify(q)},${JSON.stringify(at)})">⟳ Search Global Registry</button>
      </div>
    </td></tr>`;
    // Auto-trigger after a short delay so render completes first
    setTimeout(() => uvServerSearch(q, at), 400);
    return;
  }

  tb.innerHTML = slice.map((s, rowIdx) => {
    const flag   = UNIVERSE_FLAGS[s.co] || '🏳️';
    const live   = uvState.liveQuotes[s.t];
    const isReal = live && !live.simulated;

    // Tier badge vs asset type badge (server-mode rows carry _type)
    const assetTypeLbl = s._type || 'stock';
    const tierOrType = assetTypeLbl !== 'stock'
      ? '<span class="uv-type-badge ' + assetTypeLbl + '">' + assetTypeLbl + '</span>'
      : '<span class="uv-tier-badge uv-tier-' + s.tier + '">T' + s.tier + '</span>';

    // Momentum bar (suppressed for non-stock server rows where mom is synthetic)
    const mom = s.mom || 0;
    const showMom = assetTypeLbl === 'stock' || (!s._type);
    const momCol = mom >= 70 ? 'var(--green)' : mom < 40 ? 'var(--red)' : 'var(--amber)';
    const momBar = showMom
      ? '<div class="uv3-mom-wrap">'
        + '<div class="uv3-mom-bar"><div class="uv3-mom-fill" style="width:' + mom + '%;background:' + momCol + ';"></div></div>'
        + '<span style="font-family:var(--font-mono);font-size:10px;color:' + momCol + ';">' + mom + '</span>'
        + '</div>'
      : '<span class="uv-muted">—</span>';

    // Live price + change
    const priceHtml = live
      ? '<span class="' + (live.change >= 0 ? 'uv-up' : 'uv-down') + '" style="font-family:var(--font-mono);">'
        + (s.cur && s.cur !== 'USD' ? s.cur + ' ' : '$') + live.price.toFixed(2) + '</span>'
        + (isReal ? '<span style="font-size:8px;margin-left:3px;color:var(--green);opacity:0.6;" title="Real data">●</span>' : '')
      : '<span class="uv-muted">—</span>';

    const chgHtml = live
      ? '<span class="' + (live.change >= 0 ? 'uv-up' : 'uv-down') + '" style="font-family:var(--font-mono);">'
        + (live.change >= 0 ? '+' : '') + live.change.toFixed(2) + '%</span>'
      : '<span class="uv-muted">—</span>';

    // Signal badge (suppressed for non-stock types — no meaningful signal without full factor data)
    const sigBadge = assetTypeLbl === 'stock' ? (() => {
      const sigScore = (s.mom || 0) * 0.6 + (s.qua || 0) * 0.4;
      const sigCls   = sigScore >= 68 ? 'uv3-sig-buy' : sigScore < 42 ? 'uv3-sig-sell' : 'uv3-sig-hold';
      const sigLbl   = sigScore >= 68 ? '▲ BUY' : sigScore < 42 ? '▼ SELL' : '● HOLD';
      return '<span class="uv3-sig ' + sigCls + '">' + sigLbl + '</span>';
    })() : '<span class="uv-muted" style="font-size:10px;">—</span>';

    // Row quick-action buttons (hover-revealed)
    const tk0 = s.t.replace(/[\\\']/g,'');
    const qaBtns = '<div class="uv3-row-actions" onclick="event.stopPropagation()">'
      + '<button class="uv3-row-btn" onclick="uvQuickPanel(\'' + tk0 + '\')" title="Quick view">⚡</button>'
      + '<button class="uv3-row-btn" onclick="uvToggleWatch(\'' + tk0 + '\',this)" title="Watchlist">☆</button>'
      + '</div>';

    return '<tr data-ticker="' + uvEsc(s.t) + '" onclick="uvQuickPanel(\'' + tk0 + '\')" style="--row-delay:' + (Math.min(rowIdx, 40) * 8) + 'ms;">'
      + '<td class="uv3-rank">' + (s.gr || '—') + '</td>'
      + '<td><div style="display:flex;align-items:center;gap:6px;">'
      +   '<span class="uv3-tk">' + uvEsc(s.t) + '</span>' + tierOrType + qaBtns
      + '</div></td>'
      + '<td><div class="uv3-co-name" title="' + uvEsc(s.n) + '">' + uvEsc(s.n) + '</div>'
      +    '<div class="uv3-co-sub">' + flag + ' ' + uvEsc(s.cn || s.co || '') + ' &middot; ' + uvEsc(s.ex || '') + '</div></td>'
      + '<td><span class="uv3-sector">' + uvEsc(s.sec || '') + '</span></td>'
      + '<td class="uv3-cap">' + (s.mc > 0 ? uvFmtBn(s.mc) : '<span class="uv-muted">—</span>') + '</td>'
      + '<td class="uv3-num">' + (s.pe ? s.pe : '—') + '</td>'
      + '<td class="uv3-num">' + (s.dy ? s.dy.toFixed(1) + '%' : '—') + '</td>'
      + '<td>' + momBar + '</td>'
      + '<td class="uv3-num">' + (s.beta != null ? s.beta.toFixed(2) : '—') + '</td>'
      + '<td class="uv-live live-price-cell">' + priceHtml + '</td>'
      + '<td class="uv-live live-chg-cell">' + chgHtml + '</td>'
      + '<td>' + sigBadge + '</td>'
      + '</tr>';
  }).join('');
}

// === Cards view (top of filtered) ===
function uvRenderCards() {
  const grid = document.getElementById('uv-cards-grid'); if (!grid) return;
  const ps = uvState.pageSize;
  const start = (uvState.page-1) * ps;
  const slice = uvState.filtered.slice(start, start + ps);
  const totalPages = Math.max(1, Math.ceil(uvState.filtered.length / ps));
  document.getElementById('uv-page-info').textContent = 'Showing ' + (start+1) + '–' + Math.min(start+ps, uvState.filtered.length) + ' of ' + uvState.filtered.length.toLocaleString();
  document.getElementById('uv-page-current').textContent = 'Page ' + uvState.page + ' / ' + totalPages.toLocaleString();
  grid.innerHTML = slice.map(s => {
    const flag = UNIVERSE_FLAGS[s.co] || '🏳️';
    const live = uvState.liveQuotes[s.t];
    const sigClass = s.mom>=70 && s.qua>=70 ? 'uv-card-buy' : s.mom<40 ? 'uv-card-sell' : 'uv-card-hold';
    const sigLabel = s.mom>=70 && s.qua>=70 ? 'BUY' : s.mom<40 ? 'SELL' : 'HOLD';
    return '<div class="uv-card ' + sigClass + '" onclick="uvOpenStock(\''+s.t.replace(/[\\\']/g,'')+'\')">' +
      '<div class="uv-card-top"><span class="uv-card-rank">#' + s.gr.toLocaleString() + '</span><span class="uv-tier-badge uv-tier-' + s.tier + '">T' + s.tier + '</span></div>' +
      '<div class="uv-card-ticker">' + uvEsc(s.t) + ' <span class="uv-card-flag">' + flag + '</span></div>' +
      '<div class="uv-card-name">' + uvEsc(s.n) + '</div>' +
      '<div class="uv-card-mcap">' + uvFmtBn(s.mc) + '</div>' +
      '<div class="uv-card-meta">' + uvEsc(s.sec) + ' · ' + uvEsc(s.cn) + '</div>' +
      '<div class="uv-card-factors">' +
        '<div><div class="uv-card-factor-lbl">MOM</div><div class="uv-card-factor-bar"><div style="width:' + (s.mom||0) + '%;background:var(--green);"></div></div></div>' +
        '<div><div class="uv-card-factor-lbl">QUAL</div><div class="uv-card-factor-bar"><div style="width:' + (s.qua||0) + '%;background:var(--blue);"></div></div></div>' +
      '</div>' +
      '<div class="uv-card-bottom">' +
        '<span class="uv-card-sig">' + sigLabel + '</span>' +
        (live ? '<span class="' + (live.change>=0?'uv-up':'uv-down') + '">' + live.price.toFixed(2) + '</span>' : '<span class="uv-muted">—</span>') +
      '</div>' +
    '</div>';
  }).join('');
}

// === Map view — countries laid out as a grid heat map ===
function uvRenderMap() {
  const grid = document.getElementById('uv-map-grid'); if (!grid) return;
  const byCo = {};
  uvState.filtered.forEach(s => {
    if (!byCo[s.co]) byCo[s.co] = { co: s.co, cn: s.cn, count: 0, mc: 0, tier1: 0 };
    byCo[s.co].count++;
    byCo[s.co].mc += s.mc;
    if (s.tier === 1) byCo[s.co].tier1++;
  });
  const sorted = Object.values(byCo).sort((a,b) => b.mc - a.mc);
  const maxMc = sorted[0]?.mc || 1;
  grid.innerHTML = sorted.map(c => {
    const intensity = Math.min(1, c.mc / maxMc);
    const flag = UNIVERSE_FLAGS[c.co] || '🏳️';
    return '<div class="uv-map-tile" style="--intensity:' + intensity + ';" onclick="uvFilterByCountry(\''+c.co+'\')">' +
      '<div class="uv-map-flag">' + flag + '</div>' +
      '<div class="uv-map-name">' + uvEsc(c.cn) + '</div>' +
      '<div class="uv-map-mc">' + uvFmtBn(c.mc) + '</div>' +
      '<div class="uv-map-count">' + c.count.toLocaleString() + ' securities</div>' +
      (c.tier1 > 0 ? '<div class="uv-map-tier">' + c.tier1 + ' mega</div>' : '') +
    '</div>';
  }).join('');
}
function uvFilterByCountry(co) {
  uvState.filters.country = co;
  document.getElementById('uv-country').value = co;
  uvState.view = 'table';
  uvSetView('table', null);
  uvState.page = 1;
  uvRender();
}

// === Sectors view ===
function uvRenderSectors() {
  const grid = document.getElementById('uv-sectors-grid'); if (!grid) return;
  const bySec = {};
  uvState.filtered.forEach(s => {
    if (!bySec[s.sec]) bySec[s.sec] = { sec: s.sec, count: 0, mc: 0, top: [] };
    bySec[s.sec].count++;
    bySec[s.sec].mc += s.mc;
    if (bySec[s.sec].top.length < 3) bySec[s.sec].top.push(s);
  });
  const sorted = Object.values(bySec).sort((a,b) => b.mc - a.mc);
  const maxMc = sorted[0]?.mc || 1;
  const sectorIcons = {
    'Technology':'💻','Financials':'🏦','Healthcare':'💊','Consumer Discretionary':'🛍️',
    'Consumer Staples':'🛒','Industrials':'🏭','Energy':'⛽','Materials':'⚒️',
    'Communication Services':'📡','Utilities':'💡','Real Estate':'🏢'
  };
  grid.innerHTML = sorted.map(s => {
    const pct = (s.mc / maxMc * 100).toFixed(0);
    return '<div class="uv-sector-tile" onclick="uvFilterBySector(\''+s.sec.replace(/[\\\']/g,'')+'\')">' +
      '<div class="uv-sector-head">' +
        '<span class="uv-sector-icon">' + (sectorIcons[s.sec]||'📊') + '</span>' +
        '<span class="uv-sector-name">' + uvEsc(s.sec) + '</span>' +
      '</div>' +
      '<div class="uv-sector-mc">' + uvFmtBn(s.mc) + '</div>' +
      '<div class="uv-sector-bar"><div style="width:' + pct + '%;"></div></div>' +
      '<div class="uv-sector-count">' + s.count.toLocaleString() + ' securities</div>' +
      '<div class="uv-sector-top">' +
        s.top.map(t => '<div class="uv-sector-top-item"><span>' + uvEsc(t.t) + '</span><span class="uv-mono">' + uvFmtBn(t.mc) + '</span></div>').join('') +
      '</div>' +
    '</div>';
  }).join('');
}
function uvFilterBySector(sec) {
  uvState.filters.sector = sec;
  document.getElementById('uv-sector').value = sec;
  uvState.view = 'table';
  uvSetView('table', null);
  uvRender();
}

// === Movers view ===
function uvRenderMovers() {
  const grid = document.getElementById('uv-movers-grid'); if (!grid) return;
  // Use filtered universe; rank by live change% if available, else by momentum
  const withLive = uvState.filtered.map(s => {
    const live = uvState.liveQuotes[s.t];
    return { s, ch: live ? live.change : (s.mom - 50)/8, px: live ? live.price : null };
  });
  const gainers = withLive.slice().sort((a,b) => b.ch - a.ch).slice(0, 10);
  const losers  = withLive.slice().sort((a,b) => a.ch - b.ch).slice(0, 10);
  const renderList = (arr, title, color) =>
    '<div class="uv-mover-col">' +
      '<div class="uv-mover-title" style="color:' + color + ';">' + title + '</div>' +
      arr.map((x, i) => {
        const flag = UNIVERSE_FLAGS[x.s.co] || '🏳️';
        return '<div class="uv-mover-row" onclick="uvOpenStock(\''+x.s.t.replace(/[\\\']/g,'')+'\')">' +
          '<span class="uv-mover-idx">#' + (i+1) + '</span>' +
          '<span class="uv-mover-tkr">' + uvEsc(x.s.t) + '</span>' +
          '<span class="uv-mover-name">' + uvEsc(x.s.n) + '</span>' +
          '<span class="uv-mover-flag">' + flag + '</span>' +
          '<span class="uv-mover-mc">' + uvFmtBn(x.s.mc) + '</span>' +
          '<span class="uv-mover-ch ' + (x.ch>=0?'uv-up':'uv-down') + '">' + (x.ch>=0?'+':'') + x.ch.toFixed(2) + '%</span>' +
        '</div>';
      }).join('') +
    '</div>';
  grid.innerHTML = renderList(gainers, '🚀 TOP GAINERS', 'var(--green)') + renderList(losers, '🔻 TOP LOSERS', 'var(--red)');
}

// View switcher
function uvSetView(view, btn) {
  uvState.view = view;
  document.querySelectorAll('.uv-tab').forEach(t => t.classList.toggle('active', t.dataset.view === view));
  ['table','cards','map','sectors','movers'].forEach(v => {
    const el = document.getElementById('uv-view-' + v);
    if (el) el.classList.toggle('hidden', v !== view);
  });
  uvRender();
}

// Filter panel handlers
function uvFilter() {
  const g = id => { const el = document.getElementById(id); return el ? el.value : ''; };
  uvState.filters.search  = g('uv-search');
  uvState.filters.region  = g('uv-region');
  uvState.filters.country = g('uv-country');
  uvState.filters.sector  = g('uv-sector');
  uvState.filters.tier    = g('uv-tier');
  uvState.filters.mcap    = g('uv-mcap-filter');
  const ps = document.getElementById('uv-page-size');
  if (ps) uvState.pageSize = parseInt(ps.value) || uvState.pageSize;
  uvState.page = 1;
  // Server-mode: non-stock asset types are fetched from the registry API
  if (uvState.serverMode && typeof _UV_SERVER_TYPES !== 'undefined' && _UV_SERVER_TYPES.has(uvState.filters.assetType)) {
    const q = uvState.filters.search || '';
    if (typeof _uvServerCache !== 'undefined') _uvServerCache.delete(uvState.filters.assetType + '|' + q);
    if (typeof _uvLoadServerAssets === 'function') _uvLoadServerAssets(uvState.filters.assetType, q);
    return;
  }
  uvRender();
}
let _uvSearchTimer = 0;
function uvFilterDebounced() {
  clearTimeout(_uvSearchTimer);
  _uvSearchTimer = setTimeout(uvFilter, 300);
}

// ════════════════════════════════════════════════════════════════
//  GOOGLE-STYLE FINANCIAL SEARCH ENGINE — Autocomplete + Discovery
// ════════════════════════════════════════════════════════════════
let _uvAcTimer = 0;
let _uvAcCache = new Map(); // query → results[]
let _uvAcCtrl = null;       // AbortController for in-flight requests
let _uvAcIdx = -1;          // keyboard selected index

const _UV_TYPE_ICONS = { stock:'📈', etf:'🏦', crypto:'₿', forex:'💱', index:'📊', commodity:'🛢️' };
const _UV_TYPE_COLORS = { stock:'var(--accent)', etf:'#22d3ee', crypto:'#f59e0b', forex:'#4ade80', index:'#f87171', commodity:'#fb923c' };

function uvAcDebounced(q) {
  clearTimeout(_uvAcTimer);
  if (!q || q.trim().length < 1) { uvAcHide(); return; }
  _uvAcTimer = setTimeout(() => uvAutoComplete(q.trim()), 180);
}

async function uvAutoComplete(q) {
  if (!q) { uvAcHide(); return; }
  const dd = document.getElementById('uv-ac-dropdown');
  if (!dd) return;

  // Local universe quick match (instant, no network)
  const localHits = [];
  if (typeof UNIVERSE !== 'undefined') {
    const ql = q.toLowerCase();
    for (let i = 0; i < UNIVERSE.length && localHits.length < 5; i++) {
      const s = UNIVERSE[i];
      if ((s.t||'').toLowerCase().startsWith(ql) || (s.n||'').toLowerCase().startsWith(ql)) {
        localHits.push({ ticker: s.t, name: s.n, asset_type: 'stock', market_cap: (s.mc||0)*1e9, _local: true, _obj: s });
      }
    }
  }

  // Show local results immediately while fetching from server
  if (localHits.length) uvAcRender(q, localHits, true);

  // Check cache
  if (_uvAcCache.has(q)) { uvAcRender(q, _uvAcCache.get(q), false); return; }

  // Abort previous
  if (_uvAcCtrl) _uvAcCtrl.abort();
  _uvAcCtrl = new AbortController();

  try {
    const qs = new URLSearchParams({ q, limit: 10 });
    if (uvState.filters.assetType) qs.set('type', uvState.filters.assetType);
    const res = await fetch('/api/assets/search?' + qs, { credentials: 'include', signal: _uvAcCtrl.signal });
    if (!res.ok) return;
    const data = await res.json();
    const results = (data.results || []).slice(0, 10);
    _uvAcCache.set(q, results);
    uvAcRender(q, results, false);
  } catch (e) {
    if (e.name !== 'AbortError' && localHits.length === 0) uvAcRender(q, [], false);
  }
}

function uvAcRender(q, results, isLocal) {
  const dd = document.getElementById('uv-ac-dropdown');
  if (!dd) return;
  _uvAcIdx = -1;

  const fmtMc = mc => {
    if (!mc || mc < 1e6) return '';
    if (mc >= 1e12) return '$' + (mc/1e12).toFixed(2) + 'T';
    if (mc >= 1e9)  return '$' + (mc/1e9).toFixed(1) + 'B';
    return '$' + (mc/1e6).toFixed(0) + 'M';
  };

  const rows = results.map((r, i) => {
    const ticker = r.ticker || (r.id||'').split(':')[0] || '';
    const name = r.name || '';
    const atype = r.asset_type || 'stock';
    const icon = _UV_TYPE_ICONS[atype] || '📈';
    const color = _UV_TYPE_COLORS[atype] || 'var(--accent)';
    const mc = fmtMc(r.market_cap);
    const exch = r.exchange ? `<span style="font-size:9px;color:var(--text-muted);margin-left:4px;">· ${uvEsc(r.exchange)}</span>` : '';
    return `<div class="uv-ac-row" data-idx="${i}" onclick="uvAcPick(${JSON.stringify(ticker)},${JSON.stringify(name)},${JSON.stringify(r.id||ticker)},${JSON.stringify(atype)})" style="display:flex;align-items:center;gap:10px;padding:10px 14px;cursor:pointer;border-bottom:1px solid rgba(255,255,255,0.04);transition:background 80ms;" onmouseenter="uvAcHover(this)" onmouseleave="this.style.background=''">
      <span style="font-size:15px;width:22px;text-align:center;flex-shrink:0;">${icon}</span>
      <div style="flex:1;min-width:0;">
        <div style="font-family:var(--font-mono);font-size:13px;font-weight:700;color:var(--text-primary);">${uvEsc(ticker)}${exch}</div>
        <div style="font-size:11px;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:260px;">${uvEsc(name)}</div>
      </div>
      ${mc ? `<span style="font-size:11px;color:var(--text-muted);font-family:var(--font-mono);white-space:nowrap;">${mc}</span>` : ''}
      <span style="font-size:9px;font-family:var(--font-mono);padding:2px 7px;border-radius:4px;background:rgba(255,255,255,0.06);color:${color};text-transform:uppercase;flex-shrink:0;">${atype}</span>
    </div>`;
  }).join('');

  const footer = `<div onclick="uvTriggerDiscover(${JSON.stringify(q)})" style="display:flex;align-items:center;gap:8px;padding:10px 14px;cursor:pointer;background:rgba(167,139,250,0.04);border-top:1px solid rgba(167,139,250,0.1);transition:background 80ms;" onmouseenter="this.style.background='rgba(167,139,250,0.10)'" onmouseleave="this.style.background='rgba(167,139,250,0.04)'">
    <span style="font-size:12px;">🌐</span>
    <span style="font-size:12px;color:var(--accent-2);">Search global universe for "<strong>${uvEsc(q)}</strong>"</span>
    <span style="margin-left:auto;font-size:10px;font-family:var(--font-mono);color:var(--text-muted);">100M+ ENTITIES</span>
  </div>`;

  const loading = isLocal ? `<div style="padding:6px 14px;font-size:10px;font-family:var(--font-mono);color:var(--text-muted);letter-spacing:.06em;border-bottom:1px solid var(--border);">⚡ LOCAL · fetching global…</div>` : '';
  const header = results.length ? `<div style="padding:5px 14px 3px;font-size:9px;font-family:var(--font-mono);color:var(--text-muted);letter-spacing:.1em;background:rgba(255,255,255,0.02);">MATCHES — ${results.length} RESULT${results.length!==1?'S':''}</div>` : '';
  const empty = !results.length && !isLocal ? `<div style="padding:14px;text-align:center;font-size:12px;color:var(--text-muted);">No results — try the global search below</div>` : '';

  dd.innerHTML = loading + header + rows + empty + footer;
  dd.style.display = '';
}

function uvAcHide() {
  const dd = document.getElementById('uv-ac-dropdown');
  if (dd) dd.style.display = 'none';
  _uvAcIdx = -1;
}

function uvAcHover(el) {
  el.closest('#uv-ac-dropdown')?.querySelectorAll('.uv-ac-row').forEach((r,i) => { r.style.background = ''; });
  el.style.background = 'rgba(167,139,250,0.10)';
}

function uvAcKeyDown(e) {
  const dd = document.getElementById('uv-ac-dropdown');
  if (!dd || dd.style.display === 'none') return;
  const rows = Array.from(dd.querySelectorAll('.uv-ac-row'));
  if (!rows.length) return;
  if (e.key === 'ArrowDown') {
    e.preventDefault();
    _uvAcIdx = Math.min(_uvAcIdx + 1, rows.length - 1);
    rows.forEach((r,i) => r.style.background = i === _uvAcIdx ? 'rgba(167,139,250,0.12)' : '');
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    _uvAcIdx = Math.max(_uvAcIdx - 1, 0);
    rows.forEach((r,i) => r.style.background = i === _uvAcIdx ? 'rgba(167,139,250,0.12)' : '');
  } else if (e.key === 'Enter' && _uvAcIdx >= 0) {
    e.preventDefault();
    rows[_uvAcIdx]?.click();
  } else if (e.key === 'Escape') {
    uvAcHide();
  }
}

function uvAcPick(ticker, name, assetId, assetType) {
  uvAcHide();
  const inp = document.getElementById('uv-search');
  if (inp) inp.value = ticker;

  // Try to find in local universe first
  if (typeof UNIVERSE !== 'undefined' && typeof _searchOpenStock === 'function') {
    const local = _uvTickerMap.size > 0 ? _uvTickerMap.get(ticker) : UNIVERSE.find(s => s.t === ticker);
    if (local) { _searchOpenStock(local); return; }
  }

  // For server registry assets, fetch the full asset record
  if (assetId && typeof _showStockDetailModal === 'function') {
    _uvOpenServerAsset(assetId, ticker, name, assetType);
    return;
  }

  // Fallback: use filter to show this asset in the table
  if (inp) uvFilter();
}

async function _uvOpenServerAsset(assetId, ticker, name, assetType) {
  try {
    const res = await fetch('/api/assets/' + encodeURIComponent(assetId), { credentials: 'include' });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const row = await res.json();
    if (row && typeof _uvAdaptServerRow === 'function') {
      const adapted = _uvAdaptServerRow(row);
      if (typeof _showStockDetailModalFromLocal === 'function') _showStockDetailModalFromLocal(adapted);
    }
  } catch (_) {
    // Fallback: set search and filter to show this asset
    const inp = document.getElementById('uv-search');
    if (inp) { inp.value = ticker; uvFilter(); }
  }
}

let _uvDiscoverTimer = 0;
async function uvTriggerDiscover(q) {
  uvAcHide();
  const dd = document.getElementById('uv-ac-dropdown');
  if (dd) {
    dd.style.display = '';
    dd.innerHTML = `<div style="padding:16px 14px;display:flex;align-items:center;gap:10px;"><span style="font-size:14px;animation:spin 1s linear infinite;display:inline-block;">⟳</span><span style="font-size:12px;color:var(--accent-2);font-family:var(--font-mono);">Searching global financial universe…</span></div>`;
  }

  try {
    const res = await fetch('/api/assets/discover', {
      method: 'POST',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ query: q }),
    });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const row = await res.json();
    if (row && row.ticker) {
      // Invalidate AC cache so the new result appears
      _uvAcCache.clear();
      // Fetch fresh search results
      const sr = await fetch('/api/assets/search?q=' + encodeURIComponent(q) + '&limit=10', { credentials: 'include' });
      const data = await sr.json();
      const results = data.results || [];
      if (results.length) uvAcRender(q, results, false);
      else if (dd) { dd.style.display = 'none'; }
    } else if (dd) {
      dd.innerHTML = `<div style="padding:14px;text-align:center;font-size:12px;color:var(--text-muted);">Asset not found in any provider. Try a different query.</div>`;
    }
  } catch (e) {
    if (dd) dd.innerHTML = `<div style="padding:14px;text-align:center;font-size:12px;color:var(--red);">Discovery failed — check connection.</div>`;
  }
}

// Global server search — called when local results are empty
let _uvServerSearchLast = '';
async function uvServerSearch(q, assetType) {
  if (!q) return;
  if (_uvServerSearchLast === q + '|' + assetType) return; // dedupe
  _uvServerSearchLast = q + '|' + assetType;

  const tb = document.getElementById('uv-tbody');
  if (!tb) return;

  tb.innerHTML = `<tr><td colspan="12" style="padding:40px;text-align:center;font-family:var(--font-mono);font-size:12px;color:var(--text-muted);">
    <div style="display:flex;align-items:center;justify-content:center;gap:8px;">
      <span style="animation:spin 1s linear infinite;display:inline-block;">⟳</span>
      SEARCHING GLOBAL REGISTRY…
    </div>
  </td></tr>`;

  try {
    const qs = new URLSearchParams({ q, limit: 50 });
    if (assetType) qs.set('type', assetType);
    const res = await fetch('/api/assets/search?' + qs, { credentials: 'include' });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const data = await res.json();
    const adapted = (data.results || []).map(_uvAdaptServerRow);
    if (adapted.length) {
      // Inject into filtered state so regular render picks them up
      uvState.filtered = adapted;
      uvRenderTable();
      const infoEl = document.getElementById('uv-page-info');
      if (infoEl) infoEl.textContent = '🌐 Global registry: 1–' + adapted.length + ' of ' + (data.total || adapted.length).toLocaleString() + ' results';
    } else {
      // Try discovery as last resort
      tb.innerHTML = `<tr><td colspan="12" style="padding:40px;text-align:center;">
        <div style="font-size:13px;color:var(--text-muted);margin-bottom:12px;">Not found in registry — trying live discovery…</div>
        <button class="btn btn-secondary btn-sm" onclick="uvTriggerDiscover(${JSON.stringify(q)})">🌐 Discover from market data providers</button>
      </td></tr>`;
      // Auto-trigger discovery for unknown tickers
      uvTriggerDiscover(q);
    }
  } catch (e) {
    if (tb) tb.innerHTML = `<tr><td colspan="12" style="padding:40px;text-align:center;color:var(--red);font-size:12px;">Registry search error: ${uvEsc(e.message)}</td></tr>`;
  } finally {
    _uvServerSearchLast = ''; // allow retry
  }
}

function uvClearFilters() {
  ['uv-search','uv-region','uv-country','uv-sector','uv-tier','uv-mcap-filter'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  const ro = document.getElementById('uv-real-only'); if (ro) ro.checked = true;
  uvState.filters = { search:'', region:'', country:'', sector:'', tier:'', mcap:'' };
  uvState.page = 1;
  uvRender();
}
function uvPage(delta) {
  const total = Math.max(1, Math.ceil(uvState.filtered.length / uvState.pageSize));
  uvState.page = Math.max(1, Math.min(total, uvState.page + delta));
  uvRender();
}

// Sort
function uvSort(key) {
  if (uvState.sortKey === key) uvState.sortDir = uvState.sortDir === 'asc' ? 'desc' : 'asc';
  else {
    uvState.sortKey = key;
    uvState.sortDir = ['gr','t','n','cn','ex','sec','ind','cur'].includes(key) ? 'asc' : 'desc';
  }
  uvState.page = 1;
  uvRender();
}
function uvBindSort() {
  document.querySelectorAll('#uv-main-table thead th[data-sort], .uv-table thead th[data-sort]').forEach(th => {
    th.addEventListener('click', () => uvSort(th.dataset.sort));
  });
}

function uvPopulateCountryFilter() {
  const sel = document.getElementById('uv-country'); if (!sel || sel.options.length > 1) return;
  if (typeof UNIVERSE === 'undefined') return;
  const counts = {};
  UNIVERSE.forEach(s => { counts[s.co] = (counts[s.co]||0) + 1; });
  Object.entries(counts).sort((a,b) => b[1]-a[1]).forEach(([co, n]) => {
    const opt = document.createElement('option');
    opt.value = co;
    opt.textContent = (UNIVERSE_FLAGS[co]||'') + '  ' + (UNIVERSE_COUNTRIES[co]?.n || co) + '  (' + n.toLocaleString() + ')';
    sel.appendChild(opt);
  });
  uvState.populatedCountryFilter = true;
}

// Open stock detail — reuses the existing stock detail modal
function uvOpenStock(ticker) {
  if (typeof UNIVERSE === 'undefined') return;
  const s = (_uvTickerMap.size > 0 ? _uvTickerMap.get(ticker) : UNIVERSE.find(x => x.t === ticker)); if (!s) return;
  if (typeof _searchOpenStock === 'function') _searchOpenStock(s);
  else if (typeof _showStockDetailModalFromLocal === 'function') _showStockDetailModalFromLocal(s);
  else uvQuickPanel(ticker);
}

// ── QUICK PANEL — slide-up stock preview ──
window._uvWatchlist = JSON.parse(localStorage.getItem('qe_watchlist') || '[]');

function uvQuickPanel(ticker) {
  if (typeof UNIVERSE === 'undefined') return;
  const s = (_uvTickerMap.size > 0 ? _uvTickerMap.get(ticker) : UNIVERSE.find(x => x.t === ticker)); if (!s) return;
  const live = uvState.liveQuotes[s.t] || {};
  const price = live.price;
  const chg   = live.change || 0;
  const flag  = UNIVERSE_FLAGS[s.co] || '';
  const sigScore = (s.mom||0)*0.6 + (s.qua||0)*0.4;
  const sigCls = sigScore>=68?'uv3-sig-buy':sigScore<42?'uv3-sig-sell':'uv3-sig-hold';
  const sigLbl = sigScore>=68?'▲ BUY':sigScore<42?'▼ SELL':'● HOLD';
  const inWatch = window._uvWatchlist.includes(ticker);

  const setText = (id, v) => { const el = document.getElementById(id); if (el) el.textContent = v; };
  setText('uvqp-ticker', flag + ' ' + s.t);
  setText('uvqp-name',   s.n + '  ·  ' + s.cn + '  ·  ' + s.ex);
  setText('uvqp-price',  price ? ('$' + price.toFixed(2)) : 'N/A');
  setText('uvqp-mc',     uvFmtBn(s.mc));
  setText('uvqp-sec',    s.sec.replace('Consumer ','').replace(' Services',''));
  setText('uvqp-pe',     s.pe || '—');
  setText('uvqp-mom',    (s.mom || 0) + ' / 100');

  const chgEl = document.getElementById('uvqp-chg');
  if (chgEl) {
    chgEl.textContent = (chg >= 0 ? '+' : '') + chg.toFixed(2) + '%';
    chgEl.style.color = chg >= 0 ? 'var(--green)' : 'var(--red)';
  }
  const sigEl = document.getElementById('uvqp-sig');
  if (sigEl) { sigEl.textContent = sigLbl; sigEl.className = 'uvqp-stat-val uv3-sig ' + sigCls; }

  const actEl = document.getElementById('uvqp-actions');
  if (actEl) {
    const wLabel = inWatch ? '★ Watching' : '☆ Watch';
    actEl.innerHTML =
      '<button class="btn btn-primary btn-sm" onclick="if(typeof _searchOpenStock===\'function\'){const h=UNIVERSE&&UNIVERSE.find(s=>s.t===\'' + ticker.replace(/'/g,"") + '\');if(h)_searchOpenStock(h);}uvCloseQuickPanel();">↗ Full Detail</button>' +
      '<button class="btn btn-ghost btn-sm" id="uvqp-watch-btn" onclick="uvToggleWatch(\'' + ticker.replace(/'/g,"") + '\',this)">' + wLabel + '</button>' +
      '<button class="btn btn-ghost btn-sm" onclick="uvCloseQuickPanel()">✕ Close</button>';
  }

  // Legal history strip
  const legalEl = document.getElementById('uvqp-legal');
  if (legalEl) {
    const lrecs = getCompanyLegalHistory(ticker);
    if (lrecs && lrecs.length) {
      const ongoing = lrecs.filter(r => r.status === 'Ongoing').length;
      const settled = lrecs.filter(r => r.status === 'Settled').length;
      legalEl.style.display = '';
      legalEl.innerHTML = '⚖ Legal: <b style="color:var(--text-primary);">' + lrecs.length + ' case' + (lrecs.length!==1?'s':'') + '</b>'
        + (ongoing ? ' · <span style="color:#F59E0B;">' + ongoing + ' ongoing</span>' : '')
        + (settled ? ' · <span style="color:#22C55E;">' + settled + ' settled</span>' : '')
        + ' · <a onclick="if(typeof _searchOpenStock===\'function\'){const h=UNIVERSE&&UNIVERSE.find(s=>s.t===\'' + ticker.replace(/'/g,'') + '\');if(h)_searchOpenStock(h);}uvCloseQuickPanel();" style="color:var(--violet);cursor:pointer;">View full detail ↗</a>';
    } else {
      legalEl.style.display = 'none';
      legalEl.innerHTML = '';
    }
  }

  const panel = document.getElementById('uv-quick-panel');
  if (panel) panel.classList.add('open');
}

function uvCloseQuickPanel() {
  const panel = document.getElementById('uv-quick-panel');
  if (panel) panel.classList.remove('open');
}

function uvToggleWatch(ticker, btn) {
  window._uvWatchlist = JSON.parse(localStorage.getItem('qe_watchlist') || '[]');
  const idx = window._uvWatchlist.indexOf(ticker);
  if (idx === -1) {
    window._uvWatchlist.push(ticker);
    if (btn) btn.textContent = '★ Watching';
  } else {
    window._uvWatchlist.splice(idx, 1);
    if (btn) btn.textContent = '☆ Watch';
  }
  localStorage.setItem('qe_watchlist', JSON.stringify(window._uvWatchlist));
  // Update all ☆/★ buttons for this ticker in the table
  document.querySelectorAll('.uv3-row-btn[onclick*="' + ticker + '"]').forEach(b => {
    if (b.title === 'Watchlist') b.textContent = window._uvWatchlist.includes(ticker) ? '★' : '☆';
  });
}

// Presets
const UV_PRESETS = {
  TOP_100_GLOBAL:    { f: s => s.gr <= 100,  l: 'TOP 100 Global' },
  TOP_500_GLOBAL:    { f: s => s.gr <= 500,  l: 'TOP 500 Global' },
  TOP_1000_GLOBAL:   { f: s => s.gr <= 1000, l: 'TOP 1000 Global' },
  TOP_5000_GLOBAL:   { f: s => s.gr <= 5000, l: 'TOP 5000 Global' },
  USA_TOP_3000:      { f: s => s.co==='US' && s.cr<=3000, l:'USA TOP 3000' },
  CHINA_TOP_1500:    { f: s => (s.co==='CN'||s.co==='HK') && s.cr<=1500, l:'China TOP 1500' },
  INDIA_TOP_1000:    { f: s => s.co==='IN' && s.cr<=1000, l:'India TOP 1000' },
  JAPAN_TOP_1000:    { f: s => s.co==='JP' && s.cr<=1000, l:'Japan TOP 1000' },
  EUROPE_TOP_2000:   { f: s => s.reg==='Europe' && s.cr<=2000, l:'Europe TOP 2000' },
  KOREA_TOP_500:     { f: s => s.co==='KR' && s.cr<=500, l:'Korea TOP 500' },
  TAIWAN_TOP_500:    { f: s => s.co==='TW' && s.cr<=500, l:'Taiwan TOP 500' },
  CANADA_TOP_500:    { f: s => s.co==='CA' && s.cr<=500, l:'Canada TOP 500' },
  BRAZIL_TOP_300:    { f: s => s.co==='BR' && s.cr<=300, l:'Brazil TOP 300' },
  AUSTRALIA_TOP_500: { f: s => s.co==='AU' && s.cr<=500, l:'Australia TOP 500' },
  MIDDLE_EAST_TOP_500: { f: s => s.reg==='Middle East' && s.cr<=500, l:'Middle East TOP 500' }
};
function uvApplyPreset(name) {
  const p = UV_PRESETS[name]; if (!p) return;
  uvClearFilters();
  // Use the preset filter as a custom override on uvState.filtered
  uvState.filtered = UNIVERSE.filter(p.f);
  // Sort
  const k = uvState.sortKey, dir = uvState.sortDir==='asc'?1:-1;
  uvState.filtered.sort((a,b) => { const av=a[k], bv=b[k]; return typeof av==='string' ? av.localeCompare(bv)*dir : ((av||0)-(bv||0))*dir; });
  uvState.page = 1;
  // Manual re-render bypassing filter recompute
  uvUpdateHero();
  uvUpdateChips();
  uvUpdateSortIndicators();
  if (uvState.view === 'table')   uvRenderTable();
  if (uvState.view === 'cards')   uvRenderCards();
  if (uvState.view === 'map')     uvRenderMap();
  if (uvState.view === 'sectors') uvRenderSectors();
  if (uvState.view === 'movers')  uvRenderMovers();
}

// Exports
function uvExport(fmt) {
  const rows = (uvState.filtered.length ? uvState.filtered : (typeof UNIVERSE !== 'undefined' ? UNIVERSE : []));
  if (rows.length === 0) { alert('Nothing to export.'); return; }
  if (fmt === 'csv') {
    const headers = ['GlobalRank','CountryRank','Company','Ticker','Exchange','Country','Region','Sector','Industry','MarketCapUSD','EnterpriseValueUSD','AvgDailyVolume','FreeFloat','Currency','ISIN','Tier','Beta','PE','DivYield','RevGrowth','EarnGrowth','Momentum','Quality','Vol30'];
    const esc = v => v==null ? '' : (/[",\n]/.test(String(v)) ? '"'+String(v).replace(/"/g,'""')+'"' : String(v));
    const csv = [headers.join(',')].concat(rows.map(s => [s.gr,s.cr,s.n,s.t,s.ex,s.cn,s.reg,s.sec,s.ind,(s.mc*1e9).toFixed(0),(s.ev*1e9).toFixed(0),(s.vol*1e6).toFixed(0),s.ff,s.cur,s.isin,s.tier,s.beta,s.pe,s.dy,s.rg,s.eg,s.mom,s.qua,s.vol30].map(esc).join(','))).join('\n');
    uvDownload('quantedge_universe.csv', csv, 'text/csv');
  } else if (fmt === 'json') {
    const jsonl = rows.map(s => JSON.stringify({ global_rank:s.gr, country_rank:s.cr, company:s.n, ticker:s.t, exchange:s.ex, country:s.cn, country_code:s.co, region:s.reg, sector:s.sec, industry:s.ind, market_cap_usd:s.mc*1e9, enterprise_value_usd:s.ev*1e9, avg_daily_volume:s.vol*1e6, free_float_pct:s.ff, currency:s.cur, isin:s.isin, tier:s.tier, factors:{ beta:s.beta, pe:s.pe, div_yield:s.dy, revenue_growth:s.rg, earnings_growth:s.eg, momentum:s.mom, quality:s.qua, vol_30d:s.vol30 } })).join('\n');
    uvDownload('quantedge_universe.jsonl', jsonl, 'application/x-ndjson');
  } else if (fmt === 'sql') {
    const sqlEsc = v => v==null ? 'NULL' : typeof v === 'number' ? v : ("'" + String(v).replace(/'/g, "''") + "'");
    let out = '-- Quant Entelloq Universe Snapshot ' + new Date().toISOString() + '\n';
    out += 'BEGIN;\n';
    out += rows.slice(0, 5000).map(s => 'INSERT INTO qe_universe VALUES (' + [s.gr,s.cr,sqlEsc(s.n),sqlEsc(s.t),sqlEsc(s.ex),sqlEsc(s.cn),sqlEsc(s.co),sqlEsc(s.reg),sqlEsc(s.sec),sqlEsc(s.ind),(s.mc*1e9).toFixed(0),(s.ev*1e9).toFixed(0),(s.vol*1e6).toFixed(0),s.ff,sqlEsc(s.cur),sqlEsc(s.isin),s.tier,s.beta,s.pe||'NULL',s.dy,s.rg,s.eg,s.mom,s.qua,s.vol30].join(',') + ');').join('\n');
    out += '\nCOMMIT;\n';
    uvDownload('quantedge_universe.sql', out, 'application/sql');
  }
}
function uvDownload(name, content, mime) {
  const blob = new Blob([content], { type: mime || 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a'); a.href = url; a.download = name;
  document.body.appendChild(a); a.click(); a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1500);
}

// Live refresh — best-effort via Yahoo v8 chart through proxies; falls back gracefully
async function uvRefreshLive() {
  const btn = document.getElementById('uv-refresh-btn');
  const status = document.getElementById('uv-live-status');
  const loader = document.getElementById('uv-loader');
  if (loader) loader.classList.add('active');
  if (btn) { btn.disabled = true; btn.textContent = '⟳ Syncing…'; }

  // ── Path A: Polygon.io (best quality) ──
  if (window.PolygonAPI && window.PolygonAPI.isConfigured()) {
    if (status) status.textContent = 'SYNCING POLYGON.IO…';
    await uvEnrichWithPolygon();
    if (loader) loader.classList.remove('active');
    if (btn) { btn.disabled = false; btn.textContent = '⟳ Sync Live'; }
    return;
  }

  // ── Path B: Yahoo Finance via allorigins proxy ──
  if (status) status.textContent = 'FETCHING YAHOO…';
  const pool = (uvState.filtered.length ? uvState.filtered : UNIVERSE || [])
    .filter(s => !s._synth)
    .slice(0, 20);
  const syms = pool.map(s => s.t).join(',');
  let fetched = 0;
  try {
    const url = `https://query1.finance.yahoo.com/v7/finance/quote?symbols=${encodeURIComponent(syms)}&fields=regularMarketPrice,regularMarketChangePercent`;
    const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`;
    const res = await fetch(proxyUrl, { signal: AbortSignal.timeout ? AbortSignal.timeout(10000) : undefined });
    if (res.ok) {
      const j = await res.json();
      const raw = j.contents ? JSON.parse(j.contents) : null;
      const quotes = raw?.quoteResponse?.result || [];
      quotes.forEach(q => {
        if (q.regularMarketPrice) {
          uvState.liveQuotes[q.symbol] = {
            price: q.regularMarketPrice,
            change: q.regularMarketChangePercent || 0,
            ts: Date.now(),
            simulated: false,
            source: 'yahoo',
          };
          fetched++;
        }
      });
    }
  } catch (_) {}

  if (loader) loader.classList.remove('active');
  if (btn) { btn.disabled = false; btn.textContent = '⟳ Sync Live'; }
  if (status) status.textContent = fetched > 0
    ? `YAHOO FINANCE — ${fetched} real quotes`
    : 'SIMULATED — add Polygon key for full coverage';
  if (fetched > 0) uvSyncRealPrices();
  uvRender();
}

// === Universal Live Tick — seeds all 10K with simulated prices, ticks 1.5%/4.5s ===
function uvSeedLiveQuotes() {
  if (typeof UNIVERSE === 'undefined') return;
  // Seed visible (non-synth) companies immediately, defer synthetics
  const seedNow = UNIVERSE.filter(s => !s._synth);
  for (let i = 0; i < seedNow.length; i++) {
    const s = seedNow[i];
    if (uvState.liveQuotes[s.t]) continue;
    let basePx;
    if (s.mc >= 100) basePx = 50 + Math.sqrt(s.mc) * 6;
    else if (s.mc >= 10) basePx = 20 + Math.sqrt(s.mc) * 8;
    else basePx = 5 + Math.sqrt(s.mc) * 12;
    const seed = (s.t || '').split('').reduce((a, c) => a + c.charCodeAt(0), 0) || 1;
    basePx = basePx * (0.7 + ((seed * 13) % 100) / 100 * 0.6);
    uvState.liveQuotes[s.t] = { price: +basePx.toFixed(2), change: +(((seed * 7) % 800 - 400) / 100).toFixed(2), ts: Date.now(), simulated: true };
  }
  // Seed synthetics lazily in chunks
  const synths = UNIVERSE.filter(s => s._synth);
  let idx = 0;
  function seedChunk() {
    const end = Math.min(idx + 300, synths.length);
    for (; idx < end; idx++) {
      const s = synths[idx];
      if (uvState.liveQuotes[s.t]) continue;
      let basePx = 5 + Math.sqrt(s.mc) * 12;
      const seed2 = (s.t || '').split('').reduce((a, c) => a + c.charCodeAt(0), 0) || 1;
      basePx = basePx * (0.7 + ((seed2 * 13) % 100) / 100 * 0.6);
      uvState.liveQuotes[s.t] = { price: +basePx.toFixed(2), change: +(((seed2 * 7) % 800 - 400) / 100).toFixed(2), ts: Date.now(), simulated: true };
    }
    if (idx < synths.length) setTimeout(seedChunk, 50);
  }
  if (synths.length) setTimeout(seedChunk, 100);
}
function uvLiveTick() {
  // Skip entirely for logged-out visitors — the universe panel lives behind auth.
  if (!window.QZ_isAuthed || !window.QZ_isAuthed()) return;
  if (typeof UNIVERSE === 'undefined') return;

  // Build pool from only the rows currently rendered (visible page, max 100 rows).
  // This ensures we never iterate 100K quote objects on every tick.
  const visibleRows = document.querySelectorAll('#uv-tbody tr[data-ticker]');
  const pool = [];
  visibleRows.forEach(r => {
    const q = uvState.liveQuotes[r.dataset.ticker];
    if (q && q.simulated) pool.push(r.dataset.ticker);
  });

  // Fallback: random sample from all simulated quotes when table not in view
  if (pool.length === 0) {
    const keys = Object.keys(uvState.liveQuotes);
    const n = Math.min(20, keys.length);
    for (let i = 0; i < n; i++) {
      const t = keys[Math.floor(Math.random() * keys.length)];
      if (uvState.liveQuotes[t]?.simulated) pool.push(t);
    }
    if (pool.length === 0) return;
  }

  // Tick up to 30% of visible rows (min 3, max 25) for a fluid feel
  const nUpdates = Math.min(pool.length, Math.max(3, Math.floor(pool.length * 0.3)));
  const domBatch = [];

  for (let i = 0; i < nUpdates; i++) {
    const t  = pool[Math.floor(Math.random() * pool.length)];
    const q  = uvState.liveQuotes[t]; if (!q || !q.simulated) continue;
    // O(1) Map lookup — was O(n) UNIVERSE.find() scan
    const s  = _uvTickerMap.size > 0 ? _uvTickerMap.get(t) : null;
    const vol = (s ? s.vol30 : 25) / 100 || 0.25;
    const drift = (Math.random() - 0.5) * (vol / Math.sqrt(252)) * 4;
    const oldPx = q.price;
    q.price  = Math.max(0.01, +(q.price * (1 + drift)).toFixed(2));
    q.change = +((q.change + drift * 100) * 0.92).toFixed(2);
    q.ts     = Date.now();
    domBatch.push({ t, price: q.price, change: q.change, up: q.price >= oldPx });
  }

  if (domBatch.length === 0) return;

  // Batch all DOM writes into one animation frame — eliminates per-tick forced reflows
  requestAnimationFrame(() => {
    domBatch.forEach(({ t, price, change, up }) => {
      document.querySelectorAll('[data-ticker="' + t + '"]').forEach(row => {
        const pc = row.querySelector('.live-price-cell');
        const cc = row.querySelector('.live-chg-cell');
        if (pc) {
          pc.innerHTML = '<span class="' + (change >= 0 ? 'uv-up' : 'uv-down')
            + '" style="font-family:var(--font-mono);">$' + price.toFixed(2) + '</span>';
          // Replace flash class without void offsetWidth reflow
          pc.className = pc.className.replace(/\s*uv-flash-\w+/g, '')
            + (up ? ' uv-flash-up' : ' uv-flash-down');
        }
        if (cc) {
          cc.innerHTML = '<span class="' + (change >= 0 ? 'uv-up' : 'uv-down')
            + '" style="font-family:var(--font-mono);">'
            + (change >= 0 ? '+' : '') + change.toFixed(2) + '%</span>';
        }
      });
    });
  });
}

