  // === Holographic candlestick canvas — slow drift, low opacity ===
  function initTradingCanvas() {
    const cv = document.getElementById('qe-trading-canvas');
    if (!cv) return;
    const ctx = cv.getContext('2d');
    let candles = [];
    function resize() {
      cv.width = window.innerWidth;
      cv.height = window.innerHeight;
      candles = [];
      const cols = Math.ceil(cv.width / 14);
      let last = cv.height * 0.5;
      for (let i = 0; i < cols; i++) {
        const drift = (Math.random() - 0.5) * 30;
        const o = last;
        const c = last + drift;
        const wickHigh = Math.min(o, c) - Math.random() * 12;
        const wickLow  = Math.max(o, c) + Math.random() * 12;
        candles.push({ x: i * 14, o, c, h: wickHigh, l: wickLow, up: c < o });
        last = c;
        if (last < 80) last = 80 + Math.random() * 80;
        if (last > cv.height - 80) last = cv.height - 80 - Math.random() * 80;
      }
    }
    resize();
    window.addEventListener('resize', resize);
    let tick = 0;
    function frame() {
      tick++;
      ctx.clearRect(0, 0, cv.width, cv.height);
      candles.forEach((c, i) => {
        const wave = Math.sin((tick + i * 5) / 80) * 2;
        const cx = c.x;
        ctx.lineWidth = 1.2;
        ctx.strokeStyle = c.up ? 'rgba(124,58,237,0.18)' : 'rgba(255,71,87,0.16)';
        ctx.fillStyle  = c.up ? 'rgba(124,58,237,0.10)' : 'rgba(255,71,87,0.08)';
        ctx.beginPath(); ctx.moveTo(cx + 4, c.h + wave); ctx.lineTo(cx + 4, c.l + wave); ctx.stroke();
        const top = Math.min(c.o, c.c) + wave;
        const h = Math.abs(c.c - c.o);
        ctx.fillRect(cx, top, 8, h);
        ctx.strokeRect(cx, top, 8, h);
      });
      requestAnimationFrame(frame);
    }
    frame();
  }
