    const countries = { 'india':'IN','japan':'JP','china':'CN','usa':'US','united states':'US','britain':'GB','uk':'GB','germany':'DE','france':'FR','korea':'KR','taiwan':'TW','brazil':'BR','australia':'AU','saudi':'SA','canada':'CA','mexico':'MX','singapore':'SG','italy':'IT','spain':'ES','netherlands':'NL','switzerland':'CH' };
