        '.NS':'NSE', '.BO':'BSE', '.T':'TYO', '.HK':'HKG', '.SS':'SHA', '.SZ':'SHE',
        '.L':'LON', '.DE':'ETR', '.PA':'EPA', '.SW':'SWX', '.AS':'AMS', '.MI':'BIT',
