(function initAppAmbient() {
  // Ambient cursor glow inside the app
  const appEl = document.getElementById('app');
  if (!appEl) return;
  const glow = document.createElement('div');
  glow.id = 'qe-app-glow';
  glow.style.cssText = 'position:fixed;width:600px;height:600px;border-radius:50%;pointer-events:none;z-index:0;background:radial-gradient(circle,rgba(167,139,250,0.04) 0%,transparent 70%);filter:blur(60px);transform:translate(-50%,-50%);opacity:0;transition:opacity 0.8s ease;';
  document.body.appendChild(glow);

  let raf;
  document.addEventListener('mousemove', e => {
    const landing = document.getElementById('landing');
    const inApp = landing && (landing.classList.contains('hidden') || landing.style.display === 'none');
    if (!inApp) { glow.style.opacity = '0'; return; }
    glow.style.opacity = '1';
    if (raf) cancelAnimationFrame(raf);
    raf = requestAnimationFrame(() => {
      glow.style.left = e.clientX + 'px';
      glow.style.top = e.clientY + 'px';
    });
  }, {passive:true});

  // Dashboard card stagger entrance
  const origNav = window.navigate;
  if (typeof origNav === 'function') {
    window.navigate = function(page) {
      origNav.apply(this, arguments);
      setTimeout(() => {
        const main = document.querySelector('.main-content');
        if (!main) return;
        const cards = main.querySelectorAll('.metric-card, .signal-card, .chart-container, .market-card, .scanner-item, .news-item, .macro-card');
        cards.forEach((c, i) => {
          c.style.opacity = '0';
          c.style.transform = 'translateY(12px)';
          setTimeout(() => {
            c.style.transition = 'opacity 0.4s cubic-bezier(0.23,1,0.32,1), transform 0.4s cubic-bezier(0.23,1,0.32,1)';
            c.style.opacity = '1';
            c.style.transform = 'translateY(0)';
          }, 40 * i);
        });
      }, 80);
    };
  }

  // Live market pulse indicator on metric values
  const origTick = window.tickSimulation;
  if (typeof origTick === 'function') {
    window.tickSimulation = function() {
      origTick.apply(this, arguments);
      document.querySelectorAll('.metric-change.up').forEach(el => {
        el.closest('.metric-card')?.classList.add('up');
      });
    };
  }
})();

