(function initDoubleClap() {
  let audioCtx, analyser, dataArr, src;
  let lastClap = 0;
  let listening = false;
  const CLAP_THRESHOLD = 0.35;
  const DOUBLE_GAP_MIN = 80;
  const DOUBLE_GAP_MAX = 600;
  const COOLDOWN = 900;
  let lastTrigger = 0;
  let silenceFrames = 0;
  const SILENCE_NEEDED = 4;

  function onClap() {
    const now = Date.now();
    if (now - lastTrigger < COOLDOWN) return;
    const gap = now - lastClap;
    if (gap > DOUBLE_GAP_MIN && gap < DOUBLE_GAP_MAX) {
      lastTrigger = now;
      lastClap = 0;
      triggerQuantEdge();
    } else {
      lastClap = now;
    }
  }

  function triggerQuantEdge() {
    const panel = document.getElementById('qe-panel-static');
    const orb = document.getElementById('qe-orb-static');
    if (panel && !panel.classList.contains('open')) {
      panel.classList.add('open');
      if (orb) {
        orb.style.transform = 'scale(1.3)';
        orb.style.boxShadow = '0 0 40px rgba(167,139,250,0.8), 0 0 80px rgba(124,58,237,0.5)';
        setTimeout(() => { orb.style.transform = ''; orb.style.boxShadow = ''; }, 400);
      }
      const ripple = document.createElement('div');
      ripple.style.cssText = 'position:fixed;top:50%;left:50%;width:0;height:0;border-radius:50%;background:rgba(167,139,250,0.15);transform:translate(-50%,-50%);pointer-events:none;z-index:9999;';
      document.body.appendChild(ripple);
      ripple.animate([
        {width:'0px',height:'0px',opacity:0.6},
        {width:'200vw',height:'200vw',opacity:0}
      ], {duration:700,easing:'cubic-bezier(0.23,1,0.32,1)'}).onfinish = () => ripple.remove();
      setTimeout(() => { if (typeof qeStartListening === 'function') qeStartListening(); }, 300);
    } else if (panel && panel.classList.contains('open')) {
      if (typeof qeStartListening === 'function') qeStartListening();
    }
  }

  function detect() {
    if (!listening) return;
    requestAnimationFrame(detect);
    analyser.getByteTimeDomainData(dataArr);
    let peak = 0;
    for (let i = 0; i < dataArr.length; i++) {
      const v = Math.abs(dataArr[i] - 128) / 128;
      if (v > peak) peak = v;
    }
    if (peak > CLAP_THRESHOLD) {
      if (silenceFrames >= SILENCE_NEEDED) onClap();
      silenceFrames = 0;
    } else {
      silenceFrames++;
    }
  }

  async function startListening() {
    if (listening) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({audio:true});
      audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      analyser = audioCtx.createAnalyser();
      analyser.fftSize = 512;
      dataArr = new Uint8Array(analyser.fftSize);
      src = audioCtx.createMediaStreamSource(stream);
      src.connect(analyser);
      listening = true;
      detect();
    } catch(e) { /* mic denied — fail silently */ }
  }

  document.addEventListener('click', function initOnce() {
    startListening();
    document.removeEventListener('click', initOnce);
  }, {once:true});
  if (document.readyState === 'complete') startListening();
  else window.addEventListener('load', () => setTimeout(startListening, 2000));
})();

