// Top US tickers from UNIVERSE_SEED to enrich with real Polygon data
const UV_POLYGON_TICKERS = [
  'AAPL','NVDA','MSFT','AMZN','GOOGL','META','BRK.B','AVGO','LLY','TSLA',
  'JPM','WMT','V','XOM','UNH','MA','COST','ORCL','HD','PG','NFLX','JNJ',
  'BAC','ABBV','CRM','CVX','WFC','AMD','MRK','KO','CSCO','PEP','ACN','MCD',
  'TMUS','ADBE','MS','LIN','TXN','T','IBM','DIS','GE','CAT','RTX','GS',
  'CMCSA','VZ','INTC','PLTR','NOW','AMAT','LRCX','BKNG','UBER','SPOT',
  'ABNB','COIN','SNOW','PFE','AMGN','GILD','ISRG','MDT','TMO','ABT',
  'DHR','SYK','REGN','MRNA','BMY','CVS','CI','HUM','ELV','SPY','QQQ',
];

async function uvEnrichWithPolygon() {
  if (!window.PolygonAPI || !window.PolygonAPI.isConfigured()) return;
  const status = document.getElementById('uv-live-status');
  if (status) status.textContent = 'SYNCING POLYGON.IO…';
  try {
    const batchSize = 25;
    let enriched = 0;
    for (let i = 0; i < UV_POLYGON_TICKERS.length; i += batchSize) {
      const batch = UV_POLYGON_TICKERS.slice(i, i + batchSize);
      const snaps = await window.PolygonAPI.getMultiSnapshot(batch);
      if (!snaps) continue;
      snaps.forEach(s => {
        if (s.price && s.ticker) {
          uvState.liveQuotes[s.ticker] = {
            price: s.price,
            change: s.changePct || 0,
            prevClose: s.prevClose || 0,
            volume: s.volume || 0,
            high: s.high || 0,
            low: s.low || 0,
            ts: Date.now(),
            simulated: false,
            source: 'polygon',
          };
          enriched++;
        }
      });
      await new Promise(r => setTimeout(r, 300)); // rate-limit
    }
    if (status) status.textContent = `POLYGON.IO LIVE — ${enriched} real quotes`;
    // Flash the live badge green
    const pill = document.querySelector('.uv-live-pill');
    if (pill) {
      pill.style.borderColor = 'rgba(34,197,94,0.4)';
      pill.style.background = 'rgba(34,197,94,0.08)';
      setTimeout(() => { pill.style.borderColor = ''; pill.style.background = ''; }, 3000);
    }
    // Refresh the visible table
    if (typeof uvRender === 'function') uvRender();
    // Also sync Universe market cap + P/L with real prices
    uvSyncRealPrices();
    // Auto-refresh every 90s
    setTimeout(uvEnrichWithPolygon, 90000);
  } catch(e) {
    if (status) status.textContent = 'POLYGON SYNC ERROR — using simulated';
  }
}

function uvSyncRealPrices() {
  if (typeof UNIVERSE === 'undefined') return;
  let synced = 0;
  UNIVERSE.forEach(s => {
    const q = uvState.liveQuotes[s.t];
    if (q && !q.simulated) {
      // Update live price display in visible table rows
      const row = document.querySelector(`tr[data-ticker="${s.t}"]`);
      if (row) {
        const priceCell = row.querySelector('.live-price-cell');
        if (priceCell) {
          const isUp = q.change >= 0;
          priceCell.innerHTML = `<span style="color:${isUp?'var(--green)':'var(--red)'};font-family:var(--font-mono);">$${q.price.toFixed(2)}</span>`;
        }
        const chgCell = row.querySelector('.live-chg-cell');
        if (chgCell) {
          const isUp = q.change >= 0;
          chgCell.innerHTML = `<span class="${isUp?'chg-pos':'chg-neg'}">${isUp?'+':''}${q.change.toFixed(2)}%</span>`;
          // Flash animation
          chgCell.style.transition = 'none';
          chgCell.style.background = isUp ? 'rgba(34,197,94,0.12)' : 'rgba(255,71,87,0.10)';
          requestAnimationFrame(() => {
            chgCell.style.transition = 'background 1.5s ease';
            chgCell.style.background = 'transparent';
          });
        }
        synced++;
      }
    }
  });
}

