const MACRO_INSTRUMENTS = [
  { id:'macro-sp500',   label:'S&P 500',   ticker:'SPY',     mult:10,    fmt:'index', pfx:'' },
  { id:'macro-nasdaq',  label:'NASDAQ',    ticker:'QQQ',     mult:4.5,   fmt:'index', pfx:'' },
  { id:'macro-10y',     label:'10Y YIELD', ticker:'TNX',     mult:1,     fmt:'pct',   pfx:'' },
  { id:'macro-vix',     label:'VIX',       ticker:'VIXY',    mult:1,     fmt:'index', pfx:'' },
  { id:'macro-gold',    label:'GOLD',      ticker:'GLD',     mult:10,    fmt:'price', pfx:'$' },
  { id:'macro-oil',     label:'OIL (WTI)', ticker:'USO',     mult:3.5,   fmt:'price', pfx:'$' },
  { id:'macro-btc',     label:'BTC',       ticker:'COIN',    mult:1000,  fmt:'price', pfx:'$' },
  { id:'macro-dxy',     label:'DXY',       ticker:'UUP',     mult:38,    fmt:'index', pfx:'' },
];

async function refreshMacroData() {
  if (!window.PolygonAPI || !window.PolygonAPI.isConfigured()) {
    // Try Yahoo Finance proxies for indices
    await refreshMacroYahoo();
    return;
  }
  const tickers = MACRO_INSTRUMENTS.map(m => m.ticker).filter((t,i,a) => a.indexOf(t)===i);
  try {
    const snaps = await window.PolygonAPI.getMultiSnapshot(tickers);
    if (!snaps || !snaps.length) { await refreshMacroYahoo(); return; }
    snaps.forEach(snap => {
      const inst = MACRO_INSTRUMENTS.find(m => m.ticker === snap.ticker);
      if (!inst) return;
      const card = document.getElementById(inst.id);
      if (!card) return;
      const val = card.querySelector('.macro-val');
      const chg = card.querySelector('.macro-change');
      if (!val || !chg) return;
      const price = snap.price;
      const pct = snap.changePct || 0;
      const isUp = pct >= 0;
      const display = inst.fmt === 'pct' ? price.toFixed(2) + '%' :
                      inst.fmt === 'index' ? Math.round(price * inst.mult).toLocaleString() :
                      inst.pfx + price.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2});
      val.textContent = display;
      chg.style.color = isUp ? 'var(--green)' : 'var(--red)';
      chg.textContent = (isUp ? '▲ +' : '▼ ') + pct.toFixed(2) + '%';
      // Flash
      card.style.borderColor = isUp ? 'rgba(34,197,94,0.3)' : 'rgba(255,71,87,0.2)';
      setTimeout(() => card.style.borderColor = '', 2000);
    });
  } catch(_) { await refreshMacroYahoo(); }
}

// Yahoo Finance fallback using existing proxy helpers
async function refreshMacroYahoo() {
  const YAHOO_SYMBOLS = [
    { sym:'^GSPC', id:'macro-sp500',  label:'S&P 500',   fmt:(p)=>p.toLocaleString('en-US',{maximumFractionDigits:0}) },
    { sym:'^IXIC', id:'macro-nasdaq', label:'NASDAQ',    fmt:(p)=>p.toLocaleString('en-US',{maximumFractionDigits:0}) },
    { sym:'^TNX',  id:'macro-10y',    label:'10Y YIELD', fmt:(p)=>p.toFixed(2)+'%' },
    { sym:'^VIX',  id:'macro-vix',    label:'VIX',       fmt:(p)=>p.toFixed(1) },
    { sym:'GC=F',  id:'macro-gold',   label:'GOLD',      fmt:(p)=>'$'+Math.round(p).toLocaleString() },
    { sym:'CL=F',  id:'macro-oil',    label:'OIL (WTI)', fmt:(p)=>'$'+p.toFixed(1) },
    { sym:'BTC-USD',id:'macro-btc',   label:'BTC',       fmt:(p)=>'$'+Math.round(p).toLocaleString() },
    { sym:'DX-Y.NYB',id:'macro-dxy',  label:'DXY',       fmt:(p)=>p.toFixed(1) },
  ];
  const proxies = [
    s => `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(s)}?interval=1d&range=1d`,
    s => `https://api.allorigins.win/get?url=${encodeURIComponent('https://query2.finance.yahoo.com/v8/finance/chart/'+s+'?interval=1d&range=1d')}`,
  ];
  for (const item of YAHOO_SYMBOLS) {
    const card = document.getElementById(item.id);
    if (!card) continue;
    for (const proxyFn of proxies) {
      try {
        const url = proxyFn(item.sym);
        const res = await fetch(url, { signal: AbortSignal.timeout(5000) });
        if (!res.ok) continue;
        let json = await res.json();
        if (json.contents) json = JSON.parse(json.contents);
        const result = json?.chart?.result?.[0];
        if (!result) continue;
        const meta = result.meta;
        const price = meta.regularMarketPrice || meta.previousClose;
        const prev  = meta.previousClose || meta.chartPreviousClose;
        if (!price) continue;
        const pct = prev ? ((price - prev) / prev) * 100 : 0;
        const isUp = pct >= 0;
        const valEl = card.querySelector('.macro-val');
        const chgEl = card.querySelector('.macro-change');
        if (valEl) valEl.textContent = item.fmt(price);
        if (chgEl) {
          chgEl.style.color = isUp ? 'var(--green)' : 'var(--red)';
          chgEl.textContent = (isUp ? '▲ +' : '▼ ') + Math.abs(pct).toFixed(2) + '%';
        }
        card.style.borderColor = isUp ? 'rgba(34,197,94,0.25)' : 'rgba(255,71,87,0.15)';
        setTimeout(() => { if(card) card.style.borderColor = ''; }, 2500);
        break;
      } catch (_) {}
    }
    await new Promise(r => setTimeout(r, 150));
  }
}

// Also refresh sector performance using Polygon grouped daily
async function refreshSectorData() {
  const SECTOR_ETFS = ['XLK','XLV','XLF','XLE','XLY','XLP','XLU','XLI','XLB','XLRE','XLC'];

  // Yahoo Finance fallback for sector ETFs (works without Polygon key)
  async function _refreshSectorsYahoo() {
    for (const etf of SECTOR_ETFS) {
      const card = document.querySelector(`.msc-card[data-etf="${etf}"]`);
      if (!card) continue;
      try {
        const url = `https://query1.finance.yahoo.com/v8/finance/chart/${etf}?interval=1d&range=1d`;
        const res = await fetch(url, { signal: AbortSignal.timeout(5000) });
        if (!res.ok) continue;
        const json = await res.json();
        const meta = json?.chart?.result?.[0]?.meta;
        if (!meta) continue;
        const price = meta.regularMarketPrice || meta.previousClose;
        const prev  = meta.previousClose || meta.chartPreviousClose;
        if (!price || !prev) continue;
        const pct  = ((price - prev) / prev) * 100;
        const isUp = pct >= 0;
        const pctEl  = card.querySelector('.msc-pct');
        const barEl  = card.querySelector('.msc-bar-fill');
        if (pctEl) {
          pctEl.textContent = (isUp ? '+' : '') + pct.toFixed(2) + '%';
          pctEl.className = 'msc-pct ' + (isUp ? 'msc-up' : 'msc-dn');
        }
        if (barEl) {
          barEl.style.width = Math.min(100, Math.abs(pct) * 20) + '%';
          barEl.className = 'msc-bar-fill ' + (isUp ? 'msc-bar-up' : 'msc-bar-dn');
        }
        card.style.borderColor = isUp ? 'rgba(34,197,94,0.2)' : 'rgba(248,113,113,0.15)';
        setTimeout(() => { if (card) card.style.borderColor = ''; }, 3000);
      } catch(_) {}
      await new Promise(r => setTimeout(r, 120));
    }
  }

  if (!window.PolygonAPI || !window.PolygonAPI.isConfigured()) {
    await _refreshSectorsYahoo();
    return;
  }
  try {
    const snaps = await window.PolygonAPI.getMultiSnapshot(SECTOR_ETFS);
    if (!snaps || !snaps.length) { await _refreshSectorsYahoo(); return; }
    snaps.forEach(snap => {
      const card = document.querySelector(`.msc-card[data-etf="${snap.ticker}"]`);
      if (!card) return;
      const pct  = snap.changePct || 0;
      const isUp = pct >= 0;
      const pctEl = card.querySelector('.msc-pct');
      const barEl = card.querySelector('.msc-bar-fill');
      if (pctEl) {
        pctEl.textContent = (isUp ? '+' : '') + pct.toFixed(2) + '%';
        pctEl.className = 'msc-pct ' + (isUp ? 'msc-up' : 'msc-dn');
      }
      if (barEl) {
        barEl.style.width = Math.min(100, Math.abs(pct) * 20) + '%';
        barEl.className = 'msc-bar-fill ' + (isUp ? 'msc-bar-up' : 'msc-bar-dn');
      }
      card.style.borderColor = isUp ? 'rgba(34,197,94,0.2)' : 'rgba(248,113,113,0.15)';
      setTimeout(() => { if (card) card.style.borderColor = ''; }, 3000);
    });
  } catch(_) { await _refreshSectorsYahoo(); }

}

