async function syncPortfolioPrices() {
  if (!window.state || !state.portfolio || !state.portfolio.length) return;
  const tickers = [...new Set(state.portfolio.map(p => p.ticker).filter(Boolean))];
  if (!tickers.length) return;

  // Try Polygon first
  if (window.PolygonAPI && window.PolygonAPI.isConfigured()) {
    try {
      const snaps = await window.PolygonAPI.getMultiSnapshot(tickers);
      if (snaps && snaps.length) {
        let updated = false;
        snaps.forEach(s => {
          const pos = state.portfolio.find(p => p.ticker === s.ticker);
          if (pos && s.price) { pos.current = s.price; updated = true; }
        });
        if (updated && typeof renderPortfolio === 'function') {
          renderPortfolio();
          updatePortfolioMetrics();
        }
        return;
      }
    } catch(_) {}
  }

  // Yahoo Finance fallback
  for (const ticker of tickers) {
    try {
      const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(ticker)}?interval=1d&range=1d`;
      const res = await fetch(url, { signal: AbortSignal.timeout(4000) });
      if (!res.ok) continue;
      const json = await res.json();
      const price = json?.chart?.result?.[0]?.meta?.regularMarketPrice;
      if (!price) continue;
      const pos = state.portfolio.find(p => p.ticker === ticker);
      if (pos) pos.current = price;
    } catch(_) {}
    await new Promise(r => setTimeout(r, 200));
  }
  if (typeof renderPortfolio === 'function') {
    renderPortfolio();
    updatePortfolioMetrics();
  }
}

function updatePortfolioMetrics() {
  if (!window.state || !state.portfolio) return;
  const totalVal = state.portfolio.reduce((s, p) => s + (p.qty * p.current), 0);
  const totalCost = state.portfolio.reduce((s, p) => s + (p.qty * p.cost), 0);
  const totalPnl = totalVal - totalCost;
  const dayPnl = state.portfolio.reduce((s, p) => {
    const stock = STOCKS.find(st => st.ticker === p.ticker);
    return s + (stock ? p.qty * p.current * (stock.change / 100) : 0);
  }, 0);
  const elVal = document.getElementById('portfolio-metric-value');
  if (elVal) elVal.textContent = '$' + totalVal.toLocaleString('en-US',{maximumFractionDigits:0});
  const elPnl = document.getElementById('portfolio-metric-pnl');
  if (elPnl) {
    elPnl.textContent = (totalPnl >= 0 ? '+$' : '-$') + Math.abs(totalPnl).toLocaleString('en-US',{maximumFractionDigits:0});
    elPnl.style.color = totalPnl >= 0 ? 'var(--green)' : 'var(--red)';
  }
  const elDay = document.getElementById('portfolio-metric-day-pnl');
  if (elDay) {
    elDay.textContent = (dayPnl >= 0 ? '+$' : '-$') + Math.abs(dayPnl).toLocaleString('en-US',{maximumFractionDigits:0});
    elDay.style.color = dayPnl >= 0 ? 'var(--green)' : 'var(--red)';
  }
}

// Sync on portfolio page open
