// 1. Add real-time clock to ticker strip
function startTickerClock() {
  const strip = document.querySelector('.ticker-strip');
  if (!strip) return;
  let clockEl = document.getElementById('ticker-clock');
  if (!clockEl) {
    clockEl = document.createElement('div');
    clockEl.id = 'ticker-clock';
    clockEl.style.cssText = 'position:absolute;right:110px;top:50%;transform:translateY(-50%);z-index:3;background:var(--black);padding:0 12px;font-family:var(--font-mono);font-size:11px;color:var(--text-muted);display:flex;gap:10px;align-items:center;';
    strip.appendChild(clockEl);
  }
  function tick() {
    const now = new Date();
    const ny = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
    const isWeekday = ny.getDay() > 0 && ny.getDay() < 6;
    const h = ny.getHours(), m = ny.getMinutes();
    const isOpen = isWeekday && (h > 9 || (h === 9 && m >= 30)) && h < 16;
    const pre = isWeekday && h >= 4 && h < 9.5;
    const after = isWeekday && h >= 16 && h < 20;
    const status = isOpen ? '🟢 NYSE OPEN' : pre ? '🟡 PRE-MKT' : after ? '🟡 AFTER-HRS' : '🔴 CLOSED';
    const timeStr = ny.toLocaleTimeString('en-US', {hour:'2-digit',minute:'2-digit',second:'2-digit',timeZone:'America/New_York'}) + ' ET';
    clockEl.innerHTML = `<span>${status}</span><span style="color:var(--text-muted);">${timeStr}</span>`;
  }
  tick();
  setInterval(tick, 1000);
}

// 2. Pulse ticker prices from Polygon WS — also feeds uvState.liveQuotes
if (window.PolygonAPI) {
  window.PolygonAPI.on('trade', ({ ticker, price, oldPrice }) => {
    const isUp = price >= (oldPrice || price);

    // ── Update uvState.liveQuotes so Universe table stays current ──
    if (typeof uvState !== 'undefined') {
      const cache = window.PolygonAPI.getCache();
      const cached = cache[ticker] || {};
      const prevClose = cached.prevClose || (uvState.liveQuotes[ticker]?.prevClose) || price;
      const changePct = prevClose ? ((price - prevClose) / prevClose) * 100 : 0;
      uvState.liveQuotes[ticker] = {
        price,
        change: +changePct.toFixed(2),
        prevClose,
        volume: cached.volume || 0,
        ts: Date.now(),
        simulated: false,
        source: 'polygon-ws',
      };
      // Surgically update visible cells (no full re-render needed)
      const row = document.querySelector(`tr[data-ticker="${CSS.escape ? CSS.escape(ticker) : ticker}"]`);
      if (row) {
        const pc = row.querySelector('.live-price-cell');
        if (pc) {
          pc.innerHTML = `<span style="color:${isUp?'var(--green)':'var(--red)'};font-family:var(--font-mono);">$${price.toFixed(2)}<span style="font-size:8px;margin-left:3px;color:var(--green);opacity:0.7;">●</span></span>`;
          pc.style.transition = 'none';
          pc.style.background = isUp ? 'rgba(34,197,94,0.12)' : 'rgba(255,71,87,0.10)';
          requestAnimationFrame(() => { pc.style.transition = 'background 1.5s'; pc.style.background = 'transparent'; });
        }
        const cc = row.querySelector('.live-chg-cell');
        if (cc) {
          cc.innerHTML = `<span style="color:${isUp?'var(--green)':'var(--red)'};font-family:var(--font-mono);">${isUp?'+':''}${changePct.toFixed(2)}%</span>`;
        }
      }
    }

    // ── Update ticker strip ──
    document.querySelectorAll('.ticker-item').forEach(item => {
      const sym = item.querySelector('.ticker-sym');
      if (sym && sym.textContent.trim() === ticker) {
        const priceEl = item.querySelector('.ticker-price');
        if (priceEl) {
          priceEl.textContent = '$' + price.toFixed(2);
          priceEl.style.transition = 'none';
          priceEl.style.color = isUp ? 'var(--green)' : 'var(--red)';
          requestAnimationFrame(() => { priceEl.style.transition = 'color 1s'; priceEl.style.color = ''; });
        }
      }
    });
  });

  // Batch update from per-minute aggregates (AM events) — keep prevClose accurate
  window.PolygonAPI.on('aggregate', ({ ticker, close, volume }) => {
    if (typeof uvState === 'undefined') return;
    const q = uvState.liveQuotes[ticker];
    if (q && !q.simulated) {
      q.price = close;
      q.volume = volume;
      q.ts = Date.now();
    }
  });
}

// 3. Universe "Connect Polygon" banner when no key set
function uvShowPolygonBanner() {
  if (localStorage.getItem('qe_poly_banner_dismissed')) return;
  const hero = document.querySelector('.uv3-header') || document.querySelector('.uv-hero');
  if (!hero || document.getElementById('uv-polygon-banner')) return;
  if (window.PolygonAPI && window.PolygonAPI.isConfigured()) return;
  const banner = document.createElement('div');
  banner.id = 'uv-polygon-banner';
  banner.style.cssText = 'background:linear-gradient(90deg,rgba(124,58,237,0.08),rgba(34,197,94,0.06));border:1px solid rgba(167,139,250,0.15);border-radius:10px;padding:10px 16px;margin-bottom:12px;display:flex;align-items:center;gap:12px;font-size:12px;';
  banner.innerHTML = `
    <span style="font-size:18px;">🔗</span>
    <span style="color:var(--text-secondary);">Connect <strong style="color:var(--text-primary);">Polygon.io</strong> in Settings to enable real-time prices.</span>
    <button onclick="if(typeof showPage==='function')showPage('settings',null)" class="btn btn-ghost btn-sm" style="margin-left:auto;white-space:nowrap;">Settings →</button>
    <button onclick="localStorage.setItem('qe_poly_banner_dismissed','1');this.parentElement.remove()" style="background:none;border:none;color:var(--text-muted);font-size:16px;cursor:pointer;padding:0 4px;" title="Dismiss">×</button>
  `;
  hero.parentElement.insertBefore(banner, hero);
}

// 4. Universe data quality label
function uvUpdateDataLabel() {
  const status = document.getElementById('uv-live-status');
  if (!status) return;
  const hasReal = Object.values(uvState.liveQuotes || {}).some(q => !q.simulated);
  if (hasReal) {
    const realCount = Object.values(uvState.liveQuotes).filter(q => !q.simulated).length;
    status.textContent = `POLYGON.IO LIVE — ${realCount} real quotes`;
    status.style.color = 'var(--green)';
  } else {
    status.textContent = 'SIMULATED — Connect Polygon.io for real prices';
    status.style.color = 'var(--text-muted)';
  }
}

// 5. Better "Live" label update every 30s
setInterval(uvUpdateDataLabel, 30000);

