'use strict';

// ─── Paper Trading State ──────────────────────────────────────────
const ptState = {
  accounts:       [],
  currentAccount: null,   // full account object
  positions:      [],
  orders:         [],
  side:           'buy',
  orderType:      'market',
  currentPrice:   null,
  priceInterval:  null,
  activeTab:      'positions',
};

// ─── Helpers ──────────────────────────────────────────────────────
function ptFmt(n, dec=2) {
  if (n == null) return '—';
  return '$' + Number(n).toLocaleString('en-US', { minimumFractionDigits: dec, maximumFractionDigits: dec });
}
function ptFmtPct(n) {
  if (n == null) return '—';
  const sign = n >= 0 ? '+' : '';
  return sign + Number(n).toFixed(2) + '%';
}
function ptPnlClass(n) { return n >= 0 ? 'pt-pnl-pos' : 'pt-pnl-neg'; }

// ─── Page Init ────────────────────────────────────────────────────
async function ptInit() {
  const noAcct = document.getElementById('pt-no-acct');
  const _hide = () => ['pt-acct-card','pt-stat-strip','pt-main-grid'].forEach(id => { const el = document.getElementById(id); if (el) el.style.display = 'none'; });
  const _ptShowErr = (icon, title, body, retry) => {
    if (!noAcct) return;
    noAcct.innerHTML = `
      <div style="font-size:48px;margin-bottom:16px;">${icon}</div>
      <div style="font-size:18px;font-weight:700;margin-bottom:8px;font-family:var(--font-display);">${title}</div>
      <div style="color:var(--text-secondary);font-size:13px;line-height:1.7;max-width:420px;">${body}</div>
      ${retry ? `<button onclick="ptInit()" style="margin-top:20px;padding:10px 28px;border-radius:8px;border:none;background:var(--accent);color:#000;font-weight:700;cursor:pointer;font-size:13px;">↻ Retry</button>` : ''}`;
    _hide();
    noAcct.style.display = '';
  };

  // Single gate: can we reach the server at all?
  // Works for both file:// (always fails) and server-down cases.
  try {
    const r = await fetch('/health', { cache: 'no-store' });
    if (!r.ok) throw new Error('unhealthy');
  } catch (_) {
    _ptShowErr('📡', 'Server Not Running',
      'Paper Trading needs the backend server.<br><br>' +
      '• In development: run <code style="background:rgba(255,255,255,.08);padding:1px 6px;border-radius:4px;">node server.js</code> then open <code style="background:rgba(255,255,255,.08);padding:1px 6px;border-radius:4px;">http://localhost:3000</code><br>' +
      '• In production: make sure the Node process is running and HTTPS is configured<br><br>' +
      'Then click Retry.',
      true);
    return;
  }

  // Server is reachable — load accounts (server returns 401 if not logged in)
  await ptLoadAccounts();
}

async function ptLoadAccounts() {
  const noAcct = document.getElementById('pt-no-acct');
  try {
    const r = await fetch('/api/pt/accounts', { credentials: 'same-origin' });
    if (r.status === 401) {
      if (noAcct) noAcct.innerHTML = `
        <div style="font-size:48px;margin-bottom:16px;">🔒</div>
        <div style="font-size:18px;font-weight:700;margin-bottom:8px;font-family:var(--font-display);">Sign In Required</div>
        <div style="color:var(--text-secondary);font-size:13px;margin-bottom:18px;">Log in to access Paper Trading.</div>
        <button onclick="typeof showAuth==='function'?showAuth('login'):(document.getElementById('qz-auth-overlay')&&document.getElementById('qz-auth-overlay').classList.remove('dismissed'))" style="padding:10px 28px;border-radius:8px;border:none;background:var(--accent);color:#000;font-weight:700;cursor:pointer;font-size:13px;">Sign In →</button>`;
      [document.getElementById('pt-acct-card'), document.getElementById('pt-stat-strip'), document.getElementById('pt-main-grid')].forEach(el => { if (el) el.style.display = 'none'; });
      return;
    }
    if (!r.ok) {
      const err = await r.json().catch(() => ({}));
      if (noAcct) noAcct.innerHTML = `
        <div style="font-size:48px;margin-bottom:16px;">⚠️</div>
        <div style="font-size:18px;font-weight:700;margin-bottom:8px;font-family:var(--font-display);">Server Error</div>
        <div style="color:var(--text-secondary);font-size:13px;">${err.error || 'Could not load accounts'} (${r.status})</div>
        <button onclick="ptInit()" style="margin-top:14px;padding:10px 24px;border-radius:8px;border:none;background:var(--accent);color:#000;font-weight:700;cursor:pointer;font-size:13px;">Retry</button>`;
      [document.getElementById('pt-acct-card'), document.getElementById('pt-stat-strip'), document.getElementById('pt-main-grid')].forEach(el => { if (el) el.style.display = 'none'; });
      return;
    }
    ptState.accounts = await r.json();
    ptRenderAccountSelect();
    if (ptState.accounts.length === 0) {
      if (noAcct) {
        noAcct.style.display = '';
        noAcct.innerHTML = `
          <div style="font-size:48px;margin-bottom:16px;">📈</div>
          <div style="font-size:20px;font-weight:700;margin-bottom:8px;font-family:var(--font-display);">Start Paper Trading</div>
          <div style="color:var(--text-secondary);font-size:14px;margin-bottom:24px;max-width:420px;margin-left:auto;margin-right:auto;">Create a virtual account with $100,000 in simulated cash. Practice trading strategies with zero risk before putting real money to work.</div>
          <button class="btn btn-primary" onclick="ptNewAccountModal()" style="padding:13px 32px;font-size:14px;">Create Account →</button>`;
      }
      document.getElementById('pt-acct-card').style.display = 'none';
      document.getElementById('pt-stat-strip').style.display = 'none';
      document.getElementById('pt-main-grid').style.display = 'none';
    } else {
      if (noAcct) noAcct.style.display = 'none';
      // Auto-select first account
      const saved = localStorage.getItem('pt_last_account');
      const pick  = ptState.accounts.find(a => a.id === saved) || ptState.accounts[0];
      await ptSwitchAccount(pick.id);
    }
  } catch (e) {
    console.warn('ptLoadAccounts:', e.message);
    if (noAcct) noAcct.innerHTML = `
      <div style="font-size:48px;margin-bottom:16px;">📡</div>
      <div style="font-size:18px;font-weight:700;margin-bottom:8px;font-family:var(--font-display);">Cannot Connect to Server</div>
      <div style="color:var(--text-secondary);font-size:13px;">Make sure <code style="background:rgba(255,255,255,.08);padding:2px 6px;border-radius:4px;">node server.js</code> is running, then refresh.</div>
      <div style="color:var(--text-muted);font-size:11px;margin-top:8px;">${e.message}</div>`;
  }
}

function ptRenderAccountSelect() {
  const sel = document.getElementById('pt-acct-select');
  if (!sel) return;
  sel.innerHTML = ptState.accounts.map(a =>
    `<option value="${a.id}">${a.name} · ${ptFmt(a.equity || a.cash)}</option>`
  ).join('');
  if (ptState.currentAccount) sel.value = ptState.currentAccount.id;
}

async function ptSwitchAccount(id) {
  if (!id) return;
  localStorage.setItem('pt_last_account', id);
  try {
    const r = await fetch(`/api/pt/account/${encodeURIComponent(id)}`, { credentials: 'same-origin' });
    if (!r.ok) throw new Error('fetch failed');
    const data = await r.json();
    ptState.currentAccount = data.account;
    ptState.positions = data.positions;
    const sel = document.getElementById('pt-acct-select');
    if (sel) sel.value = id;
    ptRenderAccountCard();
    ptRenderPositions();
    await ptLoadOrders();
    document.getElementById('pt-acct-card').style.display = '';
    document.getElementById('pt-stat-strip').style.display = '';
    document.getElementById('pt-main-grid').style.display = '';
    document.getElementById('pt-no-acct').style.display = 'none';
    // Start live price refresh
    ptStartPriceRefresh();
  } catch(e) {
    console.warn('ptSwitchAccount:', e.message);
    const noAcct = document.getElementById('pt-no-acct');
    if (noAcct) noAcct.innerHTML = `
      <div style="font-size:48px;margin-bottom:16px;">📡</div>
      <div style="font-size:18px;font-weight:700;margin-bottom:8px;font-family:var(--font-display);">Cannot Connect to Server</div>
      <div style="color:var(--text-secondary);font-size:13px;">Make sure <code style="background:rgba(255,255,255,.08);padding:2px 6px;border-radius:4px;">node server.js</code> is running, then refresh.</div>
      <div style="color:var(--text-muted);font-size:11px;margin-top:8px;">${e.message}</div>`;
  }
}

function ptRenderAccountCard() {
  const a = ptState.currentAccount;
  if (!a) return;
  const posVal = ptState.positions.reduce((s,p) => s + (p.market_value || 0), 0);
  const equity = (a.cash || 0) + posVal;
  const pnl    = equity - (a.initial_cash || 100000);
  const pct    = ((pnl / (a.initial_cash || 100000)) * 100);
  document.getElementById('pt-acct-card-name').textContent = (a.name || 'Account').toUpperCase();
  document.getElementById('pt-acct-equity').textContent = ptFmt(equity);
  document.getElementById('pt-acct-cash').textContent = ptFmt(a.cash);
  document.getElementById('pt-acct-pos-val').textContent = ptFmt(posVal);
  const pnlEl = document.getElementById('pt-acct-pnl');
  const pctEl = document.getElementById('pt-acct-pnl-pct');
  pnlEl.textContent = (pnl >= 0 ? '+' : '') + ptFmt(pnl);
  pnlEl.style.color = pnl >= 0 ? 'var(--green)' : 'var(--red)';
  pctEl.textContent = ptFmtPct(pct);
  pctEl.style.color = pct >= 0 ? 'var(--green)' : 'var(--red)';
  // Stats
  const unrealPnl = ptState.positions.reduce((s,p) => s + (p.unrealized_pnl || 0), 0);
  document.getElementById('pt-stat-positions').textContent = ptState.positions.length;
  document.getElementById('pt-stat-unrealized').textContent = (unrealPnl >= 0 ? '+' : '') + ptFmt(unrealPnl);
  document.getElementById('pt-stat-unrealized').style.color = unrealPnl >= 0 ? 'var(--green)' : 'var(--red)';
}

function ptRenderPositions() {
  const el = document.getElementById('pt-positions-body');
  if (!el) return;
  if (!ptState.positions.length) {
    el.innerHTML = '<div class="pt-empty">No open positions · Place your first trade →</div>';
    ptRenderQuickClose();
    return;
  }
  const rows = ptState.positions.map(p => {
    const pnlClass = ptPnlClass(p.unrealized_pnl);
    const pnlStr = (p.unrealized_pnl >= 0 ? '+' : '') + ptFmt(p.unrealized_pnl);
    const pctStr = ptFmtPct(p.unrealized_pct);
    return `<tr>
      <td><strong>${p.ticker}</strong><br><span style="color:var(--text-muted);font-size:10px;">${(p.asset_name||'').slice(0,20)}</span></td>
      <td>${Number(p.qty).toLocaleString()}</td>
      <td class="pt-quick-price" id="pt-price-${p.ticker}">${ptFmt(p.current_price)}</td>
      <td>${ptFmt(p.avg_cost)}</td>
      <td>${ptFmt(p.market_value)}</td>
      <td class="${pnlClass}">${pnlStr}<br><span style="font-size:10px;">${pctStr}</span></td>
      <td><button style="padding:4px 10px;border-radius:6px;border:1px solid rgba(248,113,113,.3);background:rgba(248,113,113,.1);color:var(--red);font-size:11px;cursor:pointer;" onclick="ptQuickClose('${p.ticker}',${p.qty})">Close</button></td>
    </tr>`;
  }).join('');
  el.innerHTML = `<table class="pt-pos-table">
    <thead><tr><th>TICKER</th><th>QTY</th><th>PRICE</th><th>AVG COST</th><th>MKT VAL</th><th>P&L</th><th></th></tr></thead>
    <tbody>${rows}</tbody>
  </table>`;
  ptRenderQuickClose();
}

function ptRenderQuickClose() {
  const el = document.getElementById('pt-quick-close-body');
  if (!el) return;
  if (!ptState.positions.length) { el.textContent = 'No positions to close'; return; }
  el.innerHTML = ptState.positions.slice(0, 6).map(p =>
    `<div style="display:flex;align-items:center;padding:8px 0;border-bottom:1px solid rgba(255,255,255,.04);gap:10px;">
      <div style="flex:1;"><strong style="font-size:13px;">${p.ticker}</strong> <span style="color:var(--text-muted);font-size:11px;">×${Number(p.qty).toLocaleString()}</span></div>
      <div class="pt-quick-price" id="pt-qp-${p.ticker}">${ptFmt(p.current_price)}</div>
      <button style="padding:4px 10px;border-radius:6px;border:1px solid rgba(248,113,113,.3);background:rgba(248,113,113,.1);color:var(--red);font-size:11px;cursor:pointer;" onclick="ptQuickClose('${p.ticker}',${p.qty})">Close All</button>
    </div>`
  ).join('');
}

async function ptLoadOrders() {
  if (!ptState.currentAccount) return;
  try {
    const r = await fetch(`/api/pt/orders?accountId=${encodeURIComponent(ptState.currentAccount.id)}`, { credentials: 'same-origin' });
    if (!r.ok) return;
    ptState.orders = await r.json();
    ptRenderOrders();
    // Update orders stat (today's orders)
    const today = new Date().toDateString();
    const todayCount = ptState.orders.filter(o => new Date(o.created_at).toDateString() === today).length;
    document.getElementById('pt-stat-orders').textContent = todayCount;
    // Compute win rate from filled orders
    const fills = ptState.orders.filter(o => o.status === 'filled' && o.side === 'sell');
    if (fills.length >= 2) {
      document.getElementById('pt-stat-winrate').textContent = '—';
    } else {
      document.getElementById('pt-stat-winrate').textContent = '—';
    }
  } catch(e) {}
}

function ptRenderOrders() {
  const el = document.getElementById('pt-orders-body');
  if (!el) return;
  if (!ptState.orders.length) { el.innerHTML = '<div class="pt-empty">No orders yet</div>'; return; }
  el.innerHTML = ptState.orders.slice(0, 50).map(o => {
    const sideColor = o.side === 'buy' ? 'var(--green)' : 'var(--red)';
    const badge = `<span class="pt-ord-badge ${o.status}">${o.status.toUpperCase()}</span>`;
    const price = o.fill_price ? ptFmt(o.fill_price) : (o.limit_price ? `Limit ${ptFmt(o.limit_price)}` : '—');
    const ts = new Date(o.created_at).toLocaleString('en-US',{month:'short',day:'numeric',hour:'2-digit',minute:'2-digit'});
    return `<div class="pt-ord-row">
      ${badge}
      <div style="flex:1;">
        <strong style="color:${sideColor};">${o.side.toUpperCase()}</strong> ${o.qty}× <strong>${o.ticker}</strong>
        <div style="color:var(--text-muted);font-size:11px;">${o.asset_name || ''}</div>
      </div>
      <div style="text-align:right;">
        <div style="font-family:var(--font-mono);color:var(--text-primary);">${price}</div>
        <div style="color:var(--text-muted);font-size:10px;">${ts}</div>
      </div>
      ${o.status === 'pending' ? `<button onclick="ptCancelOrder('${o.id}')" style="padding:4px 8px;border-radius:5px;border:1px solid rgba(248,113,113,.3);background:rgba(248,113,113,.1);color:var(--red);font-size:10px;cursor:pointer;">✕</button>` : ''}
    </div>`;
  }).join('');
}

// ─── Order Ticket ─────────────────────────────────────────────────
function ptSetSide(side) {
  ptState.side = side;
  document.getElementById('pt-side-buy').className = 'pt-side-btn' + (side === 'buy' ? ' buy-active' : '');
  document.getElementById('pt-side-sell').className = 'pt-side-btn' + (side === 'sell' ? ' sell-active' : '');
  document.getElementById('pt-submit-btn').className = 'pt-submit-btn ' + side;
  document.getElementById('pt-submit-btn').textContent = `Place ${side.charAt(0).toUpperCase()+side.slice(1)} Order`;
  ptUpdatePreview();
}

function ptSetType(type) {
  ptState.orderType = type;
  document.getElementById('pt-type-market').className = 'pt-type-btn' + (type === 'market' ? ' active' : '');
  document.getElementById('pt-type-limit').className  = 'pt-type-btn' + (type === 'limit'  ? ' active' : '');
  document.getElementById('pt-limit-row').style.display = type === 'limit' ? '' : 'none';
  ptUpdatePreview();
}

function ptTickerChanged() {
  ptState.currentPrice = null;
  const ticker = (document.getElementById('pt-ticker-input')?.value || '').trim().toUpperCase();
  document.getElementById('pt-price-display').textContent = ticker ? 'Press "Get Price"' : '';
  ptUpdatePreview();
}

async function ptFetchPrice() {
  const ticker = (document.getElementById('pt-ticker-input')?.value || '').trim().toUpperCase().replace(/[^A-Z0-9]/g,'');
  if (!ticker) return;
  document.getElementById('pt-price-display').textContent = 'Fetching…';
  try {
    const r = await fetch(`/api/pt/price/${encodeURIComponent(ticker)}`, { credentials: 'same-origin' });
    if (!r.ok) throw new Error('not found');
    const data = await r.json();
    ptState.currentPrice = data.price;
    const el = document.getElementById('pt-price-display');
    el.textContent = ptFmt(data.price) + ' (simulated)';
    el.classList.add('pt-price-flash');
    setTimeout(() => el.classList.remove('pt-price-flash'), 500);
    ptUpdatePreview();
  } catch(e) {
    document.getElementById('pt-price-display').textContent = 'Could not fetch price';
  }
}

function ptUpdatePreview() {
  const ticker = (document.getElementById('pt-ticker-input')?.value || '').trim().toUpperCase();
  const qty    = parseFloat(document.getElementById('pt-qty-input')?.value || '0') || 0;
  const price  = ptState.orderType === 'limit'
    ? parseFloat(document.getElementById('pt-limit-input')?.value || '0')
    : ptState.currentPrice;
  const el = document.getElementById('pt-order-preview');
  if (!ticker || !qty || !price) {
    el.innerHTML = 'Enter ticker and quantity to preview order';
    return;
  }
  const value = qty * price;
  const commission = Math.min(value * 0.0005, 5);
  const total = ptState.side === 'buy' ? value + commission : value - commission;
  const acct = ptState.currentAccount;
  const cashAfter = acct ? acct.cash - (ptState.side === 'buy' ? total : -total) : null;
  el.innerHTML = `
    <strong>${ptState.side.toUpperCase()}</strong> ${qty.toLocaleString()} × <strong>${ticker}</strong><br>
    Price: <strong>${ptFmt(price)}</strong> · Value: <strong>${ptFmt(value)}</strong><br>
    Commission: ${ptFmt(commission)}<br>
    <strong>${ptState.side === 'buy' ? 'Total Cost' : 'Net Proceeds'}:</strong> <strong>${ptFmt(total)}</strong>
    ${cashAfter != null ? `<br>Cash after: <span style="color:${cashAfter>=0?'var(--green)':'var(--red);'};">${ptFmt(cashAfter)}</span>` : ''}
  `;
}

async function ptPlaceOrder() {
  if (!ptState.currentAccount) { ptStatus('No account selected', 'var(--red)'); return; }
  const ticker = (document.getElementById('pt-ticker-input')?.value || '').trim().toUpperCase().replace(/[^A-Z0-9]/g,'');
  const qty    = parseFloat(document.getElementById('pt-qty-input')?.value) || 0;
  if (!ticker) { ptStatus('Enter a ticker symbol', 'var(--red)'); return; }
  if (qty <= 0) { ptStatus('Enter a valid quantity', 'var(--red)'); return; }
  if (ptState.orderType === 'market' && !ptState.currentPrice) {
    ptStatus('Click "Get Price" first', 'var(--yellow)'); return;
  }
  const body = {
    accountId: ptState.currentAccount.id,
    ticker, side: ptState.side, qty, orderType: ptState.orderType,
  };
  if (ptState.orderType === 'limit') {
    body.limitPrice = parseFloat(document.getElementById('pt-limit-input')?.value) || 0;
    if (!body.limitPrice) { ptStatus('Enter a limit price', 'var(--red)'); return; }
  }
  const btn = document.getElementById('pt-submit-btn');
  btn.disabled = true; btn.textContent = 'Placing…';
  ptStatus('', '');
  try {
    const r = await fetch('/api/pt/orders', {
      method: 'POST', credentials: 'same-origin',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const data = await r.json();
    if (!r.ok) throw new Error(data.error || 'Order failed');
    ptStatus(data.status === 'filled'
      ? `✓ Filled at ${ptFmt(data.fill_price)} · commission ${ptFmt(data.commission)}`
      : `⏳ Limit order placed`, 'var(--green)');
    // Refresh account data
    await ptSwitchAccount(ptState.currentAccount.id);
    // Clear form
    document.getElementById('pt-qty-input').value = '';
    document.getElementById('pt-order-preview').innerHTML = 'Enter ticker and quantity to preview order';
  } catch(e) {
    ptStatus('✗ ' + e.message, 'var(--red)');
  } finally {
    btn.disabled = false;
    ptSetSide(ptState.side);
  }
}

async function ptQuickClose(ticker, qty) {
  if (!ptState.currentAccount) return;
  if (!confirm(`Close entire ${ticker} position (${qty} shares)?`)) return;
  try {
    const r = await fetch('/api/pt/orders', {
      method: 'POST', credentials: 'same-origin',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        accountId: ptState.currentAccount.id,
        ticker, side: 'sell', qty, orderType: 'market',
      }),
    });
    const data = await r.json();
    if (!r.ok) throw new Error(data.error);
    ptStatus(`✓ Closed ${ticker} at ${ptFmt(data.fill_price)}`, 'var(--green)');
    await ptSwitchAccount(ptState.currentAccount.id);
  } catch(e) {
    ptStatus('✗ ' + e.message, 'var(--red)');
  }
}

async function ptCancelOrder(orderId) {
  if (!ptState.currentAccount) return;
  try {
    await fetch(`/api/pt/orders/${encodeURIComponent(orderId)}?accountId=${encodeURIComponent(ptState.currentAccount.id)}`,
      { method: 'DELETE', credentials: 'same-origin' });
    await ptLoadOrders();
  } catch(e) {}
}

function ptStatus(msg, color) {
  const el = document.getElementById('pt-order-status');
  if (el) { el.textContent = msg; el.style.color = color; }
}

// ─── Tabs ──────────────────────────────────────────────────────────
function ptSetTab(tab, btn) {
  ptState.activeTab = tab;
  ['positions','orders','leaderboard'].forEach(t => {
    const el = document.getElementById('pt-tab-' + t);
    if (el) el.style.display = t === tab ? '' : 'none';
  });
  document.querySelectorAll('#page-paper .pt-tab').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  if (tab === 'leaderboard') ptLoadLeaderboard();
}

async function ptLoadLeaderboard() {
  const el = document.getElementById('pt-leaderboard-body');
  if (!el) return;
  el.innerHTML = '<div class="pt-empty">Loading…</div>';
  try {
    const r = await fetch('/api/pt/leaderboard', { credentials: 'same-origin' });
    if (!r.ok) throw new Error('fetch failed');
    const rows = await r.json();
    if (!rows.length) { el.innerHTML = '<div class="pt-empty">No traders yet — be the first!</div>'; return; }
    const medals = ['🥇','🥈','🥉'];
    el.innerHTML = rows.map((r, i) => {
      const pctColor = r.pct_return >= 0 ? 'var(--green)' : 'var(--red)';
      return `<div class="pt-leaderboard-row">
        <div class="pt-rank">${medals[i] || ('#' + r.rank)}</div>
        <div style="flex:1;"><strong>${r.name}</strong><div style="font-size:11px;color:var(--text-muted);">${r.account_name}</div></div>
        <div style="text-align:right;"><div style="font-family:var(--font-mono);color:${pctColor};font-weight:700;">${ptFmtPct(r.pct_return)}</div><div style="font-size:11px;color:var(--text-muted);">${ptFmt(r.equity)}</div></div>
      </div>`;
    }).join('');
  } catch(e) { el.innerHTML = '<div class="pt-empty">Could not load leaderboard</div>'; }
}

// ─── New Account Modal ─────────────────────────────────────────────
function ptNewAccountModal() {
  document.getElementById('pt-new-acct-modal').style.display = 'flex';
  document.getElementById('pt-modal-status').textContent = '';
  document.getElementById('pt-new-name').value = '';
  setTimeout(() => document.getElementById('pt-new-name')?.focus(), 80);
}
function ptCloseModal() { document.getElementById('pt-new-acct-modal').style.display = 'none'; }

async function ptCreateAccount() {
  const name = (document.getElementById('pt-new-name')?.value || '').trim() || 'Paper Account';
  const cash = parseInt(document.getElementById('pt-new-cash')?.value || '100000', 10);
  const statusEl = document.getElementById('pt-modal-status');
  try {
    const r = await fetch('/api/pt/accounts', {
      method: 'POST', credentials: 'same-origin',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name, initialCash: cash }),
    });
    const data = await r.json();
    if (!r.ok) throw new Error(data.error || 'Failed');
    ptCloseModal();
    await ptLoadAccounts();
    if (data.id) await ptSwitchAccount(data.id);
  } catch(e) {
    statusEl.textContent = e.message === 'Failed to fetch'
      ? 'Cannot reach server — is it running?'
      : e.message;
  }
}

// ─── Live price refresh ────────────────────────────────────────────
function ptStartPriceRefresh() {
  if (ptState.priceInterval) clearInterval(ptState.priceInterval);
  ptState.priceInterval = setInterval(() => {
    if (document.getElementById('page-paper')?.classList.contains('hidden')) return;
    // Update price cells for each position
    ptState.positions.forEach(p => {
      fetch(`/api/pt/price/${encodeURIComponent(p.ticker)}`, { credentials: 'same-origin' })
        .then(r => r.json())
        .then(d => {
          const el1 = document.getElementById('pt-price-' + p.ticker);
          const el2 = document.getElementById('pt-qp-' + p.ticker);
          if (el1) { el1.textContent = ptFmt(d.price); el1.classList.add('pt-price-flash'); setTimeout(()=>el1.classList.remove('pt-price-flash'),400); }
          if (el2) { el2.textContent = ptFmt(d.price); }
          p.current_price = d.price;
          p.market_value = Math.round(d.price * p.qty * 100) / 100;
          p.unrealized_pnl = Math.round((d.price - p.avg_cost) * p.qty * 100) / 100;
        }).catch(()=>{});
    });
  }, 8000); // refresh every 8s
}

// ─── showPage hook for Paper Trading ─────────────────────────────
(function() {
  const _origSP = window.showPage;
  window.showPage = function(page, navEl) {
    if (typeof _origSP === 'function') _origSP(page, navEl);
    if (page === 'paper') {
      // Immediately blank the default content so the "Create Account" button
      // is never clickable before ptInit has run its checks
      const noAcct = document.getElementById('pt-no-acct');
      if (noAcct) {
        noAcct.style.display = '';
        noAcct.innerHTML = '<div style="color:var(--text-muted);font-size:13px;padding:40px 0;text-align:center;">Connecting…</div>';
        ['pt-acct-card','pt-stat-strip','pt-main-grid'].forEach(id => {
          const el = document.getElementById(id); if (el) el.style.display = 'none';
        });
      }
      ptInit();
    } else if (ptState.priceInterval) {
      clearInterval(ptState.priceInterval);
      ptState.priceInterval = null;
    }
  };
})();


