function _hmClass(chg) {
  return chg >= 3 ? 'hm-strong-up' : chg >= 1 ? 'hm-up' : chg >= 0.1 ? 'hm-slight-up' : chg > -0.1 ? 'hm-neutral' : chg > -1 ? 'hm-slight-down' : chg > -3 ? 'hm-down' : 'hm-strong-down';
}

function renderDashboardHeatmap() {
  const el = document.getElementById('dash-heatmap');
  if (!el) return;
  // Check if Polygon has live data
  if (window.PolygonAPI) {
    const cache = window.PolygonAPI.getCache();
    HEATMAP_DATA.forEach(d => {
      const live = cache[d.ticker];
      if (live && live.changePct !== undefined) d.chg = +live.changePct.toFixed(2);
    });
  }
  el.innerHTML = HEATMAP_DATA.map(d => {
    const sign = d.chg > 0 ? '+' : '';
    const cls = _hmClass(d.chg);
    // Use data-ticker + event delegation instead of inline onclick (prevents XSS)
    const safeTicker = d.ticker.replace(/[^A-Z0-9.]/gi, '');
    const safeName   = d.name.replace(/[<>"'&]/g, c => ({'<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;','&':'&amp;'}[c]));
    const safeSector = d.sector.replace(/[<>"'&]/g, c => ({'<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;','&':'&amp;'}[c]));
    return `<div class="heatmap-cell ${cls}${d.large?' hm-large':''}"
       title="${safeName} (${safeSector}) ${sign}${d.chg}% · ${d.mktCap}"
       data-ticker="${safeTicker}" role="button" tabindex="0" style="cursor:pointer;">
      <div class="heatmap-cell-ticker">${safeTicker}</div>
      <div class="heatmap-cell-chg">${sign}${d.chg.toFixed(1)}%</div>
    </div>`;
  }).join('');
  // Attach delegated click handler once (not per-render)
  if (!el._hmClickBound) {
    el._hmClickBound = true;
    el.addEventListener('click', function(e) {
      var cell = e.target.closest('[data-ticker]');
      if (cell && typeof globalSearch === 'function') globalSearch(cell.dataset.ticker);
    });
    el.addEventListener('keydown', function(e) {
      if (e.key === 'Enter' || e.key === ' ') {
        var cell = e.target.closest('[data-ticker]');
        if (cell && typeof globalSearch === 'function') globalSearch(cell.dataset.ticker);
      }
    });
  }
}

// ─── Live heatmap micro-jitter (simulates live price feed) ─────────
let _hmJitterRunning = false;
let _hmJitterInterval = null;
function _startHeatmapLive() {
  if (_hmJitterRunning) return;
  _hmJitterRunning = true;
  _hmJitterInterval = setInterval(() => {
    const dash = document.getElementById('page-dashboard');
    if (!dash || dash.classList.contains('hidden')) return;
    // Small random walk on each ticker
    HEATMAP_DATA.forEach(d => {
      // Only jitter if we don't have live Polygon data
      if (!window.PolygonAPI?.isConnected()) {
        d.chg = +(d.chg + (Math.random() - 0.5) * 0.08).toFixed(2);
        d.chg = Math.max(d.baseChg - 0.8, Math.min(d.baseChg + 0.8, d.chg)); // clamp near base
      }
    });
    // Surgical DOM update — no full re-render, just update text + class
    const cells = document.querySelectorAll('#dash-heatmap .heatmap-cell');
    cells.forEach((cell, i) => {
      const d = HEATMAP_DATA[i];
      if (!d) return;
      const sign = d.chg > 0 ? '+' : '';
      const newCls = _hmClass(d.chg);
      // Replace class
      cell.className = `heatmap-cell ${newCls}${d.large?' hm-large':''}`;
      const chgEl = cell.querySelector('.heatmap-cell-chg');
      if (chgEl) chgEl.textContent = `${sign}${d.chg.toFixed(1)}%`;
    });
  }, 3200);
}

