// ─── Fetch server AI config and update provider badge ─────────────
function _qzInitProviderBadge() {
  const badge = document.getElementById('cmd-provider-badge');
  const label = document.getElementById('cmd-provider-label');
  if (!badge || !label) return;

  if (!window._QZ_SERVER_MODE) {
    // File mode — show whichever client key is present
    const { provider } = (typeof qzGetProvider === 'function') ? qzGetProvider() : { provider: null };
    if (provider === 'groq') {
      label.textContent = 'AI · Groq (client)';
    } else if (provider === 'claude') {
      label.textContent = 'AI · Claude (client)';
    } else {
      badge.style.background = 'rgba(239,68,68,0.1)';
      badge.style.borderColor = 'rgba(239,68,68,0.25)';
      badge.querySelector('span').style.background = '#ef4444';
      label.textContent = 'AI · No key set';
    }
    return;
  }

  fetch('/api/auth/config', { credentials: 'same-origin' })
    .then(r => r.ok ? r.json() : null)
    .then(cfg => {
      if (!cfg) return;
      const providerNames = { groq: 'Groq', openai: 'OpenAI', anthropic: 'Anthropic', together: 'Together AI' };
      const name = providerNames[cfg.aiProvider] || cfg.aiProvider || 'Server';
      label.textContent = `AI · ${name} · ${cfg.aiModelStream || ''}`;
    })
    .catch(() => {});
}

