// ═══════════════════════════════════════════════════════════════════
// QUANT ENTELLOQ — API KEY SECURITY + AUDIO-FIRST AI SYSTEM
// ═══════════════════════════════════════════════════════════════════
(function() {
  'use strict';

  // ─────────────────────────────────────────────────────────────────
  // 1. API KEY SHOW/HIDE TOGGLE
  // ─────────────────────────────────────────────────────────────────
  window.qzToggleKeyVis = function(inputId, btn) {
    var inp = document.getElementById(inputId);
    if (!inp) return;
    var shown = inp.type === 'text';
    inp.type = shown ? 'password' : 'text';
    btn.textContent = shown ? '👁' : '🙈';
    btn.title = shown ? 'Show key' : 'Hide key';
  };

  // Mask helper: show first 8 chars + •••• + last 4
  function _maskKey(k) {
    if (!k || k.length < 12) return '••••••••';
    return k.substring(0, 8) + '••••' + k.slice(-4);
  }

  // Show saved-key indicator
  function _showSavedKey(provider, key) {
    var row = document.getElementById(provider + '-key-saved-row');
    var preview = document.getElementById(provider + '-key-preview');
    if (row) row.style.display = 'flex';
    if (preview) preview.textContent = _maskKey(key);
  }

  // Remove saved key
  window.qzForgetKey = function(provider) {
    if (provider === 'claude') {
      localStorage.removeItem('qe_claude_key');
      var inp = document.getElementById('claude-api-key-input');
      if (inp) { inp.value = ''; inp.type = 'password'; }
      var row = document.getElementById('claude-key-saved-row');
      if (row) row.style.display = 'none';
      var banner = document.getElementById('ai-key-banner');
      if (banner) banner.style.display = '';
    } else if (provider === 'groq') {
      localStorage.removeItem('qe_groq_key');
      var inpG = document.getElementById('groq-api-key-input');
      if (inpG) { inpG.value = ''; inpG.type = 'password'; }
      // Fall back to built-in key — show it as active
      _showSavedKey('groq', _QZ_BUILT_IN_GROQ);
      var rowG = document.getElementById('groq-key-saved-row');
      if (rowG) rowG.style.display = 'flex';
      // Banner stays hidden — built-in key is always available
      if (false) {
        var bannerG = document.getElementById('ai-key-banner');
        if (bannerG) bannerG.style.display = '';
      }
    } else if (provider === 'polygon') {
      localStorage.removeItem('qe_poly_key');
      localStorage.removeItem('qe_polygon_key');
      var inp2 = document.getElementById('polygon-api-key');
      if (inp2) { inp2.value = ''; inp2.type = 'password'; }
      var row2 = document.getElementById('polygon-key-saved-row');
      if (row2) row2.style.display = 'none';
    }
  };

  // On load: restore key indicators from localStorage
  window.addEventListener('DOMContentLoaded', function() {
    // Groq key — always active (built-in key or user-supplied)
    var gk = localStorage.getItem('qe_groq_key') || _QZ_BUILT_IN_GROQ;
    if (gk) {
      _showSavedKey('groq', gk);
      var banner = document.getElementById('ai-key-banner');
      if (banner) banner.style.display = 'none';
    }
    // Claude key
    var ck = localStorage.getItem('qe_claude_key');
    if (ck) {
      _showSavedKey('claude', ck);
      if (!gk) {
        var banner2 = document.getElementById('ai-key-banner');
        if (banner2) banner2.style.display = 'none';
      }
    }
    // Polygon key
    var pk = localStorage.getItem('qe_poly_key') || localStorage.getItem('qe_polygon_key');
    if (pk) _showSavedKey('polygon', pk);

    // Init TTS toggle UI state
    _syncTTSUI();
  });

  // Patch saveClaudeKey to also show the saved indicator
  var _origSaveClaude = window.saveClaudeKey;
  window.saveClaudeKey = function() {
    if (typeof _origSaveClaude === 'function') _origSaveClaude.apply(this, arguments);
    setTimeout(function() {
      var saved = localStorage.getItem('qe_claude_key');
      if (saved) {
        _showSavedKey('claude', saved);
        var banner = document.getElementById('ai-key-banner');
        if (banner) banner.style.display = 'none';
      }
    }, 200);
  };

  // Patch polygonSaveKey similarly
  var _origSavePoly = window.polygonSaveKey;
  window.polygonSaveKey = function() {
    if (typeof _origSavePoly === 'function') _origSavePoly.apply(this, arguments);
    setTimeout(function() {
      var saved = localStorage.getItem('qe_poly_key') || localStorage.getItem('qe_polygon_key');
      if (saved) _showSavedKey('polygon', saved);
    }, 400);
  };

  // ─────────────────────────────────────────────────────────────────
  // 2. GLOBAL TTS (AUDIO) MODE — ON BY DEFAULT
  // ─────────────────────────────────────────────────────────────────
  function _getTTSMode() {
    // Default ON — only off if user explicitly set it
    return localStorage.getItem('qz_tts_mode') !== 'off';
  }

  function _syncTTSUI() {
    var on = _getTTSMode();
    // Chat toggle
    var ct = document.getElementById('chat-tts-toggle');
    var cl = document.getElementById('chat-tts-label');
    if (ct) { ct.className = 'qz-tts-toggle' + (on ? ' on' : ''); }
    if (cl) cl.textContent = on ? 'Audio ON' : 'Audio OFF';
    // Command center badge
    var cb = document.getElementById('cmd-audio-badge');
    var cbl = document.getElementById('cmd-audio-label');
    var cw = document.getElementById('cmd-audio-wave');
    if (cb) { cb.className = 'qz-audio-badge' + (on ? ' on' : ''); }
    if (cbl) cbl.textContent = on ? 'Audio ON' : 'Audio OFF';
    if (cw) cw.style.display = on ? 'flex' : 'none';
    // FAB
    var fab = document.getElementById('qz-tts-fab');
    if (fab) {
      fab.className = on ? '' : 'muted';
      fab.title = on ? 'Audio ON — click to mute' : 'Audio OFF — click to enable';
      fab.querySelector('span.qz-fab-icon').textContent = on ? '🔊' : '🔇';
    }
  }

  window.qzToggleTTS = function() {
    var nowOn = _getTTSMode();
    localStorage.setItem('qz_tts_mode', nowOn ? 'off' : 'on');
    _syncTTSUI();
    // If turning off, stop any current speech
    if (nowOn && window.speechSynthesis) window.speechSynthesis.cancel();
    // Feedback
    if (!nowOn && typeof qeSpeak === 'function') {
      setTimeout(function() { qeSpeak('Audio mode enabled. All AI responses will now be read aloud.'); }, 100);
    }
  };

  // Shared speak gating function — respects TTS toggle AND live mode
  window.qzSpeak = function(text) {
    if (!_getTTSMode()) return;
    try { if (localStorage.getItem('qz_live_mode') !== 'on') return; } catch(_) {}
    if (!text || !text.trim()) return;
    var clean = text.replace(/[*_`#\[\]]/g, '').replace(/\s+/g, ' ').trim();
    if (typeof qeSpeak === 'function') {
      qeSpeak(clean.substring(0, 350));
    } else if (window.speechSynthesis) {
      window.speechSynthesis.cancel();
      var u = new SpeechSynthesisUtterance(clean.substring(0, 350));
      u.rate = 1.05; u.pitch = 1.0; u.volume = 0.95;
      var voices = window.speechSynthesis.getVoices();
      var pref = voices.find(function(v){ return /samantha|female|aria|google.*us/i.test(v.name); }) ||
                 voices.find(function(v){ return v.lang === 'en-US'; });
      if (pref) u.voice = pref;
      window.speechSynthesis.speak(u);
    }
  };

  // ─────────────────────────────────────────────────────────────────
  // 3. WIRE TTS TO AI CHAT (sendChat) — speak + add Read button
  // ─────────────────────────────────────────────────────────────────
  function _qzAttachReadBtn(bubble) {
    if (!bubble || bubble.querySelector('.qz-speak-btn')) return;
    var btn = document.createElement('button');
    btn.className = 'qz-speak-btn';
    btn.innerHTML = '🔊 Read';
    btn.onclick = function(e) {
      e.stopPropagation();
      if (window.speechSynthesis && window.speechSynthesis.speaking) {
        window.speechSynthesis.cancel();
        btn.innerHTML = '🔊 Read'; btn.classList.remove('speaking'); return;
      }
      var rawText = (bubble.innerText || bubble.textContent || '')
        .replace(/🔊 Read|⏹ Stop/g, '').trim();
      qzSpeak(rawText);
      btn.innerHTML = '⏹ Stop'; btn.classList.add('speaking');
      var iv = setInterval(function() {
        if (!window.speechSynthesis || !window.speechSynthesis.speaking) {
          btn.innerHTML = '🔊 Read'; btn.classList.remove('speaking'); clearInterval(iv);
        }
      }, 300);
    };
    bubble.appendChild(btn);
  }

  var _origSendChatForTTS = window.sendChat;
  window.sendChat = async function() {
    await _origSendChatForTTS.apply(this, arguments);
    // Wait for streaming + final render to settle, then add button + speak
    setTimeout(function() {
      var msgs = document.querySelectorAll('#chat-messages .chat-msg.ai .chat-bubble');
      if (!msgs.length) return;
      var lastBubble = msgs[msgs.length - 1];
      // Don't act on thinking states
      if (lastBubble.querySelector('.typing-indicator') || lastBubble.querySelector('.stream-cursor')) return;
      _qzAttachReadBtn(lastBubble);
      if (_getTTSMode()) {
        var text = (lastBubble.innerText || lastBubble.textContent || '')
          .replace(/🔊 Read|⏹ Stop/g, '').trim();
        if (text && text.length > 10) qzSpeak(text.substring(0, 400));
      }
    }, 600);
  };

  // ─────────────────────────────────────────────────────────────────
  // 4. MIC INPUT — Speech-to-text for Chat + Command Center
  // ─────────────────────────────────────────────────────────────────
  var _qzMicActive = false;
  var _qzRecog = null;

  function _qzStartMic(targetInputId, micBtnId, onFinal) {
    var SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) {
      alert('Voice input requires Chrome or Edge. Please type your query or open the platform in Chrome.');
      return;
    }
    var btn = document.getElementById(micBtnId);
    if (_qzMicActive && _qzRecog) {
      _qzRecog.stop();
      _qzMicActive = false;
      if (btn) btn.classList.remove('listening');
      return;
    }
    var r = new SR();
    r.continuous = false;
    r.interimResults = true;
    r.lang = 'en-US';
    r.maxAlternatives = 1;
    _qzRecog = r;
    _qzMicActive = true;
    if (btn) { btn.classList.add('listening'); btn.textContent = '⏹'; }

    var inp = document.getElementById(targetInputId);

    r.onresult = function(e) {
      var transcript = '';
      for (var i = e.resultIndex; i < e.results.length; i++) {
        transcript += e.results[i][0].transcript;
      }
      if (inp) inp.value = transcript;
      if (e.results[e.results.length - 1].isFinal) {
        _qzMicActive = false;
        if (btn) { btn.classList.remove('listening'); btn.textContent = '🎙'; }
        if (transcript.trim() && typeof onFinal === 'function') onFinal(transcript.trim());
      }
    };
    r.onerror = function(e) {
      _qzMicActive = false;
      if (btn) { btn.classList.remove('listening'); btn.textContent = '🎙'; }
      if (e.error === 'not-allowed') alert('Microphone permission denied. Please allow mic access and try again.');
    };
    r.onend = function() {
      _qzMicActive = false;
      if (btn) { btn.classList.remove('listening'); btn.textContent = '🎙'; }
    };
    r.start();
  }

  // Chat page mic — speaks transcription into chat input and auto-sends
  window.qzChatMic = function() {
    _qzStartMic('chat-input', 'chat-mic-btn', function(text) {
      // Auto-send after brief pause so user sees the transcribed text
      setTimeout(function() {
        if (typeof sendChat === 'function') sendChat();
      }, 600);
    });
  };

  // Command Center mic — fills query input and optionally auto-runs
  window.qzCmdMic = function() {
    _qzStartMic('cmd-query-input', 'cmd-mic-btn', function(text) {
      setTimeout(function() {
        if (typeof cmdOrchestrate === 'function') cmdOrchestrate();
      }, 600);
    });
  };

  // ─────────────────────────────────────────────────────────────────
  // 5. WIRE TTS TO ALL COMMAND CENTER AGENTS (all, not just assistant)
  // ─────────────────────────────────────────────────────────────────
  var _origCmdRunForTTS = window._cmdRunAgent;
  // Patch is applied post-load since _cmdRunAgent is defined later
  window.addEventListener('load', function() {
    // Re-patch _cmdRunAgent to speak all agent outputs when TTS is on
    var _realCmdRun = window._cmdRunAgent;
    if (typeof _realCmdRun === 'function') {
      window._cmdRunAgent = async function(agentId, query, apiKey) {
        await _realCmdRun.apply(this, arguments);
        // Speak this agent's output if TTS on
        if (_getTTSMode() && window.cmdState && window.cmdState.agentStates) {
          var st = window.cmdState.agentStates[agentId];
          if (st && st.status === 'done' && st.output && !st.output.startsWith('⚠')) {
            // Only speak assistant agent immediately; others add to a queue
            if (agentId === 'assistant') {
              qzSpeak(st.output);
            }
          }
        }
      };
    }
  });

  // ─────────────────────────────────────────────────────────────────
  // 6. FLOATING TTS FAB + initial bubble Read buttons
  // ─────────────────────────────────────────────────────────────────
  window.addEventListener('DOMContentLoaded', function() {
    // FAB button
    var fab = document.createElement('div');
    fab.id = 'qz-tts-fab';
    fab.innerHTML = '<span class="qz-fab-icon">🔊</span><div class="qz-tts-tooltip">Audio responses ON</div>';
    fab.onclick = function() { qzToggleTTS(); };
    document.body.appendChild(fab);
    _syncTTSUI();

    // Add "Read" button to the welcome bubble that's already in the DOM
    setTimeout(function() {
      document.querySelectorAll('#chat-messages .chat-msg.ai .chat-bubble').forEach(_qzAttachReadBtn);
    }, 1500);
  });

})();

// ═══════════════════════════════════════════════════════════════════
// QUANT ENTELLOQ — LEGAL & COMPLIANCE SYSTEM
// ═══════════════════════════════════════════════════════════════════
(function() {
  'use strict';

  // ── Rate limiter for AI requests ──────────────────────────────────
  const _rlCounts = {};
  window._qeRateLimit = function(key, limit, windowMs) {
    const now = Date.now();
    if (!_rlCounts[key]) _rlCounts[key] = [];
    _rlCounts[key] = _rlCounts[key].filter(t => now - t < windowMs);
    if (_rlCounts[key].length >= limit) return false;
    _rlCounts[key].push(now);
    return true;
  };

  // ── Input sanitizer (XSS guard) ──────────────────────────────────
  window._qeSanitize = function(str) {
    if (typeof str !== 'string') return '';
    return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
              .replace(/"/g,'&quot;').replace(/'/g,'&#039;').substring(0, 4000);
  };

  // ── Legal consent check ─────────────────────────────────────────
  function _legalAccepted() {
    return localStorage.getItem('qz_legal_v2') === '1';
  }

  // ── Show overlay on load if not accepted ─────────────────────────
  window.addEventListener('DOMContentLoaded', function() {
    if (!_legalAccepted()) {
      setTimeout(function() {
        var el = document.getElementById('qe-legal-overlay');
        if (el) el.classList.remove('dismissed');
      }, 1200);
    } else {
      _showDisclaimerBar();
    }
  });

  // ── Accept T&C ──────────────────────────────────────────────────
  window.qeLegalAccept = function() {
    var checks = ['qe-chk-tos','qe-chk-privacy','qe-chk-risk'];
    var allChecked = checks.every(function(id) {
      var el = document.getElementById(id);
      return el && el.checked;
    });
    if (!allChecked) {
      var warn = document.getElementById('qe-legal-warn');
      if (warn) { warn.style.display = 'block'; setTimeout(function(){ warn.style.display='none'; }, 3000); }
      return;
    }
    localStorage.setItem('qz_legal_v2', '1');
    localStorage.setItem('qz_legal_ts', Date.now());
    var el = document.getElementById('qe-legal-overlay');
    if (el) el.classList.add('dismissed');
    _showDisclaimerBar();
  };

  // ── Enable accept button only when all boxes checked ────────────
  window.qeLegalCheckChanged = function() {
    var checks = ['qe-chk-tos','qe-chk-privacy','qe-chk-risk'];
    var allChecked = checks.every(function(id) {
      var el = document.getElementById(id);
      return el && el.checked;
    });
    var btn = document.getElementById('qe-legal-accept-btn');
    if (btn) {
      btn.disabled = !allChecked;
      btn.style.opacity = allChecked ? '1' : '0.45';
    }
  };

  // ── Persistent disclaimer bar ────────────────────────────────────
  function _showDisclaimerBar() {
    if (localStorage.getItem('qz_disc_dismissed')) return;
    setTimeout(function() {
      var bar = document.getElementById('qe-disclaimer-bar');
      if (bar) bar.classList.add('visible');
    }, 600);
  }
  window.qeDismissDisclaimer = function() {
    var bar = document.getElementById('qe-disclaimer-bar');
    if (bar) bar.classList.remove('visible');
    localStorage.setItem('qz_disc_dismissed', '1');
  };

  // ── Cookie banner ────────────────────────────────────────────────
  window.addEventListener('DOMContentLoaded', function() {
    if (!localStorage.getItem('qz_cookies_ok')) {
      setTimeout(function() {
        var banner = document.getElementById('qe-cookie-banner');
        if (banner) banner.classList.add('visible');
      }, 2800);
    }
  });
  window.qeAcceptCookies = function() {
    localStorage.setItem('qz_cookies_ok', '1');
    var b = document.getElementById('qe-cookie-banner');
    if (b) b.classList.remove('visible');
  };
  window.qeRejectCookies = function() {
    localStorage.setItem('qz_cookies_ok', 'minimal');
    var b = document.getElementById('qe-cookie-banner');
    if (b) b.classList.remove('visible');
  };

  // ── Policy modals ────────────────────────────────────────────────
  window.qeShowToS = function() {
    document.getElementById('qe-tos-modal').classList.add('open');
  };
  window.qeShowPrivacy = function() {
    document.getElementById('qe-privacy-modal').classList.add('open');
  };
  window.qeCloseModal = function(id) {
    var el = document.getElementById(id);
    if (el) el.classList.remove('open');
  };

})();

// ── Debounce global search for performance ───────────────────────
(function() {
  var _origGlobalSearch = window.globalSearch;
  if (typeof _origGlobalSearch === 'function') {
    var _dbt;
    window.globalSearch = function(q) {
      clearTimeout(_dbt);
      _dbt = setTimeout(function() { _origGlobalSearch(q); }, 180);
    };
  }
})();

// ── Null-guard all chart containers to prevent crashes ──────────
(function() {
  var lwc = window.LightweightCharts;
  if (!lwc || typeof lwc.createChart !== 'function') return;
  var _orig = lwc.createChart;
  // LightweightCharts freezes its module exports, so we can't reassign in place.
  // Wrap on a soft proxy instead — null-guarded callers should use window._qzCreateChart.
  window._qzCreateChart = function(container, opts) {
    if (!container || !document.body.contains(container)) return null;
    try { return _orig.call(lwc, container, opts); }
    catch(e) { console.warn('[Quant Entelloq] chart error:', e); return null; }
  };
  // Best-effort overlay on the original — silently no-op if the module is frozen
  try {
    Object.defineProperty(lwc, 'createChart', {
      configurable: true,
      writable: true,
      value: window._qzCreateChart,
    });
  } catch (_) { /* frozen module — fine, _qzCreateChart still works */ }
})();


