  function qzToast(msg, type) {
    var t = document.createElement('div');
    var bg = type === 'success' ? 'rgba(34,197,94,0.95)' : 'rgba(239,68,68,0.95)';
    t.style.cssText = [
      'position:fixed;top:20px;left:50%;transform:translateX(-50%) translateY(-8px)',
      'background:' + bg,
      'color:#fff;font-family:var(--font-sans,sans-serif);font-size:14px;font-weight:600',
      'padding:12px 24px;border-radius:10px;z-index:99999;pointer-events:none',
      'box-shadow:0 4px 24px rgba(0,0,0,0.35);transition:opacity 0.3s,transform 0.3s',
      'opacity:0;white-space:nowrap'
    ].join(';');
    t.textContent = msg;
    document.body.appendChild(t);
    requestAnimationFrame(function() {
      t.style.opacity = '1';
      t.style.transform = 'translateX(-50%) translateY(0)';
    });
    setTimeout(function() {
      t.style.opacity = '0';
      t.style.transform = 'translateX(-50%) translateY(-8px)';
      setTimeout(function() { t.remove(); }, 350);
    }, 4000);
  }
  window.qzToast = qzToast;

