      // Drop ALL emoji-bearing decorative wrappers in our own renders
      '.qz-page-hero .qz-hero-icon, .qz-page-hero [data-hero-icon] { display: none !important; }',
      // Drop the floating decorative orbs (kept hidden previously, reaffirm)
      '.qz-app-orb-glow { display: none !important; }',
      // ── THE ONE EXCEPTION: brand mark at top-left ──
