(function(){
  'use strict';

  var URL = 'https://quant.entelloq.com/';
  var DEFAULT_MSG = "Just found Quant Entelloq — institutional-grade financial intelligence in your browser. 10 quant tools, AI agents, paper trading, 100M+ securities. Free, no signup.";

  function injectShareButton() {
    if (document.getElementById('qe-share-btn')) return;
    // Place next to country selector
    var wrap = document.getElementById('country-selector-wrap');
    if (!wrap || !wrap.parentElement) return;
    var btn = document.createElement('button');
    btn.id = 'qe-share-btn';
    btn.title = 'Share Quant Entelloq';
    btn.innerHTML = '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg><span class="qe-share-btn-text">Share</span>';
    btn.onclick = openShareSheet;
    wrap.parentElement.insertBefore(btn, wrap);
  }

  function buildShareSheet() {
    if (document.getElementById('qe-share-overlay')) return;
    var overlay = document.createElement('div');
    overlay.id = 'qe-share-overlay';
    overlay.onclick = function(e){ if (e.target === overlay) closeShareSheet(); };
    overlay.innerHTML = ''
      + '<div id="qe-share-sheet" role="dialog" aria-modal="true">'
      +   '<div class="qe-share-eyebrow">Help us grow · One tap</div>'
      +   '<div class="qe-share-title">Share Quant Entelloq</div>'
      +   '<div class="qe-share-sub">Edit the message below, then pick where to send it. Your link is auto-attached.</div>'
      +   '<div class="qe-share-msg-wrap">'
      +     '<textarea id="qe-share-msg" rows="3"></textarea>'
      +   '</div>'
      +   '<div class="qe-share-link-row" onclick="window.QEShare.copyLink()">'
      +     '<span>' + URL + '</span>'
      +     '<span class="qe-share-copy">COPY</span>'
      +   '</div>'
      +   '<div class="qe-share-grid">'
      +     '<a class="qe-share-btn" id="qe-share-x"        target="_blank" rel="noopener"><span class="qe-share-btn-icon">𝕏</span>X / Twitter</a>'
      +     '<a class="qe-share-btn" id="qe-share-reddit"   target="_blank" rel="noopener"><span class="qe-share-btn-icon">⊙</span>Reddit</a>'
      +     '<a class="qe-share-btn" id="qe-share-hn"       target="_blank" rel="noopener"><span class="qe-share-btn-icon">Y</span>Hacker News</a>'
      +     '<a class="qe-share-btn" id="qe-share-linkedin" target="_blank" rel="noopener"><span class="qe-share-btn-icon">in</span>LinkedIn</a>'
      +     '<a class="qe-share-btn" id="qe-share-whatsapp" target="_blank" rel="noopener"><span class="qe-share-btn-icon">✆</span>WhatsApp</a>'
      +     '<a class="qe-share-btn" id="qe-share-email"    target="_blank" rel="noopener"><span class="qe-share-btn-icon">✉</span>Email</a>'
      +   '</div>'
      +   '<button class="qe-share-close" onclick="window.QEShare.close()">Close · ESC</button>'
      + '</div>';
    document.body.appendChild(overlay);

    var toast = document.createElement('div');
    toast.className = 'qe-share-toast';
    toast.id = 'qe-share-toast';
    toast.textContent = 'Copied to clipboard';
    document.body.appendChild(toast);
  }

  function refreshLinks() {
    var msg = document.getElementById('qe-share-msg').value.trim() || DEFAULT_MSG;
    var encoded = encodeURIComponent(msg);
    var encUrl = encodeURIComponent(URL);
    var combined = encodeURIComponent(msg + ' ' + URL);

    var x  = document.getElementById('qe-share-x');
    var rd = document.getElementById('qe-share-reddit');
    var hn = document.getElementById('qe-share-hn');
    var li = document.getElementById('qe-share-linkedin');
    var wa = document.getElementById('qe-share-whatsapp');
    var em = document.getElementById('qe-share-email');

    if (x)  x.href  = 'https://twitter.com/intent/tweet?text=' + encoded + '&url=' + encUrl;
    if (rd) rd.href = 'https://www.reddit.com/submit?url=' + encUrl + '&title=' + encodeURIComponent('Quant Entelloq — AI-native financial terminal, free in your browser');
    if (hn) hn.href = 'https://news.ycombinator.com/submitlink?u=' + encUrl + '&t=' + encodeURIComponent('Show HN: Quant Entelloq — AI-native financial terminal, free in your browser');
    if (li) li.href = 'https://www.linkedin.com/sharing/share-offsite/?url=' + encUrl;
    if (wa) wa.href = 'https://wa.me/?text=' + combined;
    if (em) em.href = 'mailto:?subject=' + encodeURIComponent('Check out Quant Entelloq') + '&body=' + combined;
  }

  function openShareSheet() {
    buildShareSheet();
    var overlay = document.getElementById('qe-share-overlay');
    var msgEl = document.getElementById('qe-share-msg');
    if (msgEl && !msgEl.value) msgEl.value = DEFAULT_MSG;
    if (msgEl) msgEl.oninput = refreshLinks;
    refreshLinks();
    overlay.classList.add('show');
    // Bump share-counter for fun analytics
    try {
      var n = parseInt(localStorage.getItem('qe_share_opens') || '0', 10) + 1;
      localStorage.setItem('qe_share_opens', String(n));
    } catch(_){}
    // ESC key closes
    document.addEventListener('keydown', escClose);
  }

  function escClose(e) {
    if (e.key === 'Escape') closeShareSheet();
  }

  function closeShareSheet() {
    var overlay = document.getElementById('qe-share-overlay');
    if (overlay) overlay.classList.remove('show');
    document.removeEventListener('keydown', escClose);
  }

  function copyLink() {
    var text = URL;
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(text).then(showToast).catch(fallbackCopy);
    } else {
      fallbackCopy();
    }
    function fallbackCopy() {
      var ta = document.createElement('textarea');
      ta.value = text; ta.style.position = 'fixed'; ta.style.opacity = '0';
      document.body.appendChild(ta); ta.select();
      try { document.execCommand('copy'); showToast(); } catch(_){}
      document.body.removeChild(ta);
    }
  }

  function showToast() {
    var t = document.getElementById('qe-share-toast');
    if (!t) return;
    t.classList.add('show');
    setTimeout(function(){ t.classList.remove('show'); }, 1800);
  }

  // Native share API takeover on mobile if available
  function tryNativeShare() {
    if (navigator.share && /Mobi|Android/i.test(navigator.userAgent)) {
      var msg = document.getElementById('qe-share-msg');
      navigator.share({
        title: 'Quant Entelloq',
        text: (msg && msg.value) || DEFAULT_MSG,
        url: URL
      }).catch(function(){});
    }
  }

  // Idempotent boot
  function boot() { injectShareButton(); }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }
  setInterval(boot, 1500);

  window.QEShare = {
    open: openShareSheet,
    close: closeShareSheet,
    copyLink: copyLink,
    tryNative: tryNativeShare
  };
})();

