      var active = (node.id === 'cfn-output') ? ' active' : ' idle';
      html += '<div class="cmd-flow-node' + active + '" id="' + node.id + '"><span class="cmd-flow-dot' + active + '"></span>' + node.label + '</div>';
      if (i < NEW_FLOW.length - 1) html += '<span class="cmd-flow-arrow">→</span>';
