(function(){
  'use strict';

  // ────────────────────────────────────────────────────────────────────
  // INP fix — Master boot loop
  // Many hotfixes register their own setInterval(boot, 1200-2000).
  // Collectively that's a DOM-scan storm running ~5-10 times per second
  // and blocking user interactions.
  // We expose a single registry; the actual interval here is throttled
  // via requestIdleCallback so it yields to user input.
  // ────────────────────────────────────────────────────────────────────
  var tasks = [];
  window.QEMasterLoop = {
    register: function(fn, label) {
      if (typeof fn === 'function') tasks.push({ fn: fn, label: label || 'anon' });
    },
    run: function() {
      var i = 0;
      function step(deadline) {
        while (i < tasks.length && (!deadline || deadline.timeRemaining() > 4)) {
          try { tasks[i].fn(); } catch(e){ console.warn('[QEMaster] ' + tasks[i].label + ':', e); }
          i++;
        }
        if (i < tasks.length) {
          // More work — schedule next idle slice
          if (window.requestIdleCallback) {
            requestIdleCallback(step, { timeout: 1000 });
          } else {
            setTimeout(function(){ step(null); }, 16);
          }
        }
      }
      if (window.requestIdleCallback) {
        requestIdleCallback(step, { timeout: 1000 });
      } else {
        step(null);
      }
    }
  };
  setInterval(function(){ window.QEMasterLoop.run(); }, 4000);

  // ────────────────────────────────────────────────────────────────────
  // CLS fix — reserve dashboard slot for daily card BEFORE JS injects
  // ────────────────────────────────────────────────────────────────────
  function reserveDailyCardSlot() {
    var dash = document.getElementById('page-dashboard');
    if (!dash) return;
    if (document.getElementById('qe-daily-card')) return;
    if (document.getElementById('qe-daily-card-skel')) return;
    var skel = document.createElement('div');
    skel.id = 'qe-daily-card-skel';
    skel.className = 'qe-daily-card-skel';
    skel.style.cssText = 'min-height: 140px; margin: 12px 0 18px; border-radius: 12px; background: rgba(244,244,240,0.02); border: 1px solid rgba(244,244,240,0.04);';
    var statusBar = dash.querySelector('.dash-status-bar');
    if (statusBar && statusBar.nextSibling) {
      dash.insertBefore(skel, statusBar.nextSibling);
    } else {
      dash.insertBefore(skel, dash.firstChild);
    }
  }
  // Run on DOMContentLoaded (early) to reserve space BEFORE the daily
  // card JS injects content
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', reserveDailyCardSlot);
  } else {
    reserveDailyCardSlot();
  }
  // Cleanup skel once real card arrives
  window.QEMasterLoop.register(function(){
    var real = document.getElementById('qe-daily-card');
    var skel = document.getElementById('qe-daily-card-skel');
    if (real && skel) skel.remove();
  }, 'cleanup-daily-skel');

  // ────────────────────────────────────────────────────────────────────
  // CLS fix — reserve navbar slot for country badge + share button
  // ────────────────────────────────────────────────────────────────────
  function reserveNavbarSlots() {
    var wrap = document.getElementById('country-selector-wrap');
    if (!wrap || !wrap.parentElement) return;
    // Share button skeleton
    if (!document.getElementById('qe-share-btn') && !document.getElementById('qe-share-btn-skel')) {
      var ss = document.createElement('div');
      ss.id = 'qe-share-btn-skel';
      ss.style.cssText = 'min-width:78px;min-height:30px;display:inline-block;margin-right:8px;';
      wrap.parentElement.insertBefore(ss, wrap);
    }
    // Country badge skeleton
    if (!document.getElementById('qe-country-badge') && !document.getElementById('qe-country-badge-skel')) {
      var cs = document.createElement('div');
      cs.id = 'qe-country-badge-skel';
      cs.style.cssText = 'min-width:96px;min-height:24px;display:inline-block;margin-right:6px;';
      wrap.parentElement.insertBefore(cs, wrap);
    }
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', reserveNavbarSlots);
  } else {
    reserveNavbarSlots();
  }
  window.QEMasterLoop.register(function(){
    var sb = document.getElementById('qe-share-btn');
    var sbk = document.getElementById('qe-share-btn-skel');
    if (sb && sbk) sbk.remove();
    var cb = document.getElementById('qe-country-badge');
    var cbk = document.getElementById('qe-country-badge-skel');
    if (cb && cbk) cbk.remove();
  }, 'cleanup-navbar-skels');

  // ────────────────────────────────────────────────────────────────────
  // INP fix — throttle scroll-attached handlers
  // Add passive: true to known scroll listeners if not already
  // ────────────────────────────────────────────────────────────────────
  // No-op here unless we find specific perf-blocking listeners. The
  // master loop alone should drop INP significantly.

  // ────────────────────────────────────────────────────────────────────
  // Boot
  // ────────────────────────────────────────────────────────────────────
  // Trigger one initial pass after a brief delay
  setTimeout(function(){
    window.QEMasterLoop.run();
  }, 600);

  console.log('[QEv14] Performance hotfix loaded — CLS / INP / LCP optimizations active');
})();

