(function(){
  'use strict';
  // Inject consistent 2-letter monograms onto every nav-icon so we
  // stop relying on the random unicode glyphs.
  var MONOGRAMS = {
    'Dashboard':       'DB',
    'AI Signals':      'SG',
    'Macro':           'MA',
    'AI Studio':       'AI',
    'Quant Lab':       'QL',
    'Scanner':         'SC',
    'Watchlists':      'WL',
    'Intelligence':    'IN',
    'Portfolio':       'PF',
    'Paper Trading':   'PT',
    'Ledger':          'LD',
    'Simulations':     'SM',
    'Backtest':        'BT',
    'Reports':         'RP',
    'Alerts':          'AL',
    'Settings':        'SE'
  };
  function apply() {
    document.querySelectorAll('.sidebar .nav-item').forEach(function(item){
      var icon = item.querySelector('.nav-icon');
      var lbl = item.querySelector('.nav-label');
      if (!icon || !lbl) return;
      if (icon.hasAttribute('data-mono')) return;
      var name = lbl.textContent.trim();
      var mono = MONOGRAMS[name];
      if (mono) icon.setAttribute('data-mono', mono);
    });
    // Update Pro Plan tag if the user is on free
    var planEl = document.querySelector('.sidebar-user .user-plan');
    if (planEl && planEl.textContent === 'Pro Plan') {
      // Just use "Member" — less aspirational, less wrong
      planEl.textContent = 'Member';
    }
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', apply);
  } else {
    apply();
  }
  setInterval(apply, 1500);
})();

