(function(){
  'use strict';

  var PRIMARY = [
    ['dashboard', 'Dashboard',     false],
    ['ai',        'AI Studio',     true ],
    ['signals',   'Signals',       false],
    ['portfolio', 'Portfolio',     false],
    ['paper',     'Paper Trading', false],
    ['quantlab',  'Quant Lab',     false],
    ['research',  'Research Lab',  false]
  ];
  var MORE = [
    ['macro',    'Macro',        'MA'],
    ['scanner',  'Scanner',      'SC'],
    ['universe', 'Watchlists',   'WL'],
    ['intel',    'Intelligence', 'IN'],
    ['ledger',   'Ledger',       'LD'],
    ['scenario', 'Simulations',  'SM'],
    ['backtest', 'Backtest',     'BT'],
    ['reports',  'Reports',      'RP'],
    ['alerts',   'Alerts',       'AL'],
    ['settings', 'Settings',     'SE']
  ];

  function findSidebarItem(key) {
    var target = null;
    document.querySelectorAll('.sidebar .nav-item').forEach(function(it){
      var oc = it.getAttribute('onclick') || '';
      if (oc.indexOf("'" + key + "'") >= 0) target = it;
    });
    return target;
  }

  function go(key) {
    closeMore();
    var sbItem = findSidebarItem(key);
    if (typeof window.showPage === 'function') {
      try { window.showPage(key, sbItem || undefined); }
      catch(e) { try { window.showPage(key); } catch(_){} }
    }
  }

  function closeMore() {
    var p = document.getElementById('qe-tn-more-panel');
    if (p) p.classList.remove('open');
  }

  function build() {
    var main = document.querySelector('.main-content');
    if (!main) return;
    if (document.getElementById('qe-topnav')) return;

    var user = null;
    try { user = JSON.parse(localStorage.getItem('qz_auth_user') || 'null'); } catch(_){}
    var name = (user && (user.name || (user.email && user.email.split('@')[0]))) || 'Analyst';
    var initial = (name.charAt(0) || 'A').toUpperCase();

    var nav = document.createElement('div');
    nav.id = 'qe-topnav';

    var pillsHtml = PRIMARY.map(function(p){
      return '<button class="qe-tn-pill" data-page="' + p[0] + '">'
           + (p[2] ? '<span class="qe-tn-ai-dot"></span>' : '')
           + p[1]
           + '</button>';
    }).join('');

    var moreHtml = MORE.map(function(m){
      return '<div class="qe-tn-mitem" data-page="' + m[0] + '">'
           +   '<span class="qe-tn-mono">' + m[2] + '</span>'
           +   '<span class="qe-tn-mlabel">' + m[1] + '</span>'
           + '</div>';
    }).join('');

    nav.innerHTML = ''
      + '<div class="qe-tn-inner">'
      +   '<div class="qe-tn-logo" id="qe-tn-logo">'
      +     '<span class="qe-tn-mark">QE</span>'
      +     '<span class="qe-tn-word">Quant<em>Entelloq</em></span>'
      +   '</div>'
      +   '<nav class="qe-tn-pills" id="qe-tn-pills">'
      +     pillsHtml
      +     '<button class="qe-tn-pill" id="qe-tn-more-btn">More ▾</button>'
      +   '</nav>'
      +   '<div class="qe-tn-right">'
      +     '<div class="qe-tn-user" id="qe-tn-user">'
      +       '<span class="qe-tn-ava">' + initial + '</span>'
      +       '<span class="qe-tn-name">' + name + '</span>'
      +     '</div>'
      +   '</div>'
      + '</div>'
      + '<div id="qe-tn-more-panel">' + moreHtml + '</div>';

    main.insertBefore(nav, main.firstChild);

    // Wire navigation
    nav.querySelectorAll('.qe-tn-pill[data-page]').forEach(function(p){
      p.addEventListener('click', function(){ go(p.getAttribute('data-page')); });
    });
    nav.querySelectorAll('.qe-tn-mitem[data-page]').forEach(function(m){
      m.addEventListener('click', function(){ go(m.getAttribute('data-page')); });
    });
    var logo = document.getElementById('qe-tn-logo');
    if (logo) logo.addEventListener('click', function(){ go('dashboard'); });
    var userChip = document.getElementById('qe-tn-user');
    if (userChip) userChip.addEventListener('click', function(){ go('settings'); });

    var moreBtn = document.getElementById('qe-tn-more-btn');
    if (moreBtn) {
      moreBtn.addEventListener('click', function(e){
        e.stopPropagation();
        var panel = document.getElementById('qe-tn-more-panel');
        if (panel) panel.classList.toggle('open');
      });
    }
    document.addEventListener('click', function(e){
      var panel = document.getElementById('qe-tn-more-panel');
      if (panel && !panel.contains(e.target)) closeMore();
    });
  }

  // Active-state sync: poll the visible page and highlight the pill
  function syncActive() {
    var visible = document.querySelector('.main-content > .page-anim:not(.hidden)');
    if (!visible || !visible.id) return;
    var key = visible.id.replace('page-', '');
    var moreActive = false;
    document.querySelectorAll('.qe-tn-pill[data-page]').forEach(function(p){
      p.classList.toggle('active', p.getAttribute('data-page') === key);
    });
    document.querySelectorAll('.qe-tn-mitem[data-page]').forEach(function(m){
      var is = m.getAttribute('data-page') === key;
      m.classList.toggle('active', is);
      if (is) moreActive = true;
    });
    var moreBtn = document.getElementById('qe-tn-more-btn');
    if (moreBtn) moreBtn.classList.toggle('active', moreActive);
  }

  function boot() {
    build();
    syncActive();
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }
  setInterval(boot, 1200);

  window.QEShellV2 = { go: go, rebuild: build };
})();

